    def evaluate(
        self,
        samples: Iterable[LegalSample],
        *,
        legal_ir_bridge_names: Sequence[str] = (),
        legal_ir_evaluate_provers: Optional[bool] = None,
        legal_ir_targets: Optional[Mapping[str, Any] | Sequence[Any]] = None,
        legal_ir_parallel_workers: Optional[int] = None,
        use_sample_memory: bool = True,
    ) -> AutoencoderEvaluation:
        """Evaluate current encoder/decoder state against legal samples."""
        sample_list = list(samples)
        if not sample_list:
            return AutoencoderEvaluation(
                sample_count=0,
                embedding_cosine_similarity=0.0,
                cosine_loss=0.0,
                reconstruction_loss=0.0,
                cross_entropy_loss=0.0,
                frame_ranking_loss=0.0,
                symbolic_validity_penalty=0.0,
                decoded_embeddings={},
            )
        legal_ir_payload = _legal_ir_target_payload(
            sample_list,
            bridge_names=legal_ir_bridge_names,
            evaluate_provers=legal_ir_evaluate_provers,
            legal_ir_targets=legal_ir_targets,
            parallel_workers=legal_ir_parallel_workers,
        )
        legal_ir_target_distributions: Mapping[str, Mapping[str, float]] = legal_ir_payload[
            "target_view_distributions_by_sample"
        ]
        legal_ir_target_losses: Mapping[str, Mapping[str, float]] = legal_ir_payload[
            "target_losses_by_sample"
        ]
        self._cache_legal_ir_targets(
            sample_list,
            legal_ir_target_distributions,
            legal_ir_target_losses,
        )

        cosine_scores: List[float] = []
        cosine_losses: List[float] = []
        reconstruction_losses: List[float] = []
        probability_maps: List[Mapping[str, float]] = []
        target_maps: List[Mapping[str, float]] = []
        frame_losses: List[float] = []
        symbolic_penalties: List[float] = []
        decoded_embeddings: Dict[str, List[float]] = {}
        target_vectors: List[List[float]] = []
        decoded_vectors: List[List[float]] = []

        for sample in sample_list:
            decoded = self.decode(self.encode(sample, use_sample_memory=use_sample_memory))
            decoded_embeddings[sample.sample_id] = decoded
            target_vectors.append(list(sample.embedding_vector))
            decoded_vectors.append(decoded)
            probability_maps.append(
                self._family_distribution(
                    sample,
                    use_sample_memory=use_sample_memory,
                )
            )
            target_maps.append(_observed_family_distribution(sample))
            frame_losses.append(frame_ranking_loss(sample))
            symbolic_penalties.append(symbolic_validity_penalty(sample))

        cosine_scores, reconstruction_losses = self._embedding_metrics(
            target_vectors,
            decoded_vectors,
        )
        cosine_losses = [1.0 - value for value in cosine_scores]
        ce_losses = self._cross_entropy_distribution_losses(
            probability_maps,
            target_maps,
        )
        ce_entropy_losses = [
            distribution_entropy_loss(target)
            for target in target_maps
        ]
        ce_excess_losses = [
            cross_entropy_excess_distribution_loss(probabilities, target)
            for probabilities, target in zip(probability_maps, target_maps)
        ]
        legal_ir_losses = dict(legal_ir_payload["losses"])
        legal_ir_view_ce_losses: List[float] = []
        legal_ir_view_entropy_losses: List[float] = []
        legal_ir_view_excess_losses: List[float] = []
        predicted_view_distributions: List[Mapping[str, float]] = []
        legal_ir_view_family_loss_values: Dict[str, List[float]] = {}
        family_metric_observations: Dict[
            str, Dict[str, List[tuple[float, float]]]
        ] = {}
        for sample_index, sample in enumerate(sample_list):
            target_view_distribution = legal_ir_target_distributions.get(sample.sample_id)
            if not target_view_distribution:
                continue
            predicted_view_distribution = self._legal_ir_view_distribution(
                sample,
                target_view_distribution,
                use_sample_memory=use_sample_memory,
            )
            predicted_view_distributions.append(predicted_view_distribution)
            legal_ir_view_ce_losses.append(
                cross_entropy_distribution_loss(
                    predicted_view_distribution,
                    target_view_distribution,
                )
            )
            legal_ir_view_entropy_losses.append(
                distribution_entropy_loss(target_view_distribution)
            )
            legal_ir_view_excess_losses.append(
                cross_entropy_excess_distribution_loss(
                    predicted_view_distribution,
                    target_view_distribution,
                )
            )
            sample_family_losses = _legal_ir_view_family_loss_metrics(
                predicted_view_distribution,
                target_view_distribution,
            )
            for name, value in sample_family_losses.items():
                legal_ir_view_family_loss_values.setdefault(name, []).append(
                    _float_or_zero(value)
                )
            target_family_distribution = _legal_ir_view_family_distribution(
                target_view_distribution
            )
            for family, weight in target_family_distribution.items():
                if family not in LEGAL_IR_VIEW_FAMILIES or weight <= 0.0:
                    continue
                observations = family_metric_observations.setdefault(family, {})
                prefix = f"legal_ir_view_family_{family}"
                family_cross_entropy = sample_family_losses.get(
                    f"{prefix}_cross_entropy_loss"
                )
                family_cosine_gap = sample_family_losses.get(
                    f"{prefix}_cosine_gap_loss"
                )
                if family_cross_entropy is not None:
                    observations.setdefault("ir_cross_entropy_loss", []).append(
                        (weight, family_cross_entropy)
                    )
                if family_cosine_gap is not None:
                    observations.setdefault("ir_cosine_similarity", []).append(
                        (weight, max(0.0, 1.0 - family_cosine_gap))
                    )
                observations.setdefault(
                    "autoencoder_cross_entropy_loss", []
                ).append((weight, ce_losses[sample_index]))
                observations.setdefault(
                    "autoencoder_cosine_similarity", []
                ).append((weight, cosine_scores[sample_index]))
                observations.setdefault(
                    "symbolic_validity_success_rate", []
                ).append((weight, max(0.0, 1.0 - symbolic_penalties[sample_index])))

            # Every adaptive evaluation performs a decoder round trip.  Track
            # that autoencoder signal under the canonical decompiler contract,
            # independently of which logical projection views were requested.
            decompiler_observations = family_metric_observations.setdefault(
                "decompiler", {}
            )
            if "decompiler" not in target_family_distribution:
                decompiler_observations.setdefault(
                    "autoencoder_cross_entropy_loss", []
                ).append((1.0, ce_losses[sample_index]))
                decompiler_observations.setdefault(
                    "autoencoder_cosine_similarity", []
                ).append((1.0, cosine_scores[sample_index]))
                decompiler_observations.setdefault(
                    "symbolic_validity_success_rate", []
                ).append((1.0, max(0.0, 1.0 - symbolic_penalties[sample_index])))
            target_losses = dict(legal_ir_target_losses.get(sample.sample_id, {}) or {})
            decompiler_source_copy = target_losses.get("source_copy_reward_hack_penalty")
            if decompiler_source_copy is None:
                decompiler_source_copy = target_losses.get(
                    "round_trip_source_copy_guardrail_loss"
                )
            if decompiler_source_copy is not None:
                decompiler_observations.setdefault("source_copy_penalty", []).append(
                    (1.0, max(0.0, _float_or_zero(decompiler_source_copy)))
                )
        if legal_ir_view_ce_losses:
            legal_ir_losses["legal_ir_view_cross_entropy_loss"] = _mean(
                legal_ir_view_ce_losses
            )
            legal_ir_losses["legal_ir_view_entropy_loss"] = _mean(
                legal_ir_view_entropy_losses
            )
            legal_ir_losses["legal_ir_view_cross_entropy_excess_loss"] = _mean(
                legal_ir_view_excess_losses
            )
        for name, values in sorted(legal_ir_view_family_loss_values.items()):
            if values:
                legal_ir_losses[name] = _mean(values)

        return AutoencoderEvaluation(
            sample_count=len(sample_list),
            embedding_cosine_similarity=_mean(cosine_scores),
            cosine_loss=_mean(cosine_losses),
            reconstruction_loss=_mean(reconstruction_losses),
            cross_entropy_loss=_mean(ce_losses),
            cross_entropy_entropy_loss=_mean(ce_entropy_losses),
            cross_entropy_excess_loss=_mean(ce_excess_losses),
            frame_ranking_loss=_mean(frame_losses),
            symbolic_validity_penalty=_mean(symbolic_penalties),
            decoded_embeddings=decoded_embeddings,
            sample_embedding_metrics=_sample_embedding_metric_rows(
                sample_list,
                cosine_scores=cosine_scores,
                reconstruction_losses=reconstruction_losses,
            ),
            legal_ir_target_count=legal_ir_payload["target_count"],
            legal_ir_losses=legal_ir_losses,
            legal_ir_predicted_view_distribution=_mean_distributions(
                predicted_view_distributions
            ),
            legal_ir_target_hashes=legal_ir_payload["target_hashes"],
            legal_ir_grammar_rejection_reasons=legal_ir_payload[
                "grammar_rejection_reasons_by_sample"
            ],
            legal_ir_view_distribution=legal_ir_payload["view_distribution"],
            legal_ir_view_family_metrics=_weighted_view_family_metric_block(
                family_metric_observations
            ),
        )

    def _cache_legal_ir_targets(
        self,
        samples: Sequence[LegalSample],
        target_view_distributions: Mapping[str, Mapping[str, float]],
        target_losses_by_sample: Mapping[str, Mapping[str, float]],
    ) -> None:
        """Prime LegalIR target caches before decoding/evaluating samples."""
        for sample in samples:
            target_view_distribution = target_view_distributions.get(sample.sample_id)
            if target_view_distribution:
                cached_distribution = {
                    str(name): float(value)
                    for name, value in target_view_distribution.items()
                }
                self._legal_ir_view_target_cache[sample.sample_id] = cached_distribution
                self._legal_ir_view_target_cache[
                    _sample_content_cache_id(sample)
                ] = cached_distribution
            target_losses = target_losses_by_sample.get(sample.sample_id)
            if target_losses:
                cached_losses = {
                    str(name): float(value)
                    for name, value in target_losses.items()
                }
                self._legal_ir_loss_target_cache[sample.sample_id] = cached_losses
                self._legal_ir_loss_target_cache[
                    _sample_content_cache_id(sample)
                ] = cached_losses
            if target_view_distribution or target_losses:
                cache = self._sample_cache_for(sample)
                for key in (
                    "feature_keys",
                    "fallback_feature_keys",
                    "legal_ir_view_feature_keys",
                    "legal_ir_view_core_feature_keys",
                ):
                    cache.pop(key, None)
                for key in list(cache.keys()):
                    if str(key).startswith("objective_residual_feature_keys:"):
                        cache.pop(key, None)

    def alias_cached_legal_ir_targets(
        self,
        samples: Sequence[LegalSample],
        evaluated_samples: Sequence[LegalSample],
    ) -> None:
        """Attach bounded bridge targets to their corresponding full samples.

        Metric bridges may evaluate a bounded clone with a synthetic sample ID.
        Projection updates operate on the full sample, so they need an explicit
        alias instead of relying on the bounded clone's cache identity.
        """
        source_rows = list(samples)
        evaluated_rows = list(evaluated_samples)
        if len(source_rows) != len(evaluated_rows):
            raise ValueError("LegalIR target aliases require aligned sample sequences")

        for sample, evaluated_sample in zip(source_rows, evaluated_rows):
            evaluated_id = str(evaluated_sample.sample_id)
            evaluated_content_id = _sample_content_cache_id(evaluated_sample)
            target_distribution = self._legal_ir_view_target_cache.get(
                evaluated_id,
                self._legal_ir_view_target_cache.get(evaluated_content_id),
            )
            target_losses = self._legal_ir_loss_target_cache.get(
                evaluated_id,
                self._legal_ir_loss_target_cache.get(evaluated_content_id),
            )
            if target_distribution:
                cached_distribution = dict(target_distribution)
                self._legal_ir_view_target_cache[sample.sample_id] = cached_distribution
                self._legal_ir_view_target_cache[
                    _sample_content_cache_id(sample)
                ] = cached_distribution
            if target_losses:
                cached_losses = dict(target_losses)
                self._legal_ir_loss_target_cache[sample.sample_id] = cached_losses
                self._legal_ir_loss_target_cache[
                    _sample_content_cache_id(sample)
                ] = cached_losses
            if not target_distribution and not target_losses:
                continue
            cache = self._sample_cache_for(sample)
            for key in (
                "feature_keys",
                "fallback_feature_keys",
                "legal_ir_view_feature_keys",
                "legal_ir_view_core_feature_keys",
            ):
                cache.pop(key, None)
                for key in list(cache.keys()):
                    if str(key).startswith("objective_residual_feature_keys:"):
                        cache.pop(key, None)

    def _invalidate_state_dependent_evaluator_caches(self) -> None:
        """Discard cached feature selections after swapping model state.

        Codec feature selection prioritizes keys represented by the current
        learned state. Projection line search swaps several candidate states,
        so retaining those selections would let a rejected candidate affect
        later evaluations even after its weights were rolled back.
        """
        for cache in self._sample_feature_cache.values():
            cache.pop("feature_keys", None)
            cache.pop("legal_ir_view_feature_keys", None)
        self._invalidate_legal_ir_view_family_candidates()

    def encode(self, sample: LegalSample, *, use_sample_memory: bool = True) -> Dict[str, object]:
        """Encode sample into the current intermediate representation state."""
        return {
            "family_distribution": self._family_distribution(
                sample,
                use_sample_memory=use_sample_memory,
            ),
            "sample_id": sample.sample_id,
            "selected_frame": sample.selected_frame,
            "target_family": _target_family(sample),
            "target_family_distribution": _observed_family_distribution(sample),
            "embedding_projection": self._decoded_for(sample, use_sample_memory=use_sample_memory),
        }

    def decode(self, encoded: Mapping[str, object]) -> List[float]:
        """Decode the intermediate representation into an embedding vector."""
        return [
            float(value)
            for value in encoded.get("embedding_projection", [])  # type: ignore[arg-type]
        ]

    def introspect_sample(
        self,
        sample: LegalSample,
        *,
        use_sample_memory: bool = False,
        top_k: int = 8,
        include_causal_attribution: bool = True,
    ) -> AutoencoderIntrospection:
        """Explain which adaptive features influenced this sample.

        The default ignores sample-specific memory so the resulting evidence is
        suitable for deterministic compiler/decompiler synthesis.
        """
        logits = self._logits_for(sample, use_sample_memory=use_sample_memory)
        probabilities = _softmax(logits)
        target_family = _target_family(sample)
        predicted_family = max(
            probabilities,
            key=lambda family: (probabilities[family], family),
        ) if probabilities else ModalLogicFamily.HYBRID.value
        target_probability = float(probabilities.get(target_family, 0.0))
        predicted_probability = float(probabilities.get(predicted_family, 0.0))
        other_probabilities = [
            value for family, value in probabilities.items() if family != target_family
        ]
        best_other = max(other_probabilities) if other_probabilities else 0.0
        decoded = self._decoded_for(sample, use_sample_memory=use_sample_memory)
        base_decoded = self._base_decoded_for(sample)
        embedding_cosine = cosine_similarity(sample.embedding_vector, decoded)
        embedding_reconstruction = mse_loss(sample.embedding_vector, decoded)
        residual = [
            float(target_value) - float(decoded_value)
            for target_value, decoded_value in zip(sample.embedding_vector, decoded)
        ]
        feature_keys = self._feature_keys_for(sample)
        family_contributions = self._family_contributions_for(
            sample,
            feature_keys,
            use_sample_memory=use_sample_memory,
        )
        embedding_contributions = self._embedding_contributions_for(
            feature_keys,
            residual,
            dimensions=len(sample.embedding_vector),
            sample=sample,
            use_sample_memory=use_sample_memory,
        )
        legal_ir_view_distribution = self._legal_ir_view_target_cache.get(
            sample.sample_id,
            self._legal_ir_view_target_cache.get(_sample_content_cache_id(sample), {}),
        )
        legal_ir_losses = dict(
            self._legal_ir_loss_target_cache.get(
                sample.sample_id,
                self._legal_ir_loss_target_cache.get(_sample_content_cache_id(sample), {}),
            )
        )
        source_decompiled_losses = _source_decompiled_text_losses_from_targets(
            legal_ir_losses
        )
        legal_ir_losses.update(source_decompiled_losses)
        legal_ir_predicted_view_distribution: Dict[str, float] = {}
        legal_ir_view_cross_entropy_loss = 0.0
        legal_ir_view_entropy_loss = 0.0
        legal_ir_view_cross_entropy_excess_loss = 0.0
        legal_ir_view_family_losses: Dict[str, float] = {}
        if legal_ir_view_distribution:
            legal_ir_predicted_view_distribution = self._legal_ir_view_distribution(
                sample,
                legal_ir_view_distribution,
                use_sample_memory=use_sample_memory,
            )
            legal_ir_view_cross_entropy_loss = cross_entropy_distribution_loss(
                legal_ir_predicted_view_distribution,
                legal_ir_view_distribution,
            )
            legal_ir_view_entropy_loss = distribution_entropy_loss(
                legal_ir_view_distribution
            )
            legal_ir_view_cross_entropy_excess_loss = (
                cross_entropy_excess_distribution_loss(
                    legal_ir_predicted_view_distribution,
                    legal_ir_view_distribution,
                )
            )
            legal_ir_view_family_losses = _legal_ir_view_family_loss_metrics(
                legal_ir_predicted_view_distribution,
                legal_ir_view_distribution,
            )
        legal_ir_component_gaps = _legal_ir_component_gaps(
            legal_ir_view_distribution,
            legal_ir_predicted_view_distribution,
        )
        legal_ir_underrepresented_components = _top_legal_ir_component_gaps(
            legal_ir_component_gaps,
            positive=True,
        )
        legal_ir_overrepresented_components = _top_legal_ir_component_gaps(
            legal_ir_component_gaps,
            positive=False,
        )
        pipeline_stage_diagnostics = _pipeline_stage_diagnostics_for_introspection(
            sample,
            target_family=target_family,
            predicted_family=predicted_family,
            target_probability=target_probability,
            cosine_similarity_value=embedding_cosine,
            reconstruction_loss=embedding_reconstruction,
            source_decompiled_text_embedding_cosine_loss=source_decompiled_losses[
                "source_decompiled_text_embedding_cosine_loss"
            ],
            source_decompiled_text_token_loss=source_decompiled_losses[
                "source_decompiled_text_token_loss"
            ],
            legal_ir_view_cross_entropy_loss=legal_ir_view_cross_entropy_loss,
            legal_ir_component_gaps=legal_ir_component_gaps,
        )
        pipeline_stage_focus = _pipeline_stage_focus_from_diagnostics(
            pipeline_stage_diagnostics
        )
        causal_attribution = (
            self.causal_feature_attribution_for_sample(
                sample,
                top_k=max(top_k, 0),
            )
            if include_causal_attribution
            else {}
        )
        return AutoencoderIntrospection(
            sample_id=sample.sample_id,
            target_family=target_family,
            predicted_family=predicted_family,
            target_probability=round(target_probability, 12),
            predicted_probability=round(predicted_probability, 12),
            family_margin=round(target_probability - best_other, 12),
            cosine_similarity=round(embedding_cosine, 12),
            cosine_loss=round(max(0.0, 1.0 - embedding_cosine), 12),
            reconstruction_loss=round(embedding_reconstruction, 12),
            source_decompiled_text_embedding_cosine_loss=round(
                source_decompiled_losses[
                    "source_decompiled_text_embedding_cosine_loss"
                ],
                12,
            ),
            source_decompiled_text_token_loss=round(
                source_decompiled_losses["source_decompiled_text_token_loss"],
                12,
            ),
            residual_vector=[round(value, 12) for value in residual],
            base_decoded_embedding=[round(float(value), 12) for value in base_decoded],
            decoded_embedding=[round(float(value), 12) for value in decoded],
            feature_count=len(feature_keys),
            sample_memory_used=use_sample_memory,
            top_family_contributions=family_contributions[:max(top_k, 0)],
            top_embedding_contributions=embedding_contributions[:max(top_k, 0)],
            pipeline_stage_diagnostics=pipeline_stage_diagnostics,
            pipeline_stage_focus=pipeline_stage_focus,
            legal_ir_view_cross_entropy_loss=round(legal_ir_view_cross_entropy_loss, 12),
            legal_ir_view_entropy_loss=round(legal_ir_view_entropy_loss, 12),
            legal_ir_view_cross_entropy_excess_loss=round(
                legal_ir_view_cross_entropy_excess_loss,
                12,
            ),
            legal_ir_component_gaps={
                key: round(float(value), 12)
                for key, value in sorted(legal_ir_component_gaps.items())
            },
            legal_ir_losses={
                key: round(float(value), 12)
                for key, value in sorted(
                    {
                        **dict(legal_ir_losses),
                        **legal_ir_view_family_losses,
                    }.items()
                )
            },
            legal_ir_underrepresented_components=legal_ir_underrepresented_components,
            legal_ir_overrepresented_components=legal_ir_overrepresented_components,
            legal_ir_view_distribution={
                key: round(float(value), 12)
                for key, value in sorted(legal_ir_view_distribution.items())
            },
            legal_ir_predicted_view_distribution={
                key: round(float(value), 12)
                for key, value in sorted(legal_ir_predicted_view_distribution.items())
            },
            feature_group_ablations={
                key: dict(value)
                for key, value in sorted(
                    causal_attribution.get("feature_group_ablations", {}).items()
                )
            },
            legal_minimal_pair_probes={
                key: dict(value)
                for key, value in sorted(
                    causal_attribution.get("legal_minimal_pair_probes", {}).items()
                )
            },
            compiler_actionability=dict(
                causal_attribution.get("compiler_actionability", {})
            ),
            synthesis_focus=self._synthesis_focus_for(
                sample,
                target_family=target_family,
                predicted_family=predicted_family,
                target_probability=target_probability,
                cosine_similarity=embedding_cosine,
                reconstruction_loss=embedding_reconstruction,
                source_decompiled_text_embedding_cosine_loss=source_decompiled_losses[
                    "source_decompiled_text_embedding_cosine_loss"
                ],
                source_decompiled_text_token_loss=source_decompiled_losses[
                    "source_decompiled_text_token_loss"
                ],
                legal_ir_view_cross_entropy_loss=legal_ir_view_cross_entropy_loss,
                legal_ir_view_distribution=legal_ir_view_distribution,
                legal_ir_predicted_view_distribution=legal_ir_predicted_view_distribution,
            ),
        )

    def compiler_guidance_for_sample(
        self,
        sample: LegalSample,
        *,
        use_sample_memory: bool = False,
        top_k: int = 16,
        include_causal_attribution: bool = True,
        introspection: Optional[AutoencoderIntrospection] = None,
    ) -> Dict[str, Any]:
        """Export learned compiler/decompiler guidance for deterministic IR code.

        The autoencoder learns reusable feature weights over compiler contracts,
        decompiler surface templates, cycle-consistency contracts, and LegalIR
        views.  This method exposes those representations as a compact,
        serializable contract that deterministic compiler/decompiler stages can
        consume without depending on sample-specific memory.
        """
        limit = max(0, int(top_k))
        if introspection is not None:
            if introspection.sample_id != sample.sample_id:
                raise ValueError("introspection sample_id does not match guidance sample")
            if introspection.sample_memory_used != use_sample_memory:
                raise ValueError("introspection sample-memory mode does not match guidance request")
        else:
            introspection = self.introspect_sample(
                sample,
                use_sample_memory=use_sample_memory,
                top_k=limit,
                include_causal_attribution=include_causal_attribution,
            )
        legal_ir_target_distribution = dict(
            self._legal_ir_view_target_cache.get(
                sample.sample_id,
                self._legal_ir_view_target_cache.get(
                    _sample_content_cache_id(sample),
                    {},
                ),
            )
        )
        legal_ir_predicted_distribution: Dict[str, float] = {}
        if legal_ir_target_distribution:
            legal_ir_predicted_distribution = self._legal_ir_view_distribution(
                sample,
                legal_ir_target_distribution,
                use_sample_memory=use_sample_memory,
            )
        legal_ir_view_gap_distribution = {
            key: round(
                float(legal_ir_target_distribution.get(key, 0.0))
                - float(legal_ir_predicted_distribution.get(key, 0.0)),
                12,
            )
            for key in sorted(
                set(legal_ir_target_distribution)
                | set(legal_ir_predicted_distribution)
            )
            if abs(
                float(legal_ir_target_distribution.get(key, 0.0))
                - float(legal_ir_predicted_distribution.get(key, 0.0))
            )
            > 1.0e-12
        }

        feature_groups = {
            "compiler_latent_profile": self._compiler_latent_profile_feature_keys_for(sample),
            "compiler_contract": self._compiler_contract_feature_keys_for(sample),
            "decompiler_surface_template": self._decompiler_surface_template_feature_keys_for(sample),
            "cycle_consistency": self._cycle_consistency_feature_keys_for(sample),
            "semantic_slot": [
                f"semantic-slot:{slot.removeprefix('slot:')}"
                for slot in self._semantic_slot_distribution_for(sample).keys()
            ],
            "logic_view_contract": self._logic_view_contract_feature_keys_for(sample),
        }
        ranked_features = self._rank_guidance_features(
            _unique_preserve_order(
                feature
                for features in feature_groups.values()
                for feature in features
            ),
            top_k=limit,
        )
        return {
            "decoded_embedding": list(introspection.decoded_embedding),
            "family_distribution": {
                key: round(float(value), 12)
                for key, value in sorted(
                    self._family_distribution(
                        sample,
                        use_sample_memory=use_sample_memory,
                    ).items()
                )
            },
            "causal_feature_attribution": {
                "feature_group_ablations": _json_round_floats(
                    introspection.feature_group_ablations
                ),
                "legal_minimal_pair_probes": _json_round_floats(
                    introspection.legal_minimal_pair_probes
                ),
            },
            "compiler_actionability": _json_round_floats(
                introspection.compiler_actionability
            ),
            "compiler_actionable_feature_groups": list(
                introspection.compiler_actionability.get(
                    "compiler_actionable_feature_groups",
                    [],
                )
            ),
            "feature_groups": {
                name: list(features[:limit] if limit else features)
                for name, features in sorted(feature_groups.items())
            },
            "legal_ir_predicted_view_distribution": {
                key: round(float(value), 12)
                for key, value in sorted(legal_ir_predicted_distribution.items())
            },
            "legal_ir_target_view_distribution": {
                key: round(float(value), 12)
                for key, value in sorted(legal_ir_target_distribution.items())
            },
            "legal_ir_view_gap_distribution": legal_ir_view_gap_distribution,
            "legal_ir_view_metrics": {
                "cross_entropy_excess_loss": (
                    introspection.legal_ir_view_cross_entropy_excess_loss
                ),
                "cross_entropy_loss": introspection.legal_ir_view_cross_entropy_loss,
                "entropy_loss": introspection.legal_ir_view_entropy_loss,
                "source_decompiled_text_embedding_cosine_loss": (
                    introspection.source_decompiled_text_embedding_cosine_loss
                ),
                "source_decompiled_text_token_loss": (
                    introspection.source_decompiled_text_token_loss
                ),
                "view_family_losses": {
                    key: round(float(value), 12)
                    for key, value in sorted(introspection.legal_ir_losses.items())
                    if key.startswith("legal_ir_view_family_")
                },
            },
            "ranked_guidance_features": ranked_features,
            "sample_id": sample.sample_id,
            "sample_memory_used": use_sample_memory,
            "synthesis_focus": list(introspection.synthesis_focus),
            "top_embedding_contributions": [
                contribution.to_dict()
                for contribution in introspection.top_embedding_contributions
            ],
            "top_family_contributions": [
                contribution.to_dict()
                for contribution in introspection.top_family_contributions
            ],
        }

    def export_stable_legal_ir_features(
        self,
        samples: Iterable[LegalSample] = (),
        *,
        min_sample_support: int = 1,
        max_features: int = LEGAL_IR_STABLE_FEATURE_EXPORT_MAX_FEATURES,
    ) -> StableLegalIRFeatureExport:
        """Export reusable learned features for deterministic IR promotion.

        Only feature-level state shared across samples is eligible.  The two
        sample-memory heads (``decoded_embeddings`` and ``family_logits``) are
        excluded before the state fingerprint and feature ranking are built.
        Supplying samples adds a deterministic support filter but never adds a
        sample identifier or a source-derived token to the export.
        """

        sample_rows = list(samples)
        minimum_support = max(1, int(min_sample_support))
        limit = max(
            0,
            min(
                int(max_features),
                LEGAL_IR_STABLE_FEATURE_EXPORT_MAX_FEATURES,
            ),
        )
        active_feature_counts: Dict[str, int] = {}
        view_distributions: List[Mapping[str, float]] = []
        for sample in sample_rows:
            active = set(
                _stable_legal_ir_feature_keys_for_autoencoder_sample(self, sample)
            )
            for feature in active:
                active_feature_counts[feature] = (
                    active_feature_counts.get(feature, 0) + 1
                )
            target_distribution = self._legal_ir_view_target_cache.get(
                sample.sample_id,
                self._legal_ir_view_target_cache.get(
                    _sample_content_cache_id(sample),
                    {},
                ),
            )
            if target_distribution:
                view_distributions.append(
                    self._legal_ir_view_distribution(
                        sample,
                        target_distribution,
                        use_sample_memory=False,
                    )
                )

        feature_rows = _stable_legal_ir_learned_feature_rows(self.state)
        if sample_rows:
            feature_rows = [
                row
                for row in feature_rows
                if active_feature_counts.get(str(row["feature"]), 0)
                >= minimum_support
            ]
        stable_features: List[Dict[str, Any]] = []
        for row in feature_rows[:limit]:
            feature = str(row["feature"])
            support_count = (
                active_feature_counts.get(feature, 0)
                if sample_rows
                else int(row["source_head_count"])
            )
            stable_features.append(
                {
                    **row,
                    "feature_id": "lir-feature-" + _hash_text(feature)[:20],
                    "sample_support": support_count,
                    "support_ratio": round(
                        support_count / len(sample_rows), 12
                    )
                    if sample_rows
                    else 1.0,
                    "stable": True,
                }
            )

        if view_distributions:
            mean_view_distribution = _mean_distributions(view_distributions)
        else:
            mean_view_distribution = _softmax(self.state.legal_ir_view_logits)
        family_weights: Dict[str, float] = {}
        for view, weight in mean_view_distribution.items():
            family = legal_ir_view_family_name(str(view))
            if family in LEGAL_IR_VIEW_FAMILIES:
                family_weights[family] = family_weights.get(family, 0.0) + max(
                    0.0, float(weight)
                )
        family_total = sum(family_weights.values())
        if family_total > 0.0:
            family_weights = {
                family: round(weight / family_total, 12)
                for family, weight in sorted(family_weights.items())
                if weight > 0.0
            }

        stable_state = _stable_legal_ir_model_state(self.state)
        model_state_id = "modal-autoencoder-state-" + _hash_json(stable_state)[:24]
        contract_atoms = sorted(
            {
                str(row["feature"]).removeprefix("hammer:contract-id:")
                for row in stable_features
                if str(row["feature"]).startswith("hammer:contract-id:")
            }
        )
        repair_atoms = sorted(
            {
                str(row["feature"]).removeprefix("hammer:repair-lane:")
                for row in stable_features
                if str(row["feature"]).startswith("hammer:repair-lane:")
            }
        )
        export_payload = {
            "contract_feature_atoms": contract_atoms,
            "model_state_id": model_state_id,
            "repair_lane_feature_atoms": repair_atoms,
            "sample_count": len(sample_rows),
            "stable_features": stable_features,
            "view_family_weights": family_weights,
        }
        return StableLegalIRFeatureExport(
            export_id="lir-feature-export-" + _hash_json(export_payload)[:24],
            model_state_id=model_state_id,
            sample_count=len(sample_rows),
            stable_features=tuple(stable_features),
            view_family_weights=family_weights,
            contract_feature_atoms=tuple(contract_atoms),
            repair_lane_feature_atoms=tuple(repair_atoms),
        )

    # Explicit aliases keep the trust-boundary intent discoverable to callers
    # that think in terms of guidance rather than representation export.
    def export_stable_learned_ir_features(
        self,
        samples: Iterable[LegalSample] = (),
        **kwargs: Any,
    ) -> StableLegalIRFeatureExport:
        return self.export_stable_legal_ir_features(samples, **kwargs)

    def export_deterministic_ir_guidance_features(
        self,
        samples: Iterable[LegalSample] = (),
        **kwargs: Any,
    ) -> StableLegalIRFeatureExport:
        return self.export_stable_legal_ir_features(samples, **kwargs)

    def causal_feature_attribution_for_sample(
        self,
        sample: LegalSample,
        *,
        top_k: int = 16,
    ) -> Dict[str, Any]:
        """Return bounded causal/contrastive attribution for one sample.

        The calculation intentionally evaluates reusable feature heads only:
        sample-specific decoded embeddings and family logits are stripped from
        the cloned state before every ablation.
        """

        limit = max(0, int(top_k))
        baseline = self._compiler_gap_metrics_for_sample(sample)
        ablations: Dict[str, Dict[str, Any]] = {}
        for group in COMPILER_ACTIONABLE_FEATURE_GROUPS:
            ablated = self._clone_for_feature_group_ablation(sample, group)
            ablated_metrics = ablated._compiler_gap_metrics_for_sample(sample)
            delta = _metric_delta(ablated_metrics, baseline)
            ablations[group] = {
                "ablated_metrics": ablated_metrics,
                "directional_effect": _directional_effect_from_delta(delta),
                "metric_delta": delta,
                "removed_feature_count": self._feature_group_removed_count(
                    sample,
                    group,
                ),
                "sample_memory_used": False,
            }

        pair_probes = self._legal_minimal_pair_probes_for_sample(
            sample,
            baseline_metrics=baseline,
            top_k=limit,
        )
        return {
            "baseline_metrics": baseline,
            "compiler_actionability": {
                "actionability_requires_cohort": True,
                "compiler_actionable_feature_groups": [],
                "evaluated_group_count": len(COMPILER_ACTIONABLE_FEATURE_GROUPS),
                "frozen_holdout_sample_count": 0,
                "sample_memory_used": False,
            },
            "feature_group_ablations": ablations,
            "legal_minimal_pair_probes": pair_probes,
            "sample_id": sample.sample_id,
            "sample_memory_used": False,
        }

    def causal_feature_attribution(
        self,
        samples: Iterable[LegalSample],
        *,
        frozen_holdout_samples: Iterable[LegalSample] = (),
        legal_ir_targets: Optional[Mapping[str, Any] | Sequence[Any]] = None,
        min_recurrence: float = 0.60,
        min_effect: float = 1.0e-9,
        max_samples: int = 32,
        max_holdout_samples: int = 16,
        top_k: int = 16,
    ) -> Dict[str, Any]:
        """Classify compiler-actionable feature groups across samples.

        A group is actionable only when removing it repeatedly worsens the
        compiler-facing objective on the sampled cohort and the same direction
        survives the frozen holdout.  The method never enables sample memory.
        """

        sample_list = list(samples)[: max(0, int(max_samples))]
        holdout_list = list(frozen_holdout_samples)[: max(0, int(max_holdout_samples))]
        if legal_ir_targets is not None and (sample_list or holdout_list):
            self.evaluate(
                [*sample_list, *holdout_list],
                legal_ir_targets=legal_ir_targets,
                use_sample_memory=False,
            )
        sample_reports = [
            self.causal_feature_attribution_for_sample(sample, top_k=top_k)
            for sample in sample_list
        ]
        holdout_reports = [
            self.causal_feature_attribution_for_sample(sample, top_k=top_k)
            for sample in holdout_list
        ]
        group_summaries: Dict[str, Dict[str, Any]] = {}
        actionable_groups: List[str] = []
        for group in COMPILER_ACTIONABLE_FEATURE_GROUPS:
            sample_effects = [
                _float_or_zero(
                    report["feature_group_ablations"][group]["directional_effect"][
                        "objective_delta"
                    ]
                )
                for report in sample_reports
            ]
            holdout_effects = [
                _float_or_zero(
                    report["feature_group_ablations"][group]["directional_effect"][
                        "objective_delta"
                    ]
                )
                for report in holdout_reports
            ]
            recurring_count = sum(value > min_effect for value in sample_effects)
            recurrence_ratio = (
                recurring_count / len(sample_effects)
                if sample_effects
                else 0.0
            )
            holdout_survived = bool(holdout_effects) and all(
                value > min_effect for value in holdout_effects
            )
            actionable = (
                bool(sample_effects)
                and recurrence_ratio >= max(0.0, min(1.0, float(min_recurrence)))
                and holdout_survived
            )
            if actionable:
                actionable_groups.append(group)
            group_summaries[group] = {
                "actionable": actionable,
                "frozen_holdout_mean_objective_delta": round(
                    _mean(holdout_effects),
                    12,
                ),
                "frozen_holdout_positive_count": sum(
                    value > min_effect for value in holdout_effects
                ),
                "frozen_holdout_sample_count": len(holdout_effects),
                "mean_objective_delta": round(_mean(sample_effects), 12),
                "recurrence_ratio": round(recurrence_ratio, 12),
                "recurring_positive_count": recurring_count,
                "sample_count": len(sample_effects),
            }
        return {
            "compiler_actionable_feature_groups": actionable_groups,
            "feature_group_actionability": group_summaries,
            "frozen_holdout_sample_count": len(holdout_list),
            "sample_count": len(sample_list),
            "sample_memory_used": False,
            "sample_reports": sample_reports,
        }

    def _compiler_gap_metrics_for_sample(self, sample: LegalSample) -> Dict[str, float]:
        family_distribution = self._family_distribution(
            sample,
            use_sample_memory=False,
        )
        target_family_distribution = _observed_family_distribution(sample)
        decoded = self._decoded_for(sample, use_sample_memory=False)
        legal_ir_target_distribution = self._legal_ir_view_target_distribution_for_sample(
            sample,
        )
        legal_ir_predicted_distribution: Dict[str, float] = {}
        if legal_ir_target_distribution:
            legal_ir_predicted_distribution = self._legal_ir_view_distribution(
                sample,
                legal_ir_target_distribution,
                use_sample_memory=False,
            )
        legal_ir_losses = self._compiler_quality_loss_targets_for_sample(sample)
        decompiler_losses = _source_decompiled_text_losses_from_targets(legal_ir_losses)
        return {
            "compiler_ir_cross_entropy_excess_loss": round(
                cross_entropy_excess_distribution_loss(
                    family_distribution,
                    target_family_distribution,
                ),
                12,
            ),
            "compiler_ir_cross_entropy_loss": round(
                cross_entropy_distribution_loss(
                    family_distribution,
                    target_family_distribution,
                ),
                12,
            ),
            "compiler_ir_cosine_similarity": round(
                _distribution_cosine_similarity(
                    family_distribution,
                    target_family_distribution,
                ),
                12,
            ),
            "decompiler_embedding_cosine_loss": round(
                decompiler_losses["source_decompiled_text_embedding_cosine_loss"],
                12,
            ),
            "decompiler_token_loss": round(
                decompiler_losses["source_decompiled_text_token_loss"],
                12,
            ),
            "embedding_cosine_similarity": round(
                cosine_similarity(sample.embedding_vector, decoded),
                12,
            ),
            "formal_validity": round(
                max(0.0, 1.0 - symbolic_validity_penalty(sample)),
                12,
            ),
            "formal_validity_penalty": round(symbolic_validity_penalty(sample), 12),
            "learned_view_cross_entropy_excess_loss": round(
                cross_entropy_excess_distribution_loss(
                    legal_ir_predicted_distribution,
                    legal_ir_target_distribution,
                )
                if legal_ir_target_distribution
                else 0.0,
                12,
            ),
            "learned_view_cross_entropy_loss": round(
                cross_entropy_distribution_loss(
                    legal_ir_predicted_distribution,
                    legal_ir_target_distribution,
                )
                if legal_ir_target_distribution
                else 0.0,
                12,
            ),
            "learned_view_cosine_similarity": round(
                _distribution_cosine_similarity(
                    legal_ir_predicted_distribution,
                    legal_ir_target_distribution,
                )
                if legal_ir_target_distribution
                else 0.0,
                12,
            ),
            "reconstruction_loss": round(
                mse_loss(sample.embedding_vector, decoded),
                12,
            ),
        }

    def _clone_for_feature_group_ablation(
        self,
        sample: LegalSample,
        group: str,
    ) -> "AdaptiveModalAutoencoder":
        clone = object.__new__(self.__class__)
        clone.__dict__ = dict(self.__dict__)
        clone.state = self.state.generalizable_copy()
        clone._sample_feature_cache = {}
        clone._legal_ir_loss_target_cache = {
            key: dict(value)
            for key, value in self._legal_ir_loss_target_cache.items()
        }
        clone._legal_ir_view_target_cache = {
            key: dict(value)
            for key, value in self._legal_ir_view_target_cache.items()
        }
        clone._legal_ir_view_family_candidates_cache = (
            self._legal_ir_view_family_candidates_cache
        )
        clone._ablate_feature_group_state(sample, group)
        return clone

    def _ablate_feature_group_state(self, sample: LegalSample, group: str) -> None:
        prefixes = _feature_group_prefixes(group)
        feature_keys = set(self._feature_group_keys_for(sample, group))
        for mapping in (
            self.state.feature_embedding_weights,
            self.state.feature_family_logits,
            self.state.feature_legal_ir_view_logits,
        ):
            _remove_group_keys(mapping, prefixes=prefixes, keys=feature_keys)
        if group == "compiler-contract":
            self.state.compiler_quality_embedding_weights.clear()
            self.state.compiler_quality_family_logits.clear()
        elif group == "decompiler-template":
            self.state.decompiler_plan_embedding_weights.clear()
            self.state.decompiler_plan_family_logits.clear()
            self.state.decompiler_plan_legal_ir_view_logits.clear()
        elif group == "cycle-consistency":
            self.state.round_trip_signal_embedding_weights.clear()
            self.state.round_trip_signal_family_logits.clear()
            self.state.round_trip_signal_legal_ir_view_logits.clear()
        elif group == "semantic-slot":
            self.state.semantic_slot_embedding_weights.clear()
            self.state.semantic_slot_family_logits.clear()
            self.state.semantic_slot_legal_ir_view_embedding_weights.clear()
            self.state.semantic_slot_legal_ir_view_family_logits.clear()
            self.state.semantic_slot_legal_ir_view_logits.clear()
            self.state.family_semantic_slot_embedding_weights.clear()
            self.state.family_semantic_slot_legal_ir_view_embedding_weights.clear()
            self.state.family_semantic_slot_legal_ir_view_logits.clear()
            self.state.predicate_argument_embedding_weights.clear()
            self.state.predicate_argument_family_logits.clear()
            self.state.predicate_argument_legal_ir_view_logits.clear()
        elif group == "logic-view":
            self.state.logic_signature_embedding_weights.clear()
            self.state.logic_signature_family_logits.clear()
            self.state.logic_signature_legal_ir_view_logits.clear()
            self.state.legal_ir_view_logits.clear()
            self.state.legal_ir_view_embedding_weights.clear()
            self.state.legal_ir_view_family_logits.clear()
            self.state.family_legal_ir_view_embedding_weights.clear()

    def _feature_group_keys_for(self, sample: LegalSample, group: str) -> List[str]:
        if group == "compiler-contract":
            return self._compiler_contract_feature_keys_for(sample)
        if group == "decompiler-template":
            return self._decompiler_surface_template_feature_keys_for(sample)
        if group == "cycle-consistency":
            return self._cycle_consistency_feature_keys_for(sample)
        if group == "semantic-slot":
            return _unique_preserve_order(
                [*self._semantic_slot_distribution_for(sample).keys()]
                + [
                    f"semantic-slot:{slot.removeprefix('slot:')}"
                    for slot in self._semantic_slot_distribution_for(sample).keys()
                ]
            )
        if group == "logic-view":
            return _unique_preserve_order(
                self._logic_view_contract_feature_keys_for(sample)
                + self._legal_ir_view_core_feature_keys_for(sample)
            )
        return []

    def _feature_group_removed_count(self, sample: LegalSample, group: str) -> int:
        keys = set(self._feature_group_keys_for(sample, group))
        prefixes = _feature_group_prefixes(group)
        count = 0
        for mapping in (
            self.state.feature_embedding_weights,
            self.state.feature_family_logits,
            self.state.feature_legal_ir_view_logits,
        ):
            count += sum(
                1
                for key in mapping
                if key in keys or any(str(key).startswith(prefix) for prefix in prefixes)
            )
        if group == "compiler-contract":
            count += len(self.state.compiler_quality_embedding_weights)
            count += len(self.state.compiler_quality_family_logits)
        elif group == "decompiler-template":
            count += len(self.state.decompiler_plan_embedding_weights)
            count += len(self.state.decompiler_plan_family_logits)
            count += len(self.state.decompiler_plan_legal_ir_view_logits)
        elif group == "cycle-consistency":
            count += len(self.state.round_trip_signal_embedding_weights)
            count += len(self.state.round_trip_signal_family_logits)
            count += len(self.state.round_trip_signal_legal_ir_view_logits)
        elif group == "semantic-slot":
            count += len(self.state.semantic_slot_embedding_weights)
            count += len(self.state.semantic_slot_family_logits)
            count += len(self.state.semantic_slot_legal_ir_view_logits)
            count += len(self.state.predicate_argument_embedding_weights)
        elif group == "logic-view":
            count += len(self.state.logic_signature_embedding_weights)
            count += len(self.state.logic_signature_family_logits)
            count += len(self.state.logic_signature_legal_ir_view_logits)
            count += len(self.state.legal_ir_view_logits)
            count += len(self.state.legal_ir_view_embedding_weights)
            count += len(self.state.legal_ir_view_family_logits)
        return count

    def _legal_minimal_pair_probes_for_sample(
        self,
        sample: LegalSample,
        *,
        baseline_metrics: Mapping[str, float],
        top_k: int,
    ) -> Dict[str, Dict[str, Any]]:
        probes: Dict[str, Dict[str, Any]] = {}
        for group in COMPILER_ACTIONABLE_FEATURE_GROUPS:
            pair_text, transformation = _minimal_pair_text_for_group(
                sample.text or sample.normalized_text,
                group,
            )
            if pair_text == (sample.text or sample.normalized_text):
                continue
            pair_sample = build_us_code_sample(
                title=sample.title,
                section=sample.section,
                citation=sample.citation,
                text=pair_text,
                embedding_model=sample.embedding_model,
                embedding_vector=stable_mock_embedding(
                    pair_text,
                    dimensions=len(sample.embedding_vector),
                ),
            )
            pair_metrics = self._compiler_gap_metrics_for_sample(pair_sample)
            ablated_pair = self._clone_for_feature_group_ablation(pair_sample, group)
            ablated_pair_metrics = ablated_pair._compiler_gap_metrics_for_sample(
                pair_sample
            )
            probes[group] = {
                "ablated_pair_metric_delta": _metric_delta(
                    ablated_pair_metrics,
                    pair_metrics,
                ),
                "pair_metric_delta": _metric_delta(pair_metrics, baseline_metrics),
                "pair_sample_hash": _hash_text(pair_sample.sample_id),
                "sample_memory_used": False,
                "transformation": transformation,
            }
        return dict(list(sorted(probes.items()))[: max(0, int(top_k))])

    def _rank_guidance_features(
        self,
        features: Sequence[str],
        *,
        top_k: int,
    ) -> List[Dict[str, Any]]:
        scored: List[Dict[str, Any]] = []
        for feature in _unique_preserve_order(str(feature) for feature in features):
            embedding_weight_norm = _vector_norm(
                self.state.feature_embedding_weights.get(feature, [])
            )
            family_logit_magnitude = _max_abs_mapping(
                self.state.feature_family_logits.get(feature, {})
            )
            legal_ir_view_logit_magnitude = _max_abs_mapping(
                self.state.feature_legal_ir_view_logits.get(feature, {})
            )
            score = (
                embedding_weight_norm
                + family_logit_magnitude
                + legal_ir_view_logit_magnitude
            )
            if score <= 0.0 and not self._is_core_modal_feature_key(feature):
                continue
            scored.append(
                {
                    "embedding_weight_norm": round(embedding_weight_norm, 12),
                    "family_logit_magnitude": round(family_logit_magnitude, 12),
                    "feature": feature,
                    "legal_ir_view_logit_magnitude": round(
                        legal_ir_view_logit_magnitude,
                        12,
                    ),
                    "score": round(score, 12),
                }
            )
        scored.sort(key=lambda item: (float(item["score"]), item["feature"]), reverse=True)
        return scored[:top_k] if top_k else scored

    def codex_call_decision(
        self,
        sample: LegalSample,
        *,
        config: Optional[CodexCallGateConfig] = None,
        cache: Optional[CodexCallCache] = None,
        prover_signal: Optional[ProverCompilationSignal] = None,
        legal_ir_bridge_names: Sequence[str] | str = (),
        legal_ir_targets: Optional[Mapping[str, Any] | Sequence[Any]] = None,
        use_sample_memory: bool = False,
    ) -> CodexCallDecision:
        """Decide whether this sample is worth an expensive Codex advisor call."""
        gate = config or CodexCallGateConfig()
        evaluation = self.evaluate(
            [sample],
            legal_ir_bridge_names=legal_ir_bridge_names,
            legal_ir_targets=legal_ir_targets,
            use_sample_memory=use_sample_memory,
        )
        metrics = {
            "cosine_loss": evaluation.cosine_loss,
            "cross_entropy_loss": evaluation.cross_entropy_loss,
            "embedding_cosine_similarity": evaluation.embedding_cosine_similarity,
            "frame_ranking_loss": evaluation.frame_ranking_loss,
            "legal_ir_target_count": float(evaluation.legal_ir_target_count),
            "reconstruction_loss": evaluation.reconstruction_loss,
            "symbolic_validity_penalty": evaluation.symbolic_validity_penalty,
        }
        metrics.update(
            {
                str(name): float(value)
                for name, value in sorted(evaluation.legal_ir_losses.items())
            }
        )
        feature_signature = self.codex_feature_signature(sample)
        text_hash = _hash_text(sample.normalized_text)
        feature_signature_hash = _hash_json(feature_signature)
        reasons: List[str] = []
        suppressed_reasons: List[str] = []

        if evaluation.embedding_cosine_similarity < gate.min_cosine_similarity:
            reasons.append("low_embedding_cosine_similarity")
        if evaluation.cross_entropy_loss > gate.max_cross_entropy_loss:
            reasons.append("high_cross_entropy_loss")
        if evaluation.reconstruction_loss > gate.max_reconstruction_loss:
            reasons.append("high_reconstruction_loss")
        if evaluation.frame_ranking_loss > gate.max_frame_ranking_loss:
            reasons.append("frame_ranking_uncertain")
        if evaluation.symbolic_validity_penalty > gate.max_symbolic_validity_penalty:
            reasons.append("missing_or_invalid_symbolic_ir")
        if evaluation.legal_ir_target_count > 0:
            if (
                metrics.get("legal_ir_multiview_total_loss", 0.0)
                > gate.max_legal_ir_multiview_total_loss
            ):
                reasons.append("high_legal_ir_multiview_total_loss")
            if (
                metrics.get("legal_ir_view_cross_entropy_loss", 0.0)
                > gate.max_legal_ir_view_cross_entropy_loss
            ):
                reasons.append("high_legal_ir_view_cross_entropy_loss")
            if (
                metrics.get("legal_ir_multiview_proof_failure_ratio", 0.0)
                > gate.max_legal_ir_proof_failure_ratio
            ):
                reasons.append("legal_ir_prover_gate_failed")
            if (
                metrics.get("legal_ir_multiview_graph_failure_penalty", 0.0)
                > gate.max_legal_ir_graph_failure_penalty
            ):
                reasons.append("legal_ir_graph_projection_failed")

        if gate.require_prover_compilation:
            resolved_prover_signal = prover_signal or evaluate_modal_prover_compilation(sample)
            prover_signal = resolved_prover_signal
            if resolved_prover_signal.attempted_count == 0:
                reasons.append("no_modal_formula_for_prover")
            elif not resolved_prover_signal.compiles:
                if resolved_prover_signal.unavailable_count:
                    reasons.append("prover_route_unavailable")
                if resolved_prover_signal.error_count:
                    reasons.append("prover_error")
                if resolved_prover_signal.failed_count:
                    reasons.append("prover_rejected_ir")

        local_loss = _codex_gate_local_loss(
            metrics,
            gate,
            prover_signal=prover_signal,
        )
        net_benefit = local_loss - max(0.0, float(gate.codex_call_cost))

        if cache is not None:
            if (
                gate.max_codex_calls is not None
                and cache.codex_call_count >= gate.max_codex_calls
            ):
                suppressed_reasons.append("codex_call_budget_exhausted")
            if not gate.allow_repeat_signatures:
                if text_hash in cache.codex_text_hashes:
                    suppressed_reasons.append("duplicate_text_hash")
                if feature_signature_hash in cache.codex_feature_signature_hashes:
                    suppressed_reasons.append("duplicate_feature_signature")

        if net_benefit < gate.min_net_benefit:
            suppressed_reasons.append("codex_cost_exceeds_expected_benefit")

        should_call = bool(reasons) and not suppressed_reasons
        return CodexCallDecision(
            should_call_codex=should_call,
            reasons=_unique_preserve_order(reasons),
            suppressed_reasons=_unique_preserve_order(suppressed_reasons),
            local_loss=round(local_loss, 12),
            codex_call_cost=round(max(0.0, float(gate.codex_call_cost)), 12),
            net_benefit=round(net_benefit, 12),
            text_hash=text_hash,
            feature_signature=feature_signature,
            feature_signature_hash=feature_signature_hash,
            metrics={key: round(float(value), 12) for key, value in metrics.items()},
            prover_signal=prover_signal,
        )

    def codex_feature_signature(self, sample: LegalSample) -> List[str]:
        """Return the stable signature used to batch or suppress Codex calls."""
        keys = [
            f"text-shape:{_text_shape(sample.normalized_text)}",
            f"formula-count:{len(sample.modal_ir.formulas)}",
        ]
        keys.extend(self._feature_keys_for(sample))
        return _unique_preserve_order(keys)

    def proof_auxiliary_head_architecture(self) -> Dict[str, Any]:
        """Describe the bounded, objective-isolated proof supervision heads."""

        return {
            "architecture_version": self.state.architecture_version,
            "head_count": len(PROOF_AUXILIARY_HEAD_NAMES),
            "heads": {
                head: {
                    "kind": (
                        "multilabel"
                        if head in PROOF_AUXILIARY_MULTILABEL_HEADS
                        else "categorical"
                    ),
                    "max_labels": self.proof_head_max_labels,
                }
                for head in PROOF_AUXILIARY_HEAD_NAMES
            },
            "max_family_contexts": self.proof_head_max_family_contexts,
            "objective_isolation": {
                "proof_loss_weight_in_primary_objective": 0.0,
                "protected_objectives": list(
                    PROOF_AUXILIARY_PROTECTED_OBJECTIVES
                ),
                "separate_parameters": True,
            },
            "proof_feedback_version_fingerprint": (
                self.state.proof_feedback_version_fingerprint
            ),
            "schema_version": PROOF_AUXILIARY_HEAD_SCHEMA_VERSION,
        }

    def predict_proof_auxiliary_heads(
        self,
        legal_ir_family: str,
        *,
        abstention_threshold: Optional[float] = None,
    ) -> Dict[str, Any]:
        """Return bounded proof-head probabilities for one LegalIR family.

        These predictions are advisory.  They are never fed into the compiler
        CE, embedding, structural, provenance, or anti-copy objectives.
        """

        family = _proof_auxiliary_family_context(legal_ir_family)
        threshold = (
            self.proof_head_abstention_threshold
            if abstention_threshold is None
            else max(0.0, min(1.0, float(abstention_threshold)))
        )
        heads: Dict[str, Any] = {}
        for head in PROOF_AUXILIARY_HEAD_NAMES:
            logits = self._proof_auxiliary_logits(head, family)
            kind = (
                "multilabel"
                if head in PROOF_AUXILIARY_MULTILABEL_HEADS
                else "categorical"
            )
            if kind == "multilabel":
                probabilities = {
                    label: _sigmoid(value)
                    for label, value in sorted(logits.items())
                }
                selected = [
                    label
                    for label, probability in probabilities.items()
                    if probability >= 0.5
                ]
                confidence = max(probabilities.values(), default=0.0)
                prediction: Any = selected
            else:
                probabilities = _softmax(logits)
                prediction = (
                    max(probabilities, key=probabilities.get)
                    if probabilities
                    else None
                )
                confidence = (
                    float(probabilities.get(prediction, 0.0))
                    if prediction is not None
                    else 0.0
                )
            abstained = not probabilities or confidence < threshold
            heads[head] = {
                "abstained": abstained,
                "confidence": round(confidence, 12),
                "kind": kind,
                "prediction": None if abstained else prediction,
                "probabilities": {
                    label: round(float(probability), 12)
                    for label, probability in sorted(probabilities.items())
                },
            }
        return {
            "architecture_version": self.state.architecture_version,
            "bounded": all(
                len(payload["probabilities"]) <= self.proof_head_max_labels
                for payload in heads.values()
            ),
            "family": family,
            "heads": heads,
            "proof_feedback_version_fingerprint": (
                self.state.proof_feedback_version_fingerprint
            ),
            "schema_version": PROOF_AUXILIARY_HEAD_SCHEMA_VERSION,
        }

    def evaluate_proof_auxiliary_heads(
        self,
        feedback_records: Iterable[Any],
        *,
        expected_versions: Optional[Any] = None,
        expected_version_fingerprint: str = "",
        require_train_partition: bool = False,
        abstention_threshold: Optional[float] = None,
    ) -> Dict[str, Any]:
        """Report loss, calibration, coverage, and abstention by family."""

        expected_fingerprint = (
            str(expected_version_fingerprint or "").strip()
            or _proof_feedback_expected_fingerprint(expected_versions)
            or self.state.proof_feedback_version_fingerprint
        )
        records, filtering = _validated_proof_feedback_records(
            feedback_records,
            expected_fingerprint=expected_fingerprint,
            require_train_partition=require_train_partition,
        )
        metrics = _proof_auxiliary_metrics(
            self,
            records,
            abstention_threshold=abstention_threshold,
        )
        metrics.update(
            {
                "architecture_version": self.state.architecture_version,
                "candidate_count": filtering["candidate_count"],
                "eligible_count": len(records),
                "proof_feedback_version_fingerprint": expected_fingerprint,
                "schema_version": PROOF_AUXILIARY_TRAINING_SCHEMA_VERSION,
                "skipped_holdout_count": filtering["skipped_holdout_count"],
                "skipped_invalid_count": filtering["skipped_invalid_count"],
                "skipped_untrusted_count": filtering["skipped_untrusted_count"],
                "skipped_version_mismatch_count": filtering[
                    "skipped_version_mismatch_count"
                ],
            }
        )
        return metrics

    def train_proof_auxiliary_heads(
        self,
        feedback_records: Iterable[Any],
        *,
        expected_versions: Optional[Any] = None,
        expected_version_fingerprint: str = "",
        learning_rate: float = 0.10,
        max_records: int = 256,
        require_train_partition: bool = True,
        abstention_threshold: Optional[float] = None,
    ) -> Dict[str, Any]:
        """Train all proof heads from version-matched verifier feedback only.

        The first accepted version pins an empty head state.  A caller may pin
        it explicitly with ``expected_versions``.  Once pinned, records from a
        different compiler/toolchain fingerprint are rejected.  Holdout rows
        are excluded by default.
        """

        raw_records = _proof_feedback_record_items(feedback_records)
        requested_fingerprint = (
            str(expected_version_fingerprint or "").strip()
            or _proof_feedback_expected_fingerprint(expected_versions)
        )
        pinned_fingerprint = self.state.proof_feedback_version_fingerprint
        expected_fingerprint = requested_fingerprint or pinned_fingerprint
        protected_before = _proof_protected_objective_fingerprint(self.state)
        update_before_state = self.state.copy()
        records, filtering = _validated_proof_feedback_records(
            raw_records,
            expected_fingerprint=expected_fingerprint,
            require_train_partition=require_train_partition,
        )
        if not expected_fingerprint and records:
            expected_fingerprint = records[0].version_fingerprint
            records = [
                record
                for record in records
                if record.version_fingerprint == expected_fingerprint
            ]
            filtering["skipped_version_mismatch_count"] += (
                filtering["eligible_before_version_count"] - len(records)
            )

        configuration_mismatch = bool(
            requested_fingerprint
            and pinned_fingerprint
            and requested_fingerprint != pinned_fingerprint
        )
        if configuration_mismatch:
            filtering["skipped_version_mismatch_count"] += len(records)
            records = []
            expected_fingerprint = pinned_fingerprint

        step = _clamp_learning_rate(learning_rate)
        record_limit = max(0, int(max_records))
        applied_ids = set(self.state.applied_proof_feedback_ids)
        duplicate_count = 0
        applied_records: List[Any] = []
        updated_head_counts = {head: 0 for head in PROOF_AUXILIARY_HEAD_NAMES}
        dropped_label_count = 0

        if step > 0.0 and record_limit > 0 and not configuration_mismatch:
            cuda_proof_update: Optional[Dict[str, Any]] = None
            if self.compute_backend == "torch_cuda":
                try:
                    from .modal_autoencoder_cuda import (
                        apply_cuda_resident_proof_updates,
                    )

                    cuda_proof_update = apply_cuda_resident_proof_updates(
                        self,
                        records,
                        applied_ids=applied_ids,
                        learning_rate=step,
                        record_limit=record_limit,
                        head_names=PROOF_AUXILIARY_HEAD_NAMES,
                        family_for_record=_proof_feedback_record_family,
                        targets_for_record=_proof_auxiliary_targets,
                        max_applied_record_ids=PROOF_AUXILIARY_MAX_APPLIED_RECORD_IDS,
                    )
                except Exception:
                    cuda_proof_update = None
            if cuda_proof_update is not None:
                applied_records = list(cuda_proof_update["applied_records"])
                duplicate_count = int(cuda_proof_update["duplicate_count"])
                dropped_label_count = int(cuda_proof_update["dropped_label_count"])
                updated_head_counts = dict(cuda_proof_update["updated_head_counts"])
                self._cuda_residency_reports.append(
                    dict(cuda_proof_update.get("report", {}))
                )
                self._cuda_residency_reports = self._cuda_residency_reports[-256:]
            else:
                for record in records[:record_limit]:
                    if record.record_id in applied_ids:
                        duplicate_count += 1
                        continue
                    family = _proof_feedback_record_family(record)
                    targets = _proof_auxiliary_targets(record)
                    record_updated = False
                    for head in PROOF_AUXILIARY_HEAD_NAMES:
                        labels = targets[head]
                        updated, dropped = self._update_proof_auxiliary_head(
                            head,
                            family,
                            labels,
                            learning_rate=step,
                        )
                        dropped_label_count += dropped
                        if updated:
                            updated_head_counts[head] += 1
                            record_updated = True
                    if not record_updated:
                        continue
                    self.state.applied_proof_feedback_ids.append(record.record_id)
                    self.state.applied_proof_feedback_ids = (
                        self.state.applied_proof_feedback_ids[
                            -PROOF_AUXILIARY_MAX_APPLIED_RECORD_IDS:
                        ]
                    )
                    applied_ids.add(record.record_id)
                    applied_records.append(record)

        if applied_records and not self.state.proof_feedback_version_fingerprint:
            self.state.proof_feedback_version_fingerprint = expected_fingerprint

        metrics = _proof_auxiliary_metrics(
            self,
            applied_records,
            abstention_threshold=abstention_threshold,
        )
        protected_after = _proof_protected_objective_fingerprint(self.state)
        norm_report = legal_ir_trainable_head_delta_norm_report(
            update_before_state,
            self.state,
            learning_rate=step,
        )
        objective_isolation = {
            "proof_loss_weight_in_primary_objective": 0.0,
            "protected_objectives": list(PROOF_AUXILIARY_PROTECTED_OBJECTIVES),
            "protected_parameters_unchanged": protected_before == protected_after,
            "separate_parameters": True,
        }
        metrics.update(
            {
                "applied_count": len(applied_records),
                "architecture_version": self.state.architecture_version,
                "candidate_count": filtering["candidate_count"],
                "configuration_version_mismatch": configuration_mismatch,
                "dropped_label_count": dropped_label_count,
                "duplicate_count": duplicate_count,
                "eligible_count": len(records),
                "gradient_norms_by_family": norm_report[
                    "gradient_norms_by_family"
                ],
                "gradient_norms_by_head": norm_report["gradient_norms_by_head"],
                "head_update_counts": updated_head_counts,
                "head_family_gradient_norms": norm_report[
                    "head_family_gradient_norms"
                ],
                "head_family_update_norms": norm_report[
                    "head_family_update_norms"
                ],
                "objective_isolation": objective_isolation,
                "proof_feedback_version_fingerprint": (
                    self.state.proof_feedback_version_fingerprint
                    or expected_fingerprint
                ),
                "schema_version": PROOF_AUXILIARY_TRAINING_SCHEMA_VERSION,
                "skipped_holdout_count": filtering["skipped_holdout_count"],
                "skipped_invalid_count": filtering["skipped_invalid_count"],
                "skipped_limit_count": max(
                    0,
                    len(records) - record_limit,
                ),
                "skipped_untrusted_count": filtering["skipped_untrusted_count"],
                "skipped_version_mismatch_count": filtering[
                    "skipped_version_mismatch_count"
                ],
                "status": (
                    "applied"
                    if applied_records
                    else "version_mismatch"
                    if configuration_mismatch
                    else "disabled"
                    if step <= 0.0 or record_limit <= 0
                    else "no_applicable_feedback"
                ),
                "trainable_legal_ir_head_norms": norm_report,
                "update_norms_by_family": norm_report["update_norms_by_family"],
                "update_norms_by_head": norm_report["update_norms_by_head"],
            }
        )
        return metrics

    def train_proof_feedback_heads(
        self,
        feedback_records: Iterable[Any],
        **kwargs: Any,
    ) -> Dict[str, Any]:
        """Compatibility alias for :meth:`train_proof_auxiliary_heads`."""

        return self.train_proof_auxiliary_heads(feedback_records, **kwargs)

    def apply_proof_feedback(
        self,
        feedback_records: Iterable[Any],
        **kwargs: Any,
    ) -> Dict[str, Any]:
        """Apply trusted proof records to the isolated auxiliary heads."""

        return self.train_proof_auxiliary_heads(feedback_records, **kwargs)

    def apply_proof_feedback_records(
        self,
        feedback_records: Iterable[Any],
        **kwargs: Any,
    ) -> Dict[str, Any]:
        """Compatibility alias for proof-feedback replay callers."""

        return self.train_proof_auxiliary_heads(feedback_records, **kwargs)

    def evaluate_proof_feedback_heads(
        self,
        feedback_records: Iterable[Any],
        **kwargs: Any,
    ) -> Dict[str, Any]:
        """Compatibility alias for proof-head evaluation callers."""

        return self.evaluate_proof_auxiliary_heads(feedback_records, **kwargs)

    def _proof_auxiliary_logits(
        self,
        head: str,
        family: str,
    ) -> Dict[str, float]:
        contexts = self.state.proof_auxiliary_head_logits.get(head, {})
        global_logits = contexts.get(PROOF_AUXILIARY_GLOBAL_CONTEXT, {})
        family_logits = contexts.get(family, {})
        labels = sorted(set(global_logits) | set(family_logits))[
            : self.proof_head_max_labels
        ]
        return {
            label: (
                float(global_logits.get(label, 0.0))
                + float(family_logits.get(label, 0.0))
            )
            / (2.0 if global_logits and family_logits else 1.0)
            for label in labels
        }

    def _update_proof_auxiliary_head(
        self,
        head: str,
        family: str,
        target_labels: Sequence[str],
        *,
        learning_rate: float,
    ) -> tuple[bool, int]:
        contexts = self.state.proof_auxiliary_head_logits.setdefault(head, {})
        vocabulary = {
            label
            for logits in contexts.values()
            for label in logits
        }
        targets: List[str] = []
        dropped = 0
        for raw_label in target_labels:
            label = _proof_auxiliary_label(raw_label)
            if label in vocabulary or len(vocabulary) < self.proof_head_max_labels:
                if label not in vocabulary:
                    vocabulary.add(label)
                targets.append(label)
            else:
                dropped += 1
        targets = _unique_preserve_order(targets)
        if not targets:
            return False, dropped

        contexts_to_update = [PROOF_AUXILIARY_GLOBAL_CONTEXT]
        if family != PROOF_AUXILIARY_GLOBAL_CONTEXT:
            if family in contexts or len(contexts) < self.proof_head_max_family_contexts:
                contexts_to_update.append(family)
        per_context_step = learning_rate / math.sqrt(len(contexts_to_update))
        for context in contexts_to_update:
            logits = contexts.setdefault(context, {})
            labels = sorted(vocabulary)
            for label in labels:
                logits.setdefault(label, 0.0)
            if head in PROOF_AUXILIARY_MULTILABEL_HEADS:
                target_set = set(targets)
                for label in labels:
                    prediction = _sigmoid(logits[label])
                    target = 1.0 if label in target_set else 0.0
                    logits[label] = _clip_float(
                        logits[label] + per_context_step * (target - prediction),
                        self.proof_head_logit_clip,
                    )
            else:
                target = targets[0]
                probabilities = _softmax(logits)
                for label in labels:
                    logits[label] = _clip_float(
                        logits[label]
                        + per_context_step
                        * ((1.0 if label == target else 0.0) - probabilities[label]),
                        self.proof_head_logit_clip,
                    )
        return True, dropped

    def trusted_hammer_leanstral_feature_bus(
        self,
        guidance: Any,
        *,
        require_trusted: bool = True,
    ) -> Dict[str, Any]:
        """Expose the source-free feature-bus receipt used for model updates."""

        return trusted_hammer_leanstral_feature_bus(
            guidance,
            require_trusted=require_trusted,
        )

    def apply_leanstral_guidance(
        self,
        guidance: Any,
        samples_by_id: Optional[Mapping[str, LegalSample]] = None,
        *,
        learning_rate: float = 0.05,
        allow_global_updates: bool = True,
        max_items: int = 64,
        require_trusted: bool = True,
    ) -> Dict[str, Any]:
        """Train LegalIR view logits from trusted Leanstral draft guidance.

        Leanstral guidance is intentionally treated as a view-selection target,
        not as text reconstruction data.  All updates cross the trusted feature
        bus, which keeps only bounded categorical contract signals and never
        exposes drafted logic, proof prose, or source spans to learned heads.
        """

        items = self._leanstral_guidance_items(guidance)
        item_limit = max(0, int(max_items))
        step = _clamp_learning_rate(learning_rate)
        sample_lookup = dict(samples_by_id or {})
        report: Dict[str, Any] = {
            "applied_count": 0,
            "candidate_count": len(items),
            "duplicate_count": 0,
            "guidance_ids": [],
            "hammer_guidance_count": 0,
            "hammer_metrics": hammer_guidance_metric_block(items),
            "missing_sample_count": 0,
            "sample_aware_update_count": 0,
            "schema_version": "legal-ir-leanstral-autoencoder-training-v1",
            "skipped_invalid_count": 0,
            "skipped_missing_sample_count": 0,
            "skipped_no_target_count": 0,
            "skipped_untrusted_count": 0,
            "target_view_counts": {},
            "trusted_feature_bus_excluded_field_count": 0,
            "trusted_feature_bus_feature_count": 0,
            "trusted_feature_bus_item_count": 0,
            "trusted_feature_bus_schema_version": (
                TRUSTED_HAMMER_FEATURE_BUS_SCHEMA_VERSION
            ),
            "updated_guidance_feature_count": 0,
        }
        if item_limit <= 0 or not items or step <= 0.0:
            report["status"] = "disabled" if step <= 0.0 else "no_guidance"
            return report

        applied_ids = set(self.state.applied_leanstral_guidance_ids)
        for raw_item in items[:item_limit]:
            item = self._normalize_leanstral_guidance_item(raw_item)
            if not item:
                report["skipped_invalid_count"] += 1
                continue
            feature_bus = build_trusted_hammer_leanstral_feature_bus(
                item,
                require_trusted=require_trusted,
            )
            guidance_id = feature_bus.guidance_id
            if guidance_id in applied_ids:
                report["duplicate_count"] += 1
                continue
            if require_trusted and not feature_bus.trusted:
                report["skipped_untrusted_count"] += 1
                continue
            target_distribution = self._leanstral_guidance_target_distribution(
                feature_bus.learning_payload
            )
            if not target_distribution:
                report["skipped_no_target_count"] += 1
                continue

            sample_id = str(item.get("sample_id") or "").strip()
            sample = sample_lookup.get(sample_id)
            if sample is not None:
                changed = self._nudge_legal_ir_view_logits_toward_distribution(
                    sample,
                    target_distribution,
                    learning_rate=step,
                    update_sample_memory=False,
                )
                if changed:
                    report["sample_aware_update_count"] += 1
            else:
                report["missing_sample_count"] += 1
                if not allow_global_updates:
                    report["skipped_missing_sample_count"] += 1
                    continue
                self._nudge_legal_ir_view_global_logits_toward_distribution(
                    target_distribution,
                    learning_rate=step,
                )

            report["updated_guidance_feature_count"] += (
                self._nudge_leanstral_guidance_feature_logits(
                    self._leanstral_guidance_feature_keys(
                        item,
                        feature_bus=feature_bus,
                    ),
                    target_distribution,
                    learning_rate=step,
                )
            )
            report["trusted_feature_bus_item_count"] += 1
            report["trusted_feature_bus_feature_count"] += feature_bus.feature_count
            report["trusted_feature_bus_excluded_field_count"] += len(
                feature_bus.excluded_field_paths
            )
            if self._leanstral_guidance_is_hammer_item(item):
                report["hammer_guidance_count"] += 1
            self.state.applied_leanstral_guidance_ids.append(guidance_id)
            applied_ids.add(guidance_id)
            report["guidance_ids"].append(guidance_id)
            report["applied_count"] += 1
            target_counts = report["target_view_counts"]
            for view, weight in target_distribution.items():
                target_counts[view] = round(
                    float(target_counts.get(view, 0.0)) + float(weight),
                    12,
                )

        report["status"] = (
            "applied" if int(report["applied_count"]) > 0 else "no_applicable_guidance"
        )
        report["guidance_ids"] = report["guidance_ids"][:64]
        report["target_view_counts"] = dict(sorted(report["target_view_counts"].items()))
        if isinstance(report.get("hammer_metrics"), Mapping):
            report["hammer_guidance_count"] = int(
                dict(report["hammer_metrics"]).get(
                    "hammer_artifact_count",
                    report["hammer_guidance_count"],
                )
                or 0
            )
        return report

    def _leanstral_guidance_items(self, guidance: Any) -> List[Mapping[str, Any]]:
        if guidance is None:
            return []
        normalized = self._normalize_leanstral_guidance_item(guidance)
        if isinstance(guidance, Mapping):
            nested: List[Mapping[str, Any]] = []
            for key in (
                "leanstral_guidance",
                "guidance",
                "latest_leanstral_guidance",
                "external_guidance",
                "hammer_guidance_artifacts",
                "verified_guidance",
            ):
                value = guidance.get(key)
                if value is not None:
                    nested.extend(self._leanstral_guidance_items(value))
            candidate_results = guidance.get("candidate_results")
            if isinstance(candidate_results, Sequence) and not isinstance(
                candidate_results,
                (bytes, bytearray, str),
            ):
                for candidate_result in candidate_results:
                    if not isinstance(candidate_result, Mapping):
                        continue
                    for key in ("verified_guidance", "hammer_guidance_artifacts"):
                        value = candidate_result.get(key)
                        if value is not None:
                            nested.extend(self._leanstral_guidance_items(value))
                    hammer_report = candidate_result.get("hammer_report")
                    if isinstance(hammer_report, Mapping):
                        nested.extend(
                            self._leanstral_guidance_items(
                                hammer_report.get("artifacts")
                            )
                        )
            for key in (
                "guidance_items",
                "items",
                "compiler_guidance",
                "leanstral_shadow",
            ):
                value = guidance.get(key)
                if value is not None:
                    nested.extend(self._leanstral_guidance_items(value))
            if nested:
                return nested
            return [normalized] if normalized else []
        if isinstance(guidance, Sequence) and not isinstance(
            guidance,
            (bytes, bytearray, str),
        ):
            items: List[Mapping[str, Any]] = []
            for value in guidance:
                items.extend(self._leanstral_guidance_items(value))
            return items
        return [normalized] if normalized else []

    def _normalize_leanstral_guidance_item(
        self,
        item: Any,
    ) -> Dict[str, Any]:
        if item is None:
            return {}
        if hasattr(item, "to_dict") and callable(getattr(item, "to_dict")):
            try:
                item = item.to_dict()
            except (TypeError, ValueError):
                return {}
        elif hasattr(item, "guidance"):
            item = getattr(item, "guidance")
        if isinstance(item, Mapping):
            return {str(key): value for key, value in dict(item).items()}
        return {}

    def _leanstral_guidance_id(self, item: Mapping[str, Any]) -> str:
        for key in ("guidance_id", "task_id", "leanstral_task_id", "modal_ir_hash"):
            value = str(item.get(key) or "").strip()
            if value:
                return value
        return "leanstral-guidance-" + _hash_json(dict(item))[:16]

    def _leanstral_guidance_is_trusted(self, item: Mapping[str, Any]) -> bool:
        return _trusted_guidance_is_trusted(item)

    def _leanstral_guidance_is_hammer_item(self, item: Mapping[str, Any]) -> bool:
        source = str(item.get("source") or "").strip().lower()
        return (
            source == "hammer_verified_guidance"
            or bool(item.get("backend_statuses"))
            or bool(item.get("selected_premises"))
            or bool(item.get("reconstruction_status"))
            or str(item.get("schema_version") or "").startswith("legal-ir-hammer-")
        )

    def _leanstral_guidance_target_distribution(
        self,
        item: Mapping[str, Any],
    ) -> Dict[str, float]:
        scores: Dict[str, float] = {}

        def bump(view: str, weight: float) -> None:
            name = str(view or "").strip()
            normalized_weight = max(0.0, float(weight))
            if not name or normalized_weight <= 0.0:
                return
            scores[name] = scores.get(name, 0.0) + normalized_weight

        def bump_hint(value: Any, weight: float) -> None:
            text = str(value or "").strip()
            if not text:
                return
            if text in {
                "CEC.native",
                "TDFOL.prover",
                "deontic.ir",
                "external_provers.router",
                "knowledge_graphs.neo4j_compat",
                "modal.autoencoder",
                "modal.frame_logic",
                "zkp.circuits",
            }:
                bump(text, weight)
                return
            bump(_legal_ir_timeout_view_for_bridge_name(text), weight)

        for key, weight in (
            ("legal_ir_view", 0.80),
            ("target_component", 0.70),
            ("target_view", 0.55),
            ("compiler_surface", 0.35),
            ("program_synthesis_scope", 0.30),
            ("action", 0.20),
        ):
            bump_hint(item.get(key), weight)
        if item.get("proved") is True or item.get("proof_checked") is True:
            bump_hint(item.get("legal_ir_view") or item.get("target_component"), 0.30)
        if str(item.get("reconstruction_status") or "").lower() == "verified":
            bump_hint(item.get("legal_ir_view") or item.get("target_component"), 0.20)

        for metric in self._leanstral_sequence(item.get("target_metrics")):
            bump_hint(metric, 0.18)
            metric_text = str(metric).lower()
            if "graph" in metric_text or "kg" in metric_text:
                bump("knowledge_graphs.neo4j_compat", 0.25)
            if "proof" in metric_text or "prover" in metric_text:
                bump("external_provers.router", 0.20)
            if "deontic" in metric_text or "norm" in metric_text:
                bump("deontic.ir", 0.25)

        for template in self._leanstral_sequence(item.get("theorem_templates")):
            bump_hint(template, 0.16)
            template_text = str(template).lower()
            if "exception" in template_text or "scope" in template_text:
                bump("deontic.ir", 0.22)
            if "round_trip" in template_text or "decompiler" in template_text:
                bump("modal.frame_logic", 0.18)
            if "graph" in template_text:
                bump("knowledge_graphs.neo4j_compat", 0.24)

        for mutation in self._leanstral_sequence(item.get("mutation_cases")):
            mutation_text = str(mutation).lower()
            if "exception" in mutation_text or "modality" in mutation_text:
                bump("deontic.ir", 0.18)
            if "deadline" in mutation_text or "temporal" in mutation_text:
                bump("CEC.native", 0.12)
                bump("TDFOL.prover", 0.16)

        proof_ids = self._leanstral_sequence(item.get("proof_obligation_ids"))
        if proof_ids:
            bump("TDFOL.prover", 0.12 * min(3, len(proof_ids)))
            bump("external_provers.router", 0.08 * min(3, len(proof_ids)))
        if item.get("obligation_id"):
            bump("external_provers.router", 0.08)
        for premise_view in self._leanstral_sequence(item.get("premise_views")):
            bump_hint(premise_view, 0.12)
        for backend_status in self._leanstral_sequence(item.get("backend_statuses")):
            status_text = str(backend_status).lower()
            if "proved" in status_text or "verified" in status_text:
                bump("external_provers.router", 0.10)

        for candidate in self._leanstral_sequence(item.get("drafted_logic_candidates")):
            if not isinstance(candidate, Mapping):
                continue
            confidence = _float_or_zero(candidate.get("confidence"))
            if confidence <= 0.0:
                confidence = 0.5
            confidence = min(1.0, confidence)
            family = _feature_atom(
                candidate.get("logic_family") or candidate.get("family"),
                max_tokens=3,
            )
            if family:
                mapped_views = _AUTOENCODER_FAMILY_LEGAL_IR_VIEW_TARGETS.get(
                    family,
                    (),
                )
                if mapped_views:
                    for view in mapped_views:
                        bump(view, 0.55 * confidence / len(mapped_views))
                else:
                    bump_hint(family, 0.35 * confidence)
            bump_hint(candidate.get("compiler_surface"), 0.20 * confidence)
            bump_hint(candidate.get("target_view"), 0.35 * confidence)
            for metric in self._leanstral_sequence(candidate.get("target_metrics")):
                bump_hint(metric, 0.08 * confidence)
            for premise_hint in self._leanstral_sequence(candidate.get("premise_hints")):
                hint_text = str(premise_hint).lower()
                if "exception" in hint_text or "deontic" in hint_text:
                    bump("deontic.ir", 0.12 * confidence)
                if "temporal" in hint_text or "event" in hint_text:
                    bump("TDFOL.prover", 0.10 * confidence)
                if "kg" in hint_text or "graph" in hint_text:
                    bump("knowledge_graphs.neo4j_compat", 0.10 * confidence)
            if candidate.get("proof_obligation_id") or candidate.get("proof_obligation_ids"):
                bump("TDFOL.prover", 0.10 * confidence)
                bump("external_provers.router", 0.06 * confidence)

        return _normalized_distribution(scores)

    def _leanstral_sequence(self, value: Any) -> List[Any]:
        if value is None:
            return []
        if isinstance(value, Mapping):
            return [value]
        if isinstance(value, Sequence) and not isinstance(
            value,
            (bytes, bytearray, str),
        ):
            return list(value)
        if isinstance(value, str):
            return [item.strip() for item in value.split(",") if item.strip()]
        return [value]

    def _leanstral_guidance_feature_keys(
        self,
        item: Mapping[str, Any],
        *,
        feature_bus: Optional[TrustedHammerLeanstralFeatureBus] = None,
    ) -> List[str]:
        bus = feature_bus or build_trusted_hammer_leanstral_feature_bus(
            item,
            require_trusted=False,
        )
        keys: List[str] = list(bus.feature_keys)

        # Keep the two v1 identifier aliases needed to read existing optimizer
        # state.  They are strictly capped identifier atoms, never source text.
        obligation_id = _trusted_feature_atom(item.get("obligation_id"), max_tokens=8)
        if obligation_id:
            keys.append(f"hammer:obligation:{obligation_id}")
        premise_families = bus.feature_families.get("premise_family", ())
        for premise in tuple(premise_families)[:8]:
            atom = _trusted_feature_atom(premise, max_tokens=8)
            if atom:
                keys.append(f"hammer:selected-premise:{atom}")
        return _unique_preserve_order(keys)[:48]

    def _nudge_legal_ir_view_logits_toward_distribution(
        self,
        sample: LegalSample,
        target_distribution: Mapping[str, float],
        *,
        learning_rate: float,
        update_sample_memory: bool = False,
    ) -> bool:
        normalized_target = _normalized_distribution(
            {
                str(view): _float_or_zero(weight)
                for view, weight in dict(target_distribution or {}).items()
                if _float_or_zero(weight) > 0.0
            }
        )
        if not normalized_target:
            return False
        cache_key = sample.sample_id
        had_previous = cache_key in self._legal_ir_view_target_cache
        previous = self._legal_ir_view_target_cache.get(cache_key)
        self._legal_ir_view_target_cache[cache_key] = dict(normalized_target)
        try:
            return self._nudge_legal_ir_view_logits(
                sample,
                learning_rate=learning_rate,
                update_sample_memory=update_sample_memory,
            )
        finally:
            if had_previous and previous is not None:
                self._legal_ir_view_target_cache[cache_key] = previous
            else:
                self._legal_ir_view_target_cache.pop(cache_key, None)

    def _nudge_legal_ir_view_global_logits_toward_distribution(
        self,
        target_distribution: Mapping[str, float],
        *,
        learning_rate: float,
    ) -> bool:
        normalized_target = _normalized_distribution(
            {
                str(view): _float_or_zero(weight)
                for view, weight in dict(target_distribution or {}).items()
                if _float_or_zero(weight) > 0.0
            }
        )
        if not normalized_target:
            return False
        step = _clamp_learning_rate(learning_rate)
        families = _unique_preserve_order(
            list(normalized_target.keys()) + list(self._legal_ir_view_family_candidates())
        )
        predicted = _softmax(
            {
                family: self.state.legal_ir_view_logits.get(family, 0.0)
                for family in families
            }
        )
        for family in families:
            gradient = float(normalized_target.get(family, 0.0)) - float(
                predicted.get(family, 0.0)
            )
            self.state.legal_ir_view_logits[family] = (
                self.state.legal_ir_view_logits.get(family, 0.0)
                + (step * gradient)
            )
        self._invalidate_legal_ir_view_family_candidates()
        return True

    def _nudge_leanstral_guidance_feature_logits(
        self,
        feature_keys: Sequence[str],
        target_distribution: Mapping[str, float],
        *,
        learning_rate: float,
    ) -> int:
        features = _unique_preserve_order(str(feature) for feature in feature_keys)[:48]
        normalized_target = _normalized_distribution(
            {
                str(view): _float_or_zero(weight)
                for view, weight in dict(target_distribution or {}).items()
                if _float_or_zero(weight) > 0.0
            }
        )
        if not features or not normalized_target:
            return 0
        step = _clamp_learning_rate(learning_rate) * 0.35 / math.sqrt(len(features))
        families = _unique_preserve_order(
            list(normalized_target.keys()) + list(self._legal_ir_view_family_candidates())
        )
        updated = 0
        for feature in features:
            logits = self.state.feature_legal_ir_view_logits.setdefault(feature, {})
            predicted = _softmax(
                {family: float(logits.get(family, 0.0)) for family in families}
            )
            for family in families:
                gradient = float(normalized_target.get(family, 0.0)) - float(
                    predicted.get(family, 0.0)
                )
                logits[family] = logits.get(family, 0.0) + (step * gradient)
            updated += 1
        if updated:
            self._invalidate_legal_ir_view_family_candidates()
        return updated

    def apply_todos(
        self,
        todos: Iterable[object],
        samples_by_id: Mapping[str, LegalSample],
        *,
        learning_rate: float = 0.35,
    ) -> List[Dict[str, Any]]:
        """Apply a batch of claimed TODOs as deterministic optimizer updates."""
        return [
            self.apply_todo(todo, samples_by_id, learning_rate=learning_rate)
            for todo in todos
        ]

    def apply_todo(
        self,
        todo: object,
        samples_by_id: Mapping[str, LegalSample],
        *,
        learning_rate: float = 0.35,
    ) -> Dict[str, Any]:
        """Apply one TODO and return a compact update report."""
        raw_action = str(getattr(todo, "action", ""))
        metadata = getattr(todo, "metadata", {})
        if not isinstance(metadata, Mapping):
            metadata = {}

        def metadata_payloads() -> List[Mapping[str, Any]]:
            payloads: List[Mapping[str, Any]] = [metadata]
            for key in ("bundle", "semantic_bundle_key", "evidence"):
                value = metadata.get(key)
                if isinstance(value, Mapping):
                    payloads.append(value)
                elif isinstance(value, str) and value.strip().startswith("{"):
                    try:
                        parsed = json.loads(value)
                    except (TypeError, ValueError):
                        continue
                    if isinstance(parsed, Mapping):
                        payloads.append(parsed)
            return payloads

        action = raw_action
        if action == "rescue_failed_program_synthesis_validation":
            for payload in metadata_payloads():
                rescued_action = str(payload.get("original_action") or "").strip()
                if rescued_action:
                    action = rescued_action
                    break
        loss_name = str(getattr(todo, "loss_name", ""))
        if not loss_name:
            target_metrics: List[str] = []
            for payload in metadata_payloads():
                raw_metrics = payload.get("target_metrics")
                if isinstance(raw_metrics, str):
                    target_metrics.extend(
                        metric.strip()
                        for metric in raw_metrics.split(",")
                        if metric.strip()
                    )
                elif isinstance(raw_metrics, Sequence) and not isinstance(
                    raw_metrics,
                    (bytes, bytearray, str),
                ):
                    target_metrics.extend(str(metric) for metric in raw_metrics)
            for metric in target_metrics:
                normalized_metric = str(metric).strip()
                if normalized_metric in {
                    "cosine_loss",
                    "cross_entropy_loss",
                    "legal_ir_view_cross_entropy_loss",
                    "reconstruction_loss",
                }:
                    loss_name = normalized_metric
                    break
        todo_id = str(getattr(todo, "todo_id", ""))
        sample_ids = [str(value) for value in getattr(todo, "sample_ids", [])]
        changed: List[str] = []

        trainable = (
            action
            in {
                "improve_encoder_decoder_reconstruction",
                "improve_legal_ir_view_distribution",
                "improve_modal_family_classifier",
            }
            or loss_name
            in {
                "cosine_loss",
                "cross_entropy_loss",
                "legal_ir_view_cross_entropy_loss",
                "reconstruction_loss",
            }
        )
        if not trainable:
            return {
                "action": raw_action,
                "changed": [],
                "reason": "todo targets deterministic program synthesis, not autoencoder SGD",
                "sample_ids": sample_ids,
                "skipped": True,
                "todo_id": todo_id,
            }

        for sample_id in sample_ids:
            sample = samples_by_id.get(sample_id)
            if sample is None:
                continue
            if action == "improve_modal_family_classifier" or loss_name == "cross_entropy_loss":
                self._nudge_family_logits(sample, learning_rate=learning_rate)
                changed.append("family_logits")
            if (
                action == "improve_legal_ir_view_distribution"
                or loss_name == "legal_ir_view_cross_entropy_loss"
            ):
                if self._nudge_legal_ir_view_logits(sample, learning_rate=learning_rate):
                    changed.append("legal_ir_view_logits")
            if (
                action == "improve_encoder_decoder_reconstruction"
                or loss_name in {"cosine_loss", "reconstruction_loss"}
            ):
                self._nudge_decoded_embedding(sample, learning_rate=learning_rate)
                changed.append("decoded_embedding")

        if todo_id and todo_id not in self.state.applied_todo_ids:
            self.state.applied_todo_ids.append(todo_id)
        report = {
            "action": raw_action,
            "changed": sorted(set(changed)),
            "sample_ids": sample_ids,
            "todo_id": todo_id,
        }
        if action != raw_action:
            report["effective_action"] = action
        return report

    def train_generalizable_projection(
        self,
        samples: Sequence[LegalSample],
        *,
        validation_samples: Optional[Sequence[LegalSample]] = None,
        legal_ir_bridge_names: Sequence[str] = (),
        legal_ir_evaluate_provers: Optional[bool] = None,
        legal_ir_bridge_max_samples: Optional[int] = None,
        legal_ir_bridge_max_sample_text_chars: Optional[int] = None,
        legal_ir_targets: Optional[Mapping[str, Any] | Sequence[Any]] = None,
        legal_ir_parallel_workers: Optional[int] = None,
        epochs: int = 3,
        learning_rate: float = 0.35,
        l2_regularization: float = 0.0,
        max_cosine_regression: float = 0.01,
        max_reconstruction_regression: float = 0.02,
        max_cross_entropy_regression: float = 0.0,
        max_legal_ir_loss_regression: float = 0.02,
        objective_cross_entropy_weight: float = 1.0,
        objective_reconstruction_weight: float = 1.0,
        objective_cosine_gap_weight: float = 1.5,
        objective_legal_ir_weight: float = 1.0,
        hard_example_fraction: float = 1.0,
        max_seconds: Optional[float] = None,
        max_line_search_attempts: Optional[int] = None,
        projection_deadband_mode: str = "off",
        projection_max_ce_deadband: float = 0.0,
        projection_hard_guardrail_metrics: Sequence[str] | str | None = (
            PROJECTION_DEADBAND_DEFAULT_HARD_GUARDRAILS
        ),
        projection_prescreen_mode: str = "off",
        projection_prescreen_top_k: int = 3,
        projection_periodic_full_search_every_n_cycles: int = 0,
        projection_max_update_families: Optional[int] = None,
        projection_cycle: Optional[int] = None,
        precomputed_holdout_evaluation: Optional[AutoencoderEvaluation] = None,
        precomputed_training_evaluation: Optional[AutoencoderEvaluation] = None,
        progress_callback: Optional[Callable[[Mapping[str, Any]], None]] = None,
        projection_profiler: Optional[ProjectionProfiler] = None,
        projection_update_backend: str = "auto",
    ) -> Dict[str, Any]:
        """Train feature-level weights with rollback on holdout regression.

        This guarded path keeps sample-memory disabled for updates, so any
        accepted improvement must come from reusable feature embeddings/logits.
        """
        started_at = time.time()
        self._cuda_residency_reports = []
        sample_list = list(samples)
        validation_list = list(validation_samples or [])
        target_samples = validation_list or sample_list

        def elapsed_seconds() -> float:
            return max(0.0, time.time() - started_at)

        def timed_out() -> bool:
            return (
                max_seconds is not None
                and float(max_seconds) > 0.0
                and elapsed_seconds() >= float(max_seconds)
            )

        def emit_progress(stage: str, **payload: Any) -> None:
            if progress_callback is None:
                return
            progress: Dict[str, Any] = {
                "elapsed_seconds": round(elapsed_seconds(), 3),
                "stage": stage,
            }
            progress.update(payload)
            try:
                progress_callback(progress)
            except Exception:
                pass

        profiler = projection_profiler
        if (
            profiler is not None
            and profiler.cuda_synchronizer is None
            and self._torch is not None
            and self.compute_backend == "torch_cuda"
            and hasattr(self._torch, "cuda")
            and hasattr(self._torch.cuda, "synchronize")
        ):
            profiler.cuda_synchronizer = self._torch.cuda.synchronize

        def profile_phase(
            cost_family: str,
            *,
            stage: str,
            legal_family: str = "",
            feature_head: str = "",
            metadata: Optional[Mapping[str, Any]] = None,
        ):
            if profiler is None:
                return nullcontext()
            return profiler.phase(
                cost_family,
                stage=stage,
                legal_family=legal_family,
                feature_head=feature_head,
                metadata=metadata,
            )

        normalized_update_backend = str(projection_update_backend or "auto").strip().lower()
        if normalized_update_backend in {"", "auto"}:
            normalized_update_backend = (
                "cuda_resident"
                if self.compute_backend == "torch_cuda"
                else "native"
            )
        if normalized_update_backend not in {
            "cuda_resident",
            "native",
            "legacy",
            "legacy_device",
            "python_sparse_batch",
        }:
            raise ValueError(
                "projection_update_backend must be auto, cuda_resident, native, "
                "legacy_device, or python_sparse_batch"
            )

        bridge_names = tuple(
            str(name).strip()
            for name in legal_ir_bridge_names
            if str(name).strip()
        )
        bridge_sample_cap = (
            None
            if legal_ir_bridge_max_samples is None
            else max(0, int(legal_ir_bridge_max_samples))
        )
        bridge_text_cap = (
            None
            if legal_ir_bridge_max_sample_text_chars is None
            else max(0, int(legal_ir_bridge_max_sample_text_chars))
        )
        evaluation_kwargs: Dict[str, Any] = {
            "legal_ir_bridge_names": legal_ir_bridge_names,
            "legal_ir_evaluate_provers": legal_ir_evaluate_provers,
            "legal_ir_targets": legal_ir_targets,
            "legal_ir_parallel_workers": legal_ir_parallel_workers,
            "use_sample_memory": False,
        }
        base_evaluation_kwargs: Dict[str, Any] = {
            **evaluation_kwargs,
            "legal_ir_bridge_names": (),
            "legal_ir_targets": None,
        }

        def projection_bridge_samples(rows: Sequence[LegalSample]) -> List[LegalSample]:
            row_list = list(rows)
            if not bridge_names:
                return []
            if bridge_sample_cap is None:
                selected = row_list
            elif bridge_sample_cap <= 0:
                return []
            else:
                selected = row_list[:bridge_sample_cap]
            return _bounded_legal_ir_metric_samples(
                selected,
                max_sample_text_chars=bridge_text_cap,
            )

        def evaluate_projection_rows(
            rows: Sequence[LegalSample],
            *,
            stage: str,
        ) -> AutoencoderEvaluation:
            row_list = list(rows)
            if profiler is not None and self.compute_backend.startswith("torch"):
                profiler.transfer(
                    stage=f"{stage}:metric_input",
                    legal_family="aggregate",
                    count=max(1, len(row_list)),
                    bytes_moved=sum(
                        len(getattr(sample, "embedding_vector", ()) or ()) * 8
                        for sample in row_list
                    ),
                )
            metric_cost_family = (
                "kernel" if self.compute_backend.startswith("torch") else "python_loop"
            )
            if bridge_sample_cap is None and not bridge_text_cap:
                with profile_phase(
                    metric_cost_family,
                    stage=stage,
                    legal_family="aggregate",
                    metadata={"sample_count": len(row_list)},
                ):
                    return self.evaluate(row_list, **evaluation_kwargs)
            bridge_rows = projection_bridge_samples(row_list)
            if not bridge_rows:
                with profile_phase(
                    metric_cost_family,
                    stage=stage,
                    legal_family="aggregate",
                    metadata={"sample_count": len(row_list)},
                ):
                    return self.evaluate(row_list, **base_evaluation_kwargs)
            emit_progress(
                f"{stage}_bridge_evaluation",
                bridge_sample_count=len(bridge_rows),
                bridge_sample_ids=[
                    str(getattr(sample, "sample_id", "") or "")
                    for sample in bridge_rows
                ],
                bridge_text_cap=bridge_text_cap,
                full_sample_count=len(row_list),
                sample_count=len(row_list),
            )
            with profile_phase(
                metric_cost_family,
                stage=f"{stage}:bridge",
                legal_family="aggregate",
                metadata={"sample_count": len(bridge_rows)},
            ):
                bridge = self.evaluate(bridge_rows, **evaluation_kwargs)
            self.alias_cached_legal_ir_targets(row_list, bridge_rows)
            with profile_phase(
                metric_cost_family,
                stage=f"{stage}:base",
                legal_family="aggregate",
                metadata={"sample_count": len(row_list)},
            ):
                base = self.evaluate(row_list, **base_evaluation_kwargs)
            return replace(
                base,
                legal_ir_target_count=bridge.legal_ir_target_count,
                legal_ir_losses=dict(bridge.legal_ir_losses),
                legal_ir_predicted_view_distribution=dict(
                    bridge.legal_ir_predicted_view_distribution
                ),
                legal_ir_target_hashes=dict(bridge.legal_ir_target_hashes),
                legal_ir_view_distribution=dict(bridge.legal_ir_view_distribution),
            )

        def rollback_projection_transaction(
            transaction: ModalAutoencoderStateTransaction,
        ) -> ModalAutoencoderStatePatch:
            patch = transaction.rollback()
            self._invalidate_state_dependent_evaluator_caches()
            return patch

        def commit_projection_patch(
            patch: ModalAutoencoderStatePatch,
            *,
            label: str,
        ) -> None:
            transaction = self.state.transaction(label=label).begin()
            try:
                patch.apply(transaction)
                transaction.commit()
            except BaseException:
                if transaction.active:
                    rollback_projection_transaction(transaction)
                raise
            self._invalidate_state_dependent_evaluator_caches()

        emit_progress(
            "before_holdout_evaluation",
            sample_count=len(sample_list),
            validation_sample_count=len(target_samples),
        )
        if precomputed_holdout_evaluation is None:
            before = evaluate_projection_rows(
                target_samples,
                stage="before_holdout_evaluation",
            )
        else:
            before = precomputed_holdout_evaluation
            emit_progress(
                "before_holdout_evaluation_reused",
                sample_count=len(target_samples),
            )
        if sample_list and validation_list:
            # Prime LegalIR target caches for training samples before feature-level
            # nudges.  Validation-only evaluation intentionally does not touch
            # training sample cache entries.
            emit_progress(
                "training_cache_prime",
                sample_count=len(sample_list),
                validation_sample_count=len(target_samples),
            )
            if precomputed_training_evaluation is None:
                evaluate_projection_rows(
                    sample_list,
                    stage="training_cache_prime",
                )
            else:
                emit_progress(
                    "training_cache_prime_reused",
                    sample_count=len(sample_list),
                )
        emit_progress("initial_state_snapshot")
        best = before
        accepted_epochs = 0
        epoch_reports: List[Dict[str, Any]] = []
        projection_stopped_reason: Optional[str] = None
        objective_weights = {
            "cross_entropy": max(0.0, float(objective_cross_entropy_weight)),
            "reconstruction": max(0.0, float(objective_reconstruction_weight)),
            "cosine_gap": max(0.0, float(objective_cosine_gap_weight)),
            "legal_ir": max(0.0, float(objective_legal_ir_weight)),
        }
        hard_fraction = max(0.0, min(1.0, float(hard_example_fraction)))
        deadband_mode = _projection_deadband_mode(projection_deadband_mode)
        deadband_ce = max(0.0, float(projection_max_ce_deadband or 0.0))
        deadband_guardrails = _projection_guardrail_names(
            projection_hard_guardrail_metrics
        )
        projection_deadband_config = {
            "hard_guardrail_metrics": list(deadband_guardrails),
            "max_ce_deadband": deadband_ce,
            "mode": deadband_mode,
        }
        prescreen_mode = _projection_prescreen_mode(projection_prescreen_mode)
        prescreen_top_k = max(0, int(projection_prescreen_top_k or 0))
        prescreen_full_search_every = max(
            0,
            int(projection_periodic_full_search_every_n_cycles or 0),
        )
        prescreen_periodic_full_search = bool(
            prescreen_mode == "enforce"
            and prescreen_full_search_every > 0
            and projection_cycle is not None
            and int(projection_cycle) > 0
            and int(projection_cycle) % prescreen_full_search_every == 0
        )
        effective_prescreen_mode = "shadow" if prescreen_periodic_full_search else prescreen_mode
        projection_prescreen_config = {
            "effective_mode": effective_prescreen_mode,
            "holdout_evaluation_limit": (
                prescreen_top_k
                if effective_prescreen_mode == "enforce" and prescreen_top_k > 0
                else None
            ),
            "mode": prescreen_mode,
            "periodic_full_search": prescreen_periodic_full_search,
            "periodic_full_search_every_n_cycles": prescreen_full_search_every,
            "projection_cycle": int(projection_cycle) if projection_cycle is not None else None,
            "top_k": prescreen_top_k,
        }

        candidate_updates = (
            ("legal_ir_view_global_logits", ("legal_ir_view_global_logits",)),
            ("legal_ir_view_logits", ("legal_ir_view_logits",)),
            ("family_logits", ("family_logits",)),
            ("decoded_embedding", ("decoded_embedding",)),
            (
                "combined",
                ("family_logits", "decoded_embedding", "legal_ir_view_logits"),
            ),
        )
        effective_max_update_families = max(
            0,
            int(projection_max_update_families or 0),
        )
        if effective_max_update_families > 0:
            candidate_updates = candidate_updates[:effective_max_update_families]
        projection_update_family_config = {
            "candidate_update_family_count": len(candidate_updates),
            "max_update_families": effective_max_update_families or None,
        }
        head_learning_rate_scales = {
            "family_logits": 1.0,
            "decoded_embedding": 0.5,
            "legal_ir_view_global_logits": 0.5,
            "legal_ir_view_logits": 0.5,
            "combined": 0.35,
        }
        line_search_multipliers = (1.0, 0.5, 0.25, 0.125, 0.0625, 0.03125)
        line_search_refinement_multipliers = (
            0.015625,
            0.0078125,
            0.00390625,
            0.001953125,
        )
        state_entry_count = self.state.generalizable_entry_count()
        effective_max_line_search_attempts = max(
            0,
            int(max_line_search_attempts or 0),
        )
        line_search_attempt_policy = "explicit"
        if effective_max_line_search_attempts <= 0 and state_entry_count >= 100_000:
            effective_max_line_search_attempts = _projection_auto_line_search_attempts(
                max_attempts=len(line_search_multipliers),
            )
            line_search_attempt_policy = "auto_large_state_cap"
        elif effective_max_line_search_attempts <= 0:
            line_search_attempt_policy = "unbounded_small_state"

        for epoch in range(1, max(0, int(epochs)) + 1):
            if timed_out():
                projection_stopped_reason = "projection_timeout"
                break
            emit_progress(
                "epoch_snapshot",
                epoch=epoch,
                state_entry_count=state_entry_count,
            )
            candidate_reports: List[Dict[str, Any]] = []
            selected: Optional[
                tuple[
                    float,
                    AutoencoderEvaluation,
                    ModalAutoencoderStatePatch,
                    str,
                ]
            ] = None
            prescreen_holdout_evaluation_count = 0
            prescreen_holdout_evaluation_limit = (
                prescreen_top_k
                if effective_prescreen_mode == "enforce" and prescreen_top_k > 0
                else None
            )
            emit_progress(
                "hard_example_selection",
                epoch=epoch,
                hard_example_fraction=hard_fraction,
            )
            with profile_phase(
                "python_loop",
                stage="hard_example_selection",
                legal_family="aggregate",
                metadata={"sample_count": len(sample_list)},
            ):
                update_samples = self._select_hard_examples_for_projection(
                    sample_list,
                    hard_example_fraction=hard_fraction,
                    objective_weights=objective_weights,
                )
            prescreen_before: Optional[AutoencoderEvaluation] = None
            if effective_prescreen_mode != "off" and update_samples:
                emit_progress(
                    "projection_prescreen_baseline",
                    epoch=epoch,
                    sample_count=len(update_samples),
                    top_k=prescreen_top_k,
                )
                with profile_phase(
                    (
                        "kernel"
                        if self.compute_backend.startswith("torch")
                        else "python_loop"
                    ),
                    stage="projection_prescreen_baseline",
                    legal_family="aggregate",
                    metadata={"sample_count": len(update_samples)},
                ):
                    prescreen_before = self.evaluate(
                        update_samples,
                        **base_evaluation_kwargs,
                    )

            for update_name, update_targets in candidate_updates:
                if timed_out():
                    projection_stopped_reason = "projection_timeout"
                    break
                if (
                    prescreen_holdout_evaluation_limit is not None
                    and prescreen_holdout_evaluation_count
                    >= prescreen_holdout_evaluation_limit
                ):
                    emit_progress(
                        "projection_prescreen_holdout_budget_exhausted",
                        epoch=epoch,
                        holdout_evaluation_count=(
                            prescreen_holdout_evaluation_count
                        ),
                        holdout_evaluation_limit=(
                            prescreen_holdout_evaluation_limit
                        ),
                        next_update=update_name,
                    )
                    break
                head_scale = head_learning_rate_scales.get(update_name, 1.0)
                attempt_reports: List[Dict[str, Any]] = []
                best_attempt: Optional[
                    tuple[
                        float,
                        Dict[str, Any],
                        AutoencoderEvaluation,
                        ModalAutoencoderStatePatch,
                    ]
                ] = None
                best_improved_attempt: Optional[
                    tuple[
                        float,
                        Dict[str, Any],
                        AutoencoderEvaluation,
                        ModalAutoencoderStatePatch,
                    ]
                ] = None
                attempt_tuples: List[
                    tuple[
                        float,
                        Dict[str, Any],
                        AutoencoderEvaluation,
                        ModalAutoencoderStatePatch,
                    ]
                ] = []
                multipliers_to_try = list(line_search_multipliers)
                refinement_added = False

                def finalize_attempt_report(
                    *,
                    attempt_report: Dict[str, Any],
                    candidate_state: ModalAutoencoderStatePatch,
                ) -> tuple[
                    float,
                    Dict[str, Any],
                    AutoencoderEvaluation,
                    ModalAutoencoderStatePatch,
                ]:
                    evaluation_transaction = self.state.transaction(
                        label=(
                            f"projection-evaluate:{epoch}:{update_name}:"
                            f"{attempt_report.get('line_search_attempt', 0)}"
                        )
                    ).begin()
                    try:
                        candidate_state.apply(evaluation_transaction)
                        emit_progress(
                            "line_search_evaluation",
                            epoch=epoch,
                            line_search_attempt=int(
                                attempt_report.get("line_search_attempt", 0) or 0
                            ),
                            update=update_name,
                        )
                        after = evaluate_projection_rows(
                            target_samples,
                            stage="line_search_evaluation",
                        )
                    finally:
                        if evaluation_transaction.active:
                            rollback_projection_transaction(evaluation_transaction)
                    regressions = _evaluation_regressions_for_training(
                        best,
                        after,
                        max_cosine_regression=max_cosine_regression,
                        max_reconstruction_regression=max_reconstruction_regression,
                        max_cross_entropy_regression=max_cross_entropy_regression,
                        max_legal_ir_loss_regression=max_legal_ir_loss_regression,
                    )
                    objective_delta = (
                        _evaluation_objective_for_training(
                            best,
                            **objective_weights,
                        )
                        - _evaluation_objective_for_training(
                            after,
                            **objective_weights,
                        )
                    )
                    strict_improved = bool(
                        not regressions and objective_delta > 0.0
                    )
                    deadband_decision = _projection_deadband_decision(
                        regressions,
                        objective_delta=objective_delta,
                        mode=deadband_mode,
                        max_ce_deadband=deadband_ce,
                        hard_guardrail_metrics=deadband_guardrails,
                    )
                    improved = bool(
                        strict_improved
                        or deadband_decision.get("enforced_accepted", False)
                    )
                    attempt_report.update(
                        {
                            "accepted": improved,
                            "acceptance_source": (
                                "strict"
                                if strict_improved
                                else "deadband_enforced"
                                if deadband_decision.get("enforced_accepted", False)
                                else "rejected"
                            ),
                            "cross_entropy_delta": best.cross_entropy_loss
                            - after.cross_entropy_loss,
                            "cross_entropy_excess_delta": (
                                best.cross_entropy_excess_loss
                                - after.cross_entropy_excess_loss
                            ),
                            "cosine_similarity_delta": (
                                after.embedding_cosine_similarity
                                - best.embedding_cosine_similarity
                            ),
                            "holdout_evaluated": True,
                            "evaluated_objective": {
                                "after": _selected_objective_metric_values(
                                    after,
                                    objective_weights,
                                ),
                                "before": _selected_objective_metric_values(
                                    best,
                                    objective_weights,
                                ),
                                "selected_metric_names": _selected_objective_metric_names(
                                    after,
                                    objective_weights,
                                ),
                            },
                            "legal_ir_view_cross_entropy_delta": (
                                float(
                                    best.legal_ir_losses.get(
                                        "legal_ir_view_cross_entropy_loss",
                                        0.0,
                                    )
                                )
                                - float(
                                    after.legal_ir_losses.get(
                                        "legal_ir_view_cross_entropy_loss",
                                        0.0,
                                    )
                                )
                            ),
                            "legal_ir_view_cross_entropy_excess_delta": (
                                float(
                                    best.legal_ir_losses.get(
                                        "legal_ir_view_cross_entropy_excess_loss",
                                        0.0,
                                    )
                                )
                                - float(
                                    after.legal_ir_losses.get(
                                        "legal_ir_view_cross_entropy_excess_loss",
                                        0.0,
                                    )
                                )
                            ),
                            "legal_ir_view_family_cross_entropy_delta": (
                                float(
                                    best.legal_ir_losses.get(
                                        "legal_ir_view_family_cross_entropy_loss",
                                        0.0,
                                    )
                                )
                                - float(
                                    after.legal_ir_losses.get(
                                        "legal_ir_view_family_cross_entropy_loss",
                                        0.0,
                                    )
                                )
                            ),
                            "legal_ir_view_family_cross_entropy_excess_delta": (
                                float(
                                    best.legal_ir_losses.get(
                                        "legal_ir_view_family_cross_entropy_excess_loss",
                                        0.0,
                                    )
                                )
                                - float(
                                    after.legal_ir_losses.get(
                                        "legal_ir_view_family_cross_entropy_excess_loss",
                                        0.0,
                                    )
                                )
                            ),
                            "legal_ir_view_family_cosine_gap_delta": (
                                float(
                                    best.legal_ir_losses.get(
                                        "legal_ir_view_family_cosine_gap_loss",
                                        0.0,
                                    )
                                )
                                - float(
                                    after.legal_ir_losses.get(
                                        "legal_ir_view_family_cosine_gap_loss",
                                        0.0,
                                    )
                                )
                            ),
                            "objective_delta": objective_delta,
                            "pareto_regressions": regressions,
                            "projection_deadband": deadband_decision,
                            "reconstruction_delta": best.reconstruction_loss
                            - after.reconstruction_loss,
                            "strict_accepted": strict_improved,
                        }
                    )
                    return (
                        objective_delta,
                        attempt_report,
                        after,
                        candidate_state,
                    )
                for line_search_multiplier in multipliers_to_try:
                    if timed_out():
                        projection_stopped_reason = "projection_timeout"
                        break
                    if (
                        effective_max_line_search_attempts > 0
                        and len(attempt_reports) >= effective_max_line_search_attempts
                    ):
                        break
                    is_refinement_attempt = (
                        float(line_search_multiplier)
                        in line_search_refinement_multipliers
                    )
                    effective_learning_rate = (
                        learning_rate * head_scale * float(line_search_multiplier)
                    )
                    emit_progress(
                        "line_search_attempt",
                        effective_learning_rate=effective_learning_rate,
                        epoch=epoch,
                        hard_example_count=len(update_samples),
                        line_search_attempt=len(attempt_reports) + 1,
                        line_search_multiplier=float(line_search_multiplier),
                        state_entry_count=state_entry_count,
                        update=update_name,
                    )
                    attempt_transaction = self.state.transaction(
                        label=(
                            f"projection-attempt:{epoch}:{update_name}:"
                            f"{len(attempt_reports) + 1}"
                        )
                    ).begin()
                    try:
                        update_norm_report = self._apply_projection_update_batch(
                            update_samples,
                            update_targets=update_targets,
                            learning_rate=effective_learning_rate,
                            l2_regularization=l2_regularization,
                            profiler=profiler,
                            update_backend=normalized_update_backend,
                        )
                        prescreen_report: Dict[str, Any] = {
                            "effective_mode": effective_prescreen_mode,
                            "enabled": effective_prescreen_mode != "off",
                            "mode": prescreen_mode,
                            "selected_for_holdout": True,
                            "top_k": prescreen_top_k,
                        }
                        if prescreen_before is not None:
                            emit_progress(
                                "projection_prescreen_evaluation",
                                effective_learning_rate=effective_learning_rate,
                                epoch=epoch,
                                line_search_attempt=len(attempt_reports) + 1,
                                line_search_multiplier=float(line_search_multiplier),
                                sample_count=len(update_samples),
                                top_k=prescreen_top_k,
                                update=update_name,
                            )
                            with profile_phase(
                                (
                                    "kernel"
                                    if self.compute_backend.startswith("torch")
                                    else "python_loop"
                                ),
                                stage="projection_prescreen_evaluation",
                                legal_family="aggregate",
                                metadata={"sample_count": len(update_samples)},
                            ):
                                prescreen_after = self.evaluate(
                                    update_samples,
                                    **base_evaluation_kwargs,
                                )
                            before_prescreen_objective = (
                                _evaluation_objective_for_training(
                                    prescreen_before,
                                    **objective_weights,
                                )
                            )
                            after_prescreen_objective = (
                                _evaluation_objective_for_training(
                                    prescreen_after,
                                    **objective_weights,
                                )
                            )
                            prescreen_report.update(
                                {
                                    "after_objective": round(
                                        after_prescreen_objective,
                                        12,
                                    ),
                                    "before_objective": round(
                                        before_prescreen_objective,
                                        12,
                                    ),
                                    "objective_delta": round(
                                        before_prescreen_objective
                                        - after_prescreen_objective,
                                        12,
                                    ),
                                    "sample_count": len(update_samples),
                                }
                            )
                        candidate_state = attempt_transaction.capture_patch()
                    finally:
                        if attempt_transaction.active:
                            rollback_projection_transaction(attempt_transaction)
                    line_search_attempt_index = len(attempt_reports) + 1
                    defer_holdout_evaluation = bool(
                        effective_prescreen_mode == "enforce"
                        and prescreen_before is not None
                    )
                    prescreen_objective_delta = _float_or_zero(
                        prescreen_report.get("objective_delta")
                    )
                    attempt_report = {
                        "accepted": False,
                        "acceptance_source": (
                            "prescreen_deferred"
                            if defer_holdout_evaluation
                            else "pending"
                        ),
                        "effective_learning_rate": effective_learning_rate,
                        "hard_example_count": len(update_samples),
                        "hard_example_fraction": hard_fraction,
                        "head_learning_rate_scale": head_scale,
                        "holdout_evaluated": False,
                        "line_search_attempt": line_search_attempt_index,
                        "line_search_multiplier": float(line_search_multiplier),
                        "line_search_refinement": bool(is_refinement_attempt),
                        "objective_delta": prescreen_objective_delta,
                        "pareto_regressions": {},
                        "projection_deadband": {},
                        "projection_prescreen": prescreen_report,
                        "strict_accepted": False,
                        "gradient_norms_by_family": update_norm_report[
                            "gradient_norms_by_family"
                        ],
                        "gradient_norms_by_head": update_norm_report[
                            "gradient_norms_by_head"
                        ],
                        "head_family_gradient_norms": update_norm_report[
                            "head_family_gradient_norms"
                        ],
                        "head_family_update_norms": update_norm_report[
                            "head_family_update_norms"
                        ],
                        "trainable_legal_ir_head_norms": update_norm_report,
                        "update": update_name,
                        "update_norms_by_family": update_norm_report[
                            "update_norms_by_family"
                        ],
                        "update_norms_by_head": update_norm_report[
                            "update_norms_by_head"
                        ],
                    }
                    if defer_holdout_evaluation:
                        attempt_reports.append(attempt_report)
                        attempt_tuples.append(
                            (
                                prescreen_objective_delta,
                                attempt_report,
                                best,
                                candidate_state,
                            )
                        )
                        continue
                    attempt_tuple = finalize_attempt_report(
                        attempt_report=attempt_report,
                        candidate_state=candidate_state,
                    )
                    objective_delta, attempt_report, after, _candidate_state = (
                        attempt_tuple
                    )
                    attempt_reports.append(attempt_report)
                    attempt_tuples.append(attempt_tuple)
                    if best_attempt is None or objective_delta > best_attempt[0]:
                        best_attempt = attempt_tuple
                    if attempt_report.get("accepted") and (
                        best_improved_attempt is None
                        or objective_delta > best_improved_attempt[0]
                    ):
                        best_improved_attempt = attempt_tuple
                    if (
                        not refinement_added
                        and best_improved_attempt is None
                        and len(attempt_reports) == len(line_search_multipliers)
                        and (
                            effective_max_line_search_attempts <= 0
                            or len(attempt_reports) < effective_max_line_search_attempts
                        )
                    ):
                        multipliers_to_try.extend(line_search_refinement_multipliers)
                        refinement_added = True
                if projection_stopped_reason and not attempt_tuples:
                    break
                _annotate_projection_prescreen_rankings(
                    attempt_reports,
                    top_k=prescreen_top_k,
                )
                if effective_prescreen_mode == "enforce":
                    selected_tuples = []
                    for attempt in attempt_tuples:
                        _score, attempt_report, after, candidate_state = attempt
                        prescreen = attempt_report.get("projection_prescreen", {})
                        selected_for_holdout = bool(
                            isinstance(prescreen, Mapping)
                            and prescreen.get("selected_for_holdout", True)
                        )
                        if not selected_for_holdout:
                            if not bool(attempt_report.get("holdout_evaluated", False)):
                                attempt_report["acceptance_source"] = (
                                    "prescreen_filtered"
                                )
                            continue
                        if bool(attempt_report.get("holdout_evaluated", False)):
                            selected_tuples.append(attempt)
                            continue
                        if (
                            prescreen_holdout_evaluation_limit is not None
                            and prescreen_holdout_evaluation_count
                            >= prescreen_holdout_evaluation_limit
                        ):
                            if isinstance(prescreen, MutableMapping):
                                prescreen["global_holdout_budget_filtered"] = True
                                prescreen["selected_for_holdout"] = False
                            attempt_report["acceptance_source"] = "prescreen_filtered"
                            continue
                        if timed_out():
                            projection_stopped_reason = "projection_timeout"
                            if isinstance(prescreen, MutableMapping):
                                prescreen["projection_timeout_filtered"] = True
                                prescreen["selected_for_holdout"] = False
                            attempt_report["acceptance_source"] = "projection_timeout"
                            continue
                        selected_tuples.append(
                            finalize_attempt_report(
                                attempt_report=attempt_report,
                                candidate_state=candidate_state,
                            )
                        )
                        prescreen_holdout_evaluation_count += 1
                    best_attempt = max(
                        selected_tuples,
                        key=lambda attempt: attempt[0],
                        default=None,
                    )
                    improved_tuples = [
                        attempt
                        for attempt in selected_tuples
                        if bool(attempt[1].get("accepted"))
                    ]
                    best_improved_attempt = max(
                        improved_tuples,
                        key=lambda attempt: attempt[0],
                        default=None,
                    )
                chosen = best_improved_attempt or best_attempt
                if chosen is None:
                    if attempt_tuples:
                        _score, candidate_report, _after, _candidate_state = max(
                            attempt_tuples,
                            key=lambda attempt: attempt[0],
                        )
                        candidate_reports.append(
                            {
                                **candidate_report,
                                "attempt_reports": attempt_reports,
                                "line_search_attempt_count": len(attempt_reports),
                                "line_search_refinement_attempt_count": sum(
                                    1
                                    for report in attempt_reports
                                    if report.get("line_search_refinement")
                                ),
                            }
                        )
                    continue
                objective_delta, candidate_report, after, candidate_state = chosen
                candidate_reports.append(
                    {
                        **candidate_report,
                        "attempt_reports": attempt_reports,
                        "line_search_attempt_count": len(attempt_reports),
                        "line_search_refinement_attempt_count": sum(
                            1
                            for report in attempt_reports
                            if report.get("line_search_refinement")
                        ),
                    }
                )
                if candidate_report["accepted"] and (
                    selected is None or objective_delta > selected[0]
                ):
                    selected = (
                        objective_delta,
                        after,
                        candidate_state,
                        update_name,
                    )

            if projection_stopped_reason:
                if selected is None:
                    epoch_reports.append(
                        {
                            "accepted": False,
                            "candidate_reports": candidate_reports,
                            "epoch": epoch,
                            "objective_delta": max(
                                (
                                    float(report.get("objective_delta", 0.0))
                                    for report in candidate_reports
                                ),
                                default=0.0,
                            ),
                            "selected_update": None,
                            "stopped_reason": projection_stopped_reason,
                        }
                    )
                    break
                objective_delta, after, selected_state, update_name = selected
                commit_projection_patch(
                    selected_state,
                    label=f"projection-commit:{epoch}:{update_name}",
                )
                best = after
                accepted_epochs += 1
                selected_report = next(
                    report
                    for report in candidate_reports
                    if report["update"] == update_name
                )
                epoch_reports.append(
                    {
                        **selected_report,
                        "accepted": True,
                        "candidate_reports": candidate_reports,
                        "epoch": epoch,
                        "objective_delta": objective_delta,
                        "selected_update": update_name,
                        "stopped_reason": projection_stopped_reason,
                    }
                )
                break
            if selected is None:
                epoch_reports.append(
                    {
                        "accepted": False,
                        "candidate_reports": candidate_reports,
                        "epoch": epoch,
                        "objective_delta": max(
                            (
                                float(report.get("objective_delta", 0.0))
                                for report in candidate_reports
                            ),
                            default=0.0,
                        ),
                        "selected_update": None,
                    }
                )
                break

            objective_delta, after, selected_state, update_name = selected
            commit_projection_patch(
                selected_state,
                label=f"projection-commit:{epoch}:{update_name}",
            )
            best = after
            accepted_epochs += 1
            selected_report = next(
                report
                for report in candidate_reports
                if report["update"] == update_name
            )
            epoch_reports.append(
                {
                    **selected_report,
                    "accepted": True,
                    "candidate_reports": candidate_reports,
                    "epoch": epoch,
                    "objective_delta": objective_delta,
                    "selected_update": update_name,
                }
            )

        projection_profile = profiler.summarize() if profiler is not None else {}
        cuda_residency = {
            "enabled": normalized_update_backend == "cuda_resident",
            "reports": list(self._cuda_residency_reports[-64:]),
            "schema_version": "modal-autoencoder-cuda-residency-v2",
        }
        emit_progress(
            "finished",
            accepted_epochs=accepted_epochs,
            stopped_reason=projection_stopped_reason,
        )
        return {
            "accepted_epochs": accepted_epochs,
            "after": best.to_dict(),
            "before": before.to_dict(),
            "compute_backend": self.compute_backend_metadata(),
            "candidate_update_order": [name for name, _targets in candidate_updates],
            "epoch_reports": epoch_reports,
            "evaluated_objective": {
                "after": _selected_objective_metric_values(best, objective_weights),
                "before": _selected_objective_metric_values(before, objective_weights),
                "selected_metric_names": _selected_objective_metric_names(
                    best,
                    objective_weights,
                ),
            },
            "elapsed_seconds": round(elapsed_seconds(), 3),
            "effective_max_line_search_attempts": effective_max_line_search_attempts,
            "line_search_attempt_policy": line_search_attempt_policy,
            "objective_weights": dict(objective_weights),
            "projection_deadband": dict(projection_deadband_config),
            "projection_prescreen": dict(projection_prescreen_config),
            "projection_update_families": dict(projection_update_family_config),
            "projection_prescreen_summary": _projection_prescreen_summary(
                epoch_reports
            ),
            "projection_profile": projection_profile,
            "projection_profile_enabled": profiler is not None,
            "projection_cuda_residency": cuda_residency,
            "projection_update_backend": normalized_update_backend,
            "rejection_summary": _projection_rejection_summary(epoch_reports),
            "sample_memory_used": False,
            "legal_ir_bridge_max_samples": bridge_sample_cap,
            "legal_ir_bridge_max_sample_text_chars": bridge_text_cap,
            "precomputed_holdout_evaluation_reused": (
                precomputed_holdout_evaluation is not None
            ),
            "precomputed_training_evaluation_reused": (
                precomputed_training_evaluation is not None
            ),
            "state_entry_count": state_entry_count,
            "stopped_reason": projection_stopped_reason,
            "validation_sample_count": len(target_samples),
        }

    def _apply_projection_update_batch(
        self,
        samples: Sequence[LegalSample],
        *,
        update_targets: Sequence[str],
        learning_rate: float,
        l2_regularization: float,
        profiler: Optional[ProjectionProfiler] = None,
        update_backend: str = "native",
    ) -> Dict[str, Any]:
        """Apply a batch atomically and account only for its touched rows."""

        active = self.state._active_state_transaction
        if active is not None:
            return self._apply_projection_update_batch_in_transaction(
                samples,
                update_targets=update_targets,
                learning_rate=learning_rate,
                l2_regularization=l2_regularization,
                profiler=profiler,
                update_backend=update_backend,
            )
        transaction = self.state.transaction(label="projection-update-batch").begin()
        try:
            report = self._apply_projection_update_batch_in_transaction(
                samples,
                update_targets=update_targets,
                learning_rate=learning_rate,
                l2_regularization=l2_regularization,
                profiler=profiler,
                update_backend=update_backend,
            )
            transaction.commit()
            return report
        except BaseException:
            if transaction.active:
                transaction.rollback()
                self._invalidate_state_dependent_evaluator_caches()
            raise

    def _apply_projection_update_batch_in_transaction(
        self,
        samples: Sequence[LegalSample],
        *,
        update_targets: Sequence[str],
        learning_rate: float,
        l2_regularization: float,
        profiler: Optional[ProjectionProfiler] = None,
        update_backend: str = "native",
    ) -> Dict[str, Any]:
        """Apply compatible projection updates as one guarded optimizer batch.

        Native updates retain the historical sample-outer/head-inner order.
        The ``cuda_resident`` backend instead collates the complete batch into
        packed feature/parameter tensors and performs forward loss, backward,
        clipping, and the optimizer step on the selected CUDA device.  It never
        enters this method recursively or invokes a legacy per-sample updater.
        """
        sample_list = list(samples)
        target_tuple = tuple(str(target) for target in update_targets)
        normalized_backend = str(update_backend or "native").strip().lower()
        transaction = self.state._active_state_transaction
        if transaction is None:
            raise StateTransactionConflictError(
                "projection update batch requires an active state transaction"
            )
        if normalized_backend == "cuda_resident":
            try:
                from .modal_autoencoder_cuda import (
                    apply_cuda_resident_projection_update,
                )

                report = apply_cuda_resident_projection_update(
                    self,
                    sample_list,
                    update_targets=target_tuple,
                    learning_rate=learning_rate,
                    l2_regularization=l2_regularization,
                    profiler=profiler,
                )
                self._cuda_residency_reports.append(report.to_dict())
                self._cuda_residency_reports = self._cuda_residency_reports[-256:]
                if report.applied:
                    norm_report = legal_ir_trainable_head_transaction_delta_norm_report(
                        transaction,
                        self.state,
                        learning_rate=learning_rate,
                    )
                    norm_report["backend_report"] = report.to_dict()
                    norm_report["projection_update_backend"] = "cuda_resident"
                    return norm_report
                if profiler is not None:
                    profiler.count("cuda_resident_deterministic_fallback_count")
            except Exception:
                if profiler is not None:
                    profiler.count("cuda_resident_deterministic_fallback_count")
            normalized_backend = "native"
        use_sparse_python = normalized_backend == "python_sparse_batch"
        if profiler is not None:
            profiler.count("projection_update_batch_count", 1)
            profiler.count("projection_update_sample_count", len(sample_list))
            profiler.count("projection_update_head_count", len(target_tuple))
            if self.compute_backend == "torch_cuda":
                if use_sparse_python:
                    profiler.count("redundant_cuda_update_sync_avoided_count", 1)
                    profiler.count(
                        "host_device_transfer_avoided_count",
                        max(1, len(sample_list) * max(1, len(target_tuple))),
                    )
                else:
                    profiler.transfer(
                        stage="projection_update_batch",
                        legal_family="aggregate",
                        count=max(1, len(sample_list) * max(1, len(target_tuple))),
                        bytes_moved=sum(
                            len(getattr(sample, "embedding_vector", ()) or ()) * 8
                            for sample in sample_list
                        ),
                    )

        old_torch = self._torch
        old_device = self.compute_device
        if use_sparse_python:
            self._torch = None
            self.compute_device = None
        try:
            phase_context = (
                profiler.phase(
                    "optimizer",
                    stage="projection_update_batch",
                    legal_family="aggregate",
                    feature_head="+".join(target_tuple),
                    metadata={
                        "learning_rate": float(learning_rate),
                        "sample_count": len(sample_list),
                        "update_backend": normalized_backend,
                        "update_targets": list(target_tuple),
                    },
                )
                if profiler is not None
                else nullcontext()
            )
            with phase_context:
                for sample in sample_list:
                    legal_family = (
                        _target_family(sample)
                        if profiler is not None
                        else ""
                    )
                    for update_target in target_tuple:
                        head_context = (
                            profiler.phase(
                                "feature_head",
                                stage="projection_update_head",
                                legal_family=legal_family,
                                feature_head=update_target,
                            )
                            if profiler is not None
                            else nullcontext()
                        )
                        with head_context:
                            if update_target == "family_logits":
                                self._nudge_family_logits(
                                    sample,
                                    learning_rate=learning_rate,
                                    update_sample_memory=False,
                                )
                            elif update_target == "decoded_embedding":
                                self._nudge_decoded_embedding(
                                    sample,
                                    learning_rate=learning_rate,
                                    update_sample_memory=False,
                                )
                            elif update_target == "legal_ir_view_logits":
                                self._nudge_legal_ir_view_logits(
                                    sample,
                                    learning_rate=learning_rate,
                                    update_sample_memory=False,
                                )
                            elif update_target == "legal_ir_view_global_logits":
                                self._nudge_legal_ir_view_global_logits(
                                    sample,
                                    learning_rate=learning_rate,
                                )
                            else:
                                raise ValueError(
                                    f"unknown projection update target: {update_target}"
                                )
                if l2_regularization:
                    regularize_context = (
                        profiler.phase(
                            "optimizer",
                            stage="projection_l2_regularization",
                            legal_family="aggregate",
                        )
                        if profiler is not None
                        else nullcontext()
                    )
                    with regularize_context:
                        self._regularize_feature_state(l2_regularization)
        finally:
            if use_sparse_python:
                self._torch = old_torch
                self.compute_device = old_device
        norm_report = legal_ir_trainable_head_transaction_delta_norm_report(
            transaction,
            self.state,
            learning_rate=learning_rate,
        )
        norm_report["projection_update_backend"] = normalized_backend
        return norm_report

    def _select_hard_examples_for_projection(
        self,
        samples: Sequence[LegalSample],
        *,
        hard_example_fraction: float,
        objective_weights: Mapping[str, float],
    ) -> List[LegalSample]:
        if not samples:
            return []
        if hard_example_fraction >= 1.0 or len(samples) == 1:
            return list(samples)
        ranked = sorted(
            (
                (
                    self._sample_training_objective(
                        sample,
                        objective_weights=objective_weights,
                    ),
                    sample,
                )
                for sample in samples
            ),
            key=lambda item: item[0],
            reverse=True,
        )
        keep = max(1, int(math.ceil(len(ranked) * hard_example_fraction)))
        return [sample for _, sample in ranked[:keep]]

    def _sample_training_objective(
        self,
        sample: LegalSample,
        *,
        objective_weights: Mapping[str, float],
    ) -> float:
        ce_weight = max(0.0, float(objective_weights.get("cross_entropy", 1.0)))
        rec_weight = max(0.0, float(objective_weights.get("reconstruction", 1.0)))
        cos_weight = max(0.0, float(objective_weights.get("cosine_gap", 1.0)))
        legal_weight = max(0.0, float(objective_weights.get("legal_ir", 1.0)))

        decoded = self._decoded_for(sample, use_sample_memory=False)
        reconstruction = mse_loss(sample.embedding_vector, decoded)
        cosine_gap = max(0.0, 1.0 - cosine_similarity(sample.embedding_vector, decoded))
        distribution = self._family_distribution(sample, use_sample_memory=False)
        target_family_distribution = _observed_family_distribution(sample)
        cross_entropy = cross_entropy_excess_distribution_loss(
            distribution,
            target_family_distribution,
        )

        legal_ir_loss = 0.0
        target_distribution = self._legal_ir_view_target_cache.get(sample.sample_id)
        if target_distribution:
            predicted = self._legal_ir_view_distribution(
                sample,
                target_distribution,
                use_sample_memory=False,
            )
            legal_ir_loss = cross_entropy_excess_distribution_loss(
                predicted,
                target_distribution,
            )

        return (
            (ce_weight * cross_entropy)
            + (rec_weight * reconstruction)
            + (cos_weight * cosine_gap)
            + (legal_weight * legal_ir_loss)
        )

    def _decoded_for(self, sample: LegalSample, *, use_sample_memory: bool = True) -> List[float]:
        stored = self.state.decoded_embeddings.get(sample.sample_id) if use_sample_memory else None
        if stored is not None and len(stored) == len(sample.embedding_vector):
            return list(stored)
        base = self._base_decoded_for(sample)
        compiler_quality_adjustment = self._compiler_quality_embedding_adjustment(
            sample,
            dimensions=len(base),
        )
        logic_signature_adjustment = self._logic_signature_embedding_adjustment(
            sample,
            dimensions=len(base),
        )
        round_trip_signal_adjustment = self._round_trip_signal_embedding_adjustment(
            sample,
            dimensions=len(base),
        )
        decompiler_plan_adjustment = self._decompiler_plan_embedding_adjustment(
            sample,
            dimensions=len(base),
        )
        predicate_argument_adjustment = self._predicate_argument_embedding_adjustment(
            sample,
            dimensions=len(base),
        )
        family_adjustment = self._family_embedding_adjustment(
            sample,
            dimensions=len(base),
            use_sample_memory=use_sample_memory,
        )
        semantic_slot_adjustment = self._semantic_slot_embedding_adjustment(
            sample,
            dimensions=len(base),
        )
        family_semantic_slot_adjustment = (
            self._family_semantic_slot_embedding_adjustment(
                sample,
                dimensions=len(base),
                use_sample_memory=use_sample_memory,
            )
        )
        semantic_slot_legal_ir_view_adjustment = (
            self._semantic_slot_legal_ir_view_embedding_adjustment(
                sample,
                dimensions=len(base),
                use_sample_memory=use_sample_memory,
            )
        )
        family_semantic_slot_legal_ir_view_adjustment = (
            self._family_semantic_slot_legal_ir_view_embedding_adjustment(
                sample,
                dimensions=len(base),
                use_sample_memory=use_sample_memory,
            )
        )
        family_legal_ir_view_adjustment = (
            self._family_legal_ir_view_embedding_adjustment(
                sample,
                dimensions=len(base),
                use_sample_memory=use_sample_memory,
            )
        )
        legal_ir_view_adjustment = self._legal_ir_view_embedding_adjustment(
            sample,
            dimensions=len(base),
            use_sample_memory=use_sample_memory,
        )
        adjustment = self._feature_embedding_adjustment(sample, dimensions=len(base))
        candidate = [
            (
                base_value
                + compiler_quality_value
                + logic_signature_value
                + round_trip_signal_value
                + decompiler_plan_value
                + predicate_argument_value
                + family_value
                + slot_value
                + family_slot_value
                + slot_view_value
                + family_slot_view_value
                + joint_value
                + view_value
                + adjustment_value
            )
            for base_value, compiler_quality_value, logic_signature_value, round_trip_signal_value, decompiler_plan_value, predicate_argument_value, family_value, slot_value, family_slot_value, slot_view_value, family_slot_view_value, joint_value, view_value, adjustment_value in zip(
                base,
                compiler_quality_adjustment,
                logic_signature_adjustment,
                round_trip_signal_adjustment,
                decompiler_plan_adjustment,
                predicate_argument_adjustment,
                family_adjustment,
                semantic_slot_adjustment,
                family_semantic_slot_adjustment,
                semantic_slot_legal_ir_view_adjustment,
                family_semantic_slot_legal_ir_view_adjustment,
                family_legal_ir_view_adjustment,
                legal_ir_view_adjustment,
                adjustment,
            )
        ]
        return self._reconstruction_safe_projection(
            sample.embedding_vector,
            base,
            candidate,
        )

    def _reconstruction_safe_projection(
        self,
        target: Sequence[float],
        base: Sequence[float],
        candidate: Sequence[float],
    ) -> List[float]:
        """Return the best point from base toward candidate for reconstruction."""
        if len(target) != len(base) or len(target) != len(candidate):
            return [float(value) for value in candidate]
        direction = [
            float(candidate_value) - float(base_value)
            for base_value, candidate_value in zip(base, candidate)
        ]
        denominator = sum(value * value for value in direction)
        if denominator <= 0.0:
            return [float(value) for value in candidate]
        numerator = sum(
            (float(target_value) - float(base_value)) * direction_value
            for target_value, base_value, direction_value in zip(target, base, direction)
        )
        unclamped_step = numerator / denominator
        step = max(0.0, min(1.0, unclamped_step))
        projected = [
            float(base_value) + (step * direction_value)
            for base_value, direction_value in zip(base, direction)
        ]
        target_point = [float(value) for value in target]
        if (
            0.0 < unclamped_step
            and mse_loss(target_point, target_point) <= mse_loss(target_point, projected)
            and cosine_loss(target_point, target_point) <= cosine_loss(
                target_point,
                projected,
            )
        ):
            return target_point
        return projected

    def _base_decoded_for(self, sample: LegalSample) -> List[float]:
        cache = self._sample_cache_for(sample)
        cached = cache.get("base_decoded")
        if isinstance(cached, list) and len(cached) == len(sample.embedding_vector):
            return [float(value) for value in cached]

        if self.feature_codec is not None and hasattr(
            self.feature_codec,
            "decode_sample_embedding",
        ):
            decoded = self.feature_codec.decode_sample_embedding(
                sample,
                dimensions=len(sample.embedding_vector),
            )
            if len(decoded) == len(sample.embedding_vector):
                result = [float(value) for value in decoded]
                cache["base_decoded"] = list(result)
                return result
        result = self._initial_embedding_projection(sample.embedding_vector)
        cache["base_decoded"] = list(result)
        return result

    def _initial_embedding_projection(self, embedding: Sequence[float]) -> List[float]:
        """Return a stable imperfect fallback projection for cold decoder state.

        The pairwise skew component keeps cosine below 1.0 for sparse fixtures
        while the error norm remains lower than the previous all-zero fallback
        when ``(1 - scale) ** 2 + rotation_scale ** 2 <= 1``.
        """
        scale = float(self.initial_embedding_scale)
        rotation_scale = float(self.initial_embedding_rotation_scale)
        if not embedding:
            return []
        if rotation_scale == 0.0:
            return [scale * float(value) for value in embedding]

        result = [0.0 for _ in embedding]
        index = 0
        while index + 1 < len(embedding):
            left = float(embedding[index])
            right = float(embedding[index + 1])
            result[index] = (scale * left) + (rotation_scale * right)
            result[index + 1] = (scale * right) - (rotation_scale * left)
            index += 2
        if index < len(embedding):
            result[index] = scale * float(embedding[index])
        return result

    def _family_distribution(
        self,
        sample: LegalSample,
        *,
        use_sample_memory: bool = True,
    ) -> Dict[str, float]:
        return _softmax(self._logits_for(sample, use_sample_memory=use_sample_memory))

    def _legal_ir_view_distribution(
        self,
        sample: LegalSample,
        target_distribution: Mapping[str, float],
        *,
        use_sample_memory: bool = True,
    ) -> Dict[str, float]:
        families = _unique_preserve_order(
            [str(name) for name in target_distribution.keys()]
            + list(self._legal_ir_view_family_candidates())
            + [
                str(family)
                for family in self.state.family_logits.get(sample.sample_id, {}).keys()
                if self._is_legal_ir_view_family(str(family))
            ]
        )
        logits = self._legal_ir_view_logits_for(
            sample,
            families,
            use_sample_memory=use_sample_memory,
        )
        return _softmax(logits)

    def _legal_ir_view_target_distribution_for_sample(
        self,
        sample: LegalSample,
        *,
        include_autoencoder_prior: bool = True,
    ) -> Dict[str, float]:
        distribution = self._legal_ir_view_target_cache.get(
            sample.sample_id,
            self._legal_ir_view_target_cache.get(_sample_content_cache_id(sample), {}),
        )
        cached_distribution = {
            str(name): _float_or_zero(value)
            for name, value in dict(distribution or {}).items()
            if _float_or_zero(value) > 0.0
        }
        if cached_distribution:
            return cached_distribution
        if not include_autoencoder_prior:
            return {}
        return self._autoencoder_view_target_distribution_for_sample(sample)

    def _autoencoder_view_target_distribution_for_sample(
        self,
        sample: LegalSample,
    ) -> Dict[str, float]:
        """Return a deterministic view prior for reconstruction-only training."""
        family_distribution = _observed_family_distribution(sample)
        surface_distribution = _legal_ir_surface_profile_view_distribution(
            sample.text or sample.normalized_text or ""
        )
        if not family_distribution:
            return surface_distribution
        view_weights: Dict[str, float] = {}

        def bump(view: str, weight: float) -> None:
            normalized_weight = max(0.0, float(weight))
            if not view or normalized_weight <= 0.0:
                return
            view_weights[view] = view_weights.get(view, 0.0) + normalized_weight

        for family, family_weight in family_distribution.items():
            weight = max(0.0, float(family_weight))
            if weight <= 0.0:
                continue
            family_name = str(family)
            if family_name == "deontic":
                bump("deontic.ir", 0.60 * weight)
                bump("TDFOL.prover", 0.25 * weight)
                bump("modal.frame_logic", 0.15 * weight)
            elif family_name == "frame":
                bump("modal.frame_logic", 0.55 * weight)
                bump("modal.autoencoder", 0.30 * weight)
                bump("deontic.ir", 0.15 * weight)
            elif family_name == "temporal":
                bump("TDFOL.prover", 0.35 * weight)
                bump("CEC.native", 0.25 * weight)
                bump("modal.frame_logic", 0.20 * weight)
                bump("deontic.ir", 0.15 * weight)
                bump("modal.autoencoder", 0.05 * weight)
            elif family_name == "conditional_normative":
                bump("deontic.ir", 0.35 * weight)
                bump("TDFOL.prover", 0.25 * weight)
                bump("modal.frame_logic", 0.20 * weight)
                bump("CEC.native", 0.15 * weight)
                bump("modal.autoencoder", 0.05 * weight)
            else:
                bump("modal.autoencoder", 0.50 * weight)
                bump("modal.frame_logic", 0.25 * weight)
                bump("TDFOL.prover", 0.25 * weight)
        for view, surface_weight in surface_distribution.items():
            bump(view, 0.35 * surface_weight)
        return _normalized_distribution(view_weights)

    def _legal_ir_view_distribution_for_embedding(
        self,
        sample: LegalSample,
        *,
        use_sample_memory: bool,
    ) -> Dict[str, float]:
        target_distribution = self._legal_ir_view_target_distribution_for_sample(sample)
        if target_distribution:
            return self._legal_ir_view_distribution(
                sample,
                target_distribution,
                use_sample_memory=use_sample_memory,
            )
        families = self._legal_ir_view_family_candidates()
        if not families:
            return {}
        return _softmax(
            self._legal_ir_view_logits_for(
                sample,
                families,
                use_sample_memory=use_sample_memory,
            )
        )

    def _compiler_quality_loss_targets_for_sample(
        self,
        sample: LegalSample,
    ) -> Dict[str, float]:
        losses = self._legal_ir_loss_target_cache.get(
            sample.sample_id,
            self._legal_ir_loss_target_cache.get(_sample_content_cache_id(sample), {}),
        )
        return {
            str(name): _float_or_zero(value)
            for name, value in dict(losses or {}).items()
            if _float_or_zero(value) > 0.0
        }

    def _compiler_quality_slot_distribution_for(
        self,
        sample: LegalSample,
    ) -> Dict[str, float]:
        counts: Dict[str, float] = {}

        def bump(slot: str, weight: float = 1.0) -> None:
            normalized_weight = max(0.0, float(weight))
            if normalized_weight <= 0.0:
                return
            counts[str(slot)] = counts.get(str(slot), 0.0) + normalized_weight

        formula_count = len(sample.modal_ir.formulas)
        frame_loss = frame_ranking_loss(sample)
        bump("quality:bias", 1.0)
        bump(f"quality:formula-count:{_count_bucket(formula_count)}", 0.5)
        bump(
            f"quality:symbolic-penalty:{_quality_loss_bucket(symbolic_validity_penalty(sample))}",
            0.5,
        )
        if formula_count:
            bump("quality:symbolic:has-formula", 1.0)
        else:
            bump("quality:symbolic:missing-formula", 2.0)
            bump("quality:todo:add-deterministic-parser-rule", 1.25)

        if not sample.frame_candidates or sample.selected_frame is None:
            bump("quality:frame:missing", 1.25)
        elif frame_loss <= 0.0:
            bump("quality:frame:rank-top", 0.75)
        else:
            bump(
                f"quality:frame:rank-off-top:{_count_bucket(int(math.ceil(frame_loss)))}",
                1.0,
            )
        bump(f"quality:frame-candidate-count:{_count_bucket(len(sample.frame_candidates))}", 0.4)
        if sample.selected_frame:
            frame = _feature_atom(sample.selected_frame, max_tokens=6)
            if frame:
                bump(f"quality:frame:selected:{frame}", 0.4)

        frame_logic = getattr(sample.modal_ir, "frame_logic", None)
        if frame_logic is None:
            bump("quality:frame-logic:missing", 0.5)
        else:
            triples = list(getattr(frame_logic, "triples", []) or [])
            bump(f"quality:frame-logic-triples:{_count_bucket(len(triples))}", 0.4)
            if not triples:
                bump("quality:frame-logic:empty", 0.5)

        for name, value in sorted(
            self._compiler_quality_loss_targets_for_sample(sample).items()
        ):
            if value <= 0.0:
                continue
            loss_name = _feature_atom(name, max_tokens=6)
            if not loss_name:
                continue
            bump(
                f"quality:legal-ir-loss:{loss_name}:{_quality_loss_bucket(value)}",
                min(2.0, 0.25 + value),
            )

        return _normalized_distribution(counts)

    def _logic_signature_distribution_for(
        self,
        sample: LegalSample,
    ) -> Dict[str, float]:
        cache = self._sample_cache_for(sample)
        cached = cache.get("logic_signature_distribution")
        if isinstance(cached, dict):
            return {str(name): float(value) for name, value in cached.items()}

        counts: Dict[str, float] = {}

        def bump(signature: str, weight: float = 1.0) -> None:
            normalized_weight = max(0.0, float(weight))
            if not signature or normalized_weight <= 0.0:
                return
            counts[str(signature)] = counts.get(str(signature), 0.0) + normalized_weight

        bump("signature:bias", 0.5)
        bump(f"signature:formula-count:{_count_bucket(len(sample.modal_ir.formulas))}", 0.4)
        if sample.selected_frame:
            frame = _feature_atom(sample.selected_frame, max_tokens=6)
            if frame:
                bump(f"signature:frame:{frame}", 0.5)

        frame_logic = sample.modal_ir.frame_logic
        if frame_logic is not None:
            ontology = _feature_atom(getattr(frame_logic, "ontology_name", ""))
            if ontology:
                bump(f"signature:frame-logic-ontology:{ontology}", 0.5)
            triples = list(getattr(frame_logic, "triples", []) or [])
            bump(f"signature:frame-logic-triples:{_count_bucket(len(triples))}", 0.4)
            relation_names = [
                _feature_atom(relation)
                for relation in sorted(
                    getattr(frame_logic, "neo4j_relationship_types", []) or []
                )[:4]
            ]
            for relation in relation_names:
                if relation:
                    bump(f"signature:kg-relation:{relation}", 0.35)

        if not sample.modal_ir.formulas:
            bump("signature:no-modal-formula", 1.0)

        family_sequence: List[str] = []
        operator_sequence: List[str] = []
        for formula in sample.modal_ir.formulas:
            family = _feature_atom(formula.operator.family)
            system = _feature_atom(formula.operator.system)
            symbol = _feature_atom(formula.operator.symbol)
            predicate_name = _feature_atom(getattr(formula.predicate, "name", ""))
            predicate_role = _feature_atom(
                getattr(formula.predicate, "role", "") or "none"
            )
            arguments = list(getattr(formula.predicate, "arguments", []) or [])
            conditions = list(getattr(formula, "conditions", []) or [])
            exceptions = list(getattr(formula, "exceptions", []) or [])
            arity_bucket = _count_bucket(len(arguments))
            condition_bucket = _count_bucket(len(conditions))
            exception_bucket = _count_bucket(len(exceptions))

            if family:
                family_sequence.append(family)
                bump(f"signature:family:{family}", 1.0)
                bump(
                    f"signature:constraint-shape:{family}:c{condition_bucket}:e{exception_bucket}",
                    1.0,
                )
                if sample.selected_frame:
                    frame = _feature_atom(sample.selected_frame, max_tokens=6)
                    if frame:
                        bump(f"signature:frame-family:{frame}:{family}", 0.75)
            if family and system and symbol:
                operator_sequence.append(f"{family}:{system}:{symbol}")
                bump(f"signature:operator:{family}:{system}:{symbol}", 1.25)
            if family and predicate_role:
                bump(
                    f"signature:role-schema:{family}:{predicate_role}:arity:{arity_bucket}",
                    1.25,
                )
                bump(
                    f"signature:role-constraint:{family}:{predicate_role}:c{condition_bucket}:e{exception_bucket}",
                    0.9,
                )
            if family and predicate_name:
                predicate_head = predicate_name.split("_", 1)[0]
                if predicate_head:
                    bump(f"signature:predicate-head:{family}:{predicate_head}", 0.5)
            cue = formula.metadata.get("cue") if formula.metadata else None
            cue_name = _feature_atom(cue)
            if family and cue_name:
                bump(f"signature:cue-family:{cue_name}:{family}", 0.75)

        for left_family, right_family in zip(family_sequence, family_sequence[1:]):
            bump(f"signature:family-transition:{left_family}->{right_family}", 0.75)
        for left_operator, right_operator in zip(operator_sequence, operator_sequence[1:]):
            bump(f"signature:operator-transition:{left_operator}->{right_operator}", 0.75)

        result = _normalized_distribution(counts)
        cache["logic_signature_distribution"] = dict(result)
        return result

    def _round_trip_signal_distribution_for(
        self,
        sample: LegalSample,
    ) -> Dict[str, float]:
        cache = self._sample_cache_for(sample)
        cached = cache.get("round_trip_signal_distribution")
        if isinstance(cached, dict):
            return {str(name): float(value) for name, value in cached.items()}

        counts: Dict[str, float] = {}

        def bump(signal: str, weight: float = 1.0) -> None:
            normalized_weight = max(0.0, float(weight))
            if not signal or normalized_weight <= 0.0:
                return
            counts[str(signal)] = counts.get(str(signal), 0.0) + normalized_weight

        base_distribution = _softmax(self._base_logits_for(sample))
        ranked_families = sorted(
            base_distribution.items(),
            key=lambda item: (-float(item[1]), str(item[0])),
        )
        top_family, top_probability = (
            ranked_families[0] if ranked_families else (ModalLogicFamily.HYBRID.value, 0.0)
        )
        second_family, second_probability = (
            ranked_families[1] if len(ranked_families) > 1 else ("none", 0.0)
        )
        entropy = 0.0
        for value in base_distribution.values():
            probability = max(float(value), 1e-12)
            entropy += -probability * math.log(probability)
        max_entropy = math.log(max(2, len(base_distribution)))
        normalized_entropy = entropy / max_entropy if max_entropy > 0.0 else 0.0
        margin = max(0.0, float(top_probability) - float(second_probability))

        bump("round-trip:bias", 0.5)
        bump(f"round-trip:base-top-family:{top_family}", 1.0)
        bump(f"round-trip:base-runner-up-family:{second_family}", 0.5)
        bump(f"round-trip:base-confidence:{_ratio_bucket(float(top_probability))}", 0.75)
        bump(f"round-trip:base-margin:{_ratio_bucket(margin)}", 0.75)
        bump(f"round-trip:base-entropy:{_ratio_bucket(normalized_entropy)}", 0.75)
        if margin <= 0.10:
            bump("round-trip:modal-family-ambiguous", 1.25)

        formula_families = [
            _feature_atom(formula.operator.family)
            for formula in sample.modal_ir.formulas
            if _feature_atom(formula.operator.family)
        ]
        distinct_formula_families = sorted(set(formula_families))
        bump(
            f"round-trip:formula-count:{_count_bucket(len(sample.modal_ir.formulas))}",
            0.5,
        )
        bump(
            f"round-trip:observed-family-count:{_count_bucket(len(distinct_formula_families))}",
            0.5,
        )
        if not sample.modal_ir.formulas:
            bump("round-trip:no-modal-formula", 1.25)
        if len(distinct_formula_families) > 1:
            bump("round-trip:mixed-modal-families", 1.0)
        for family in distinct_formula_families[:4]:
            bump(f"round-trip:observed-family:{family}", 0.5)

        text = " ".join(str(sample.normalized_text or sample.text or "").split()).lower()
        cues = self._cue_names_for_text(text)
        surface_profiles = _uscode_surface_profile_tags(text)
        bump(f"round-trip:cue-count:{_count_bucket(len(cues))}", 0.4)
        if len(cues) > 1:
            bump("round-trip:multiple-modal-cues", 0.75)
        for cue in cues[:4]:
            bump(f"round-trip:cue:{cue}", 0.4)
        for profile in surface_profiles[:8]:
            bump(f"round-trip:uscode-surface-profile:{profile}", 0.8)
        for left_profile, right_profile in zip(surface_profiles, surface_profiles[1:]):
            bump(
                f"round-trip:uscode-surface-profile-transition:{left_profile}->{right_profile}",
                0.55,
            )

        frame_candidates = list(sample.frame_candidates or [])
        bump(
            f"round-trip:frame-candidate-count:{_count_bucket(len(frame_candidates))}",
            0.4,
        )
        if sample.selected_frame:
            frame = _feature_atom(sample.selected_frame, max_tokens=6)
            if frame:
                bump(f"round-trip:selected-frame:{frame}", 0.5)
        scores = sorted(
            [
                max(0.0, _float_or_zero(candidate.get("score", 0.0)))
                for candidate in frame_candidates
                if isinstance(candidate, Mapping)
            ],
            reverse=True,
        )
        if scores:
            frame_margin = scores[0] - (scores[1] if len(scores) > 1 else 0.0)
            bump(f"round-trip:frame-score-margin:{_ratio_bucket(frame_margin)}", 0.5)
            if len(scores) > 1 and frame_margin <= 0.05:
                bump("round-trip:frame-choice-ambiguous", 1.0)

        frame_logic = getattr(sample.modal_ir, "frame_logic", None)
        if frame_logic is None:
            bump("round-trip:frame-logic-missing", 0.75)
        else:
            triples = list(getattr(frame_logic, "triples", []) or [])
            bump(
                f"round-trip:frame-logic-triples:{_count_bucket(len(triples))}",
                0.5,
            )
            if not triples:
                bump("round-trip:frame-logic-empty", 0.75)
            for relation in sorted(
                getattr(frame_logic, "neo4j_relationship_types", []) or []
            )[:4]:
                relation_atom = _feature_atom(relation)
                if relation_atom:
                    bump(f"round-trip:kg-relation:{relation_atom}", 0.35)

        result = _normalized_distribution(counts)
        cache["round_trip_signal_distribution"] = dict(result)
        return result

    def _decompiler_plan_distribution_for(
        self,
        sample: LegalSample,
    ) -> Dict[str, float]:
        cache = self._sample_cache_for(sample)
        cached = cache.get("decompiler_plan_distribution")
        if isinstance(cached, dict):
            return {str(name): float(value) for name, value in cached.items()}

        text = " ".join(str(sample.normalized_text or sample.text or "").split()).lower()
        raw_tokens = _TOKEN_RE.findall(text)
        content_tokens = _token_features(text, max_tokens=32)
        cues = self._cue_names_for_text(text)
        surface_profiles = _uscode_surface_profile_tags(text)
        counts: Dict[str, float] = {}

        def bump(plan: str, weight: float = 1.0) -> None:
            normalized_weight = max(0.0, float(weight))
            if not plan or normalized_weight <= 0.0:
                return
            counts[str(plan)] = counts.get(str(plan), 0.0) + normalized_weight

        cue_markers = {
            "shall",
            "must",
            "may",
            "required",
            "requires",
            "prohibited",
            "authorized",
            "permitted",
            "eligible",
            "entitled",
            "means",
            "defined",
            "within",
            "before",
            "after",
            "until",
            "during",
            "except",
            "notwithstanding",
        }

        def role_tokens(tokens: Sequence[str]) -> List[str]:
            return [
                token
                for token in tokens
                if len(token) > 2
                and token not in _STOPWORDS
                and token not in cue_markers
            ]

        cue_index = next(
            (index for index, token in enumerate(raw_tokens) if token in cue_markers),
            -1,
        )
        source_anchors = self._source_role_anchors_for(sample)
        if cue_index >= 0:
            subject_candidates = role_tokens(raw_tokens[:cue_index])
            predicate_candidates = role_tokens(raw_tokens[cue_index + 1 :])
        else:
            subject_candidates = role_tokens(raw_tokens[:2])
            predicate_candidates = role_tokens(raw_tokens[1:])

        subject_anchor = (
            source_anchors.get("subject")
            or (subject_candidates[-1] if subject_candidates else "")
        )
        action_anchor = (
            source_anchors.get("action")
            or (predicate_candidates[0] if predicate_candidates else "")
        )
        object_anchor = (
            source_anchors.get("object")
            or (predicate_candidates[1] if len(predicate_candidates) > 1 else "")
        )
        condition_anchor = source_anchors.get("condition", "")
        exception_anchor = source_anchors.get("exception", "")
        temporal_anchor = source_anchors.get("temporal", "")

        bump("decompiler-plan:bias", 0.75)
        bump(f"decompiler-plan:token-count:{_count_bucket(len(content_tokens))}", 0.35)
        bump(f"decompiler-plan:cue-count:{_count_bucket(len(cues))}", 0.35)
        if not cues:
            bump("decompiler-plan:no-explicit-modal-cue", 0.75)
        for cue in cues[:5]:
            bump(f"decompiler-plan:cue:{cue}", 0.9)
        if cues:
            bump(f"decompiler-plan:first-cue:{cues[0]}", 0.65)
            bump(f"decompiler-plan:cue-signature:{'|'.join(cues[:4])}", 0.6)
        for left_cue, right_cue in zip(cues, cues[1:]):
            bump(f"decompiler-plan:cue-transition:{left_cue}->{right_cue}", 0.4)
        for profile in surface_profiles[:8]:
            bump(f"decompiler-plan:uscode-surface-profile:{profile}", 0.85)
            if not cues:
                bump(
                    f"decompiler-plan:no-cue-surface-profile:{profile}",
                    0.65,
                )
        for left_profile, right_profile in zip(surface_profiles, surface_profiles[1:]):
            bump(
                f"decompiler-plan:uscode-surface-profile-transition:{left_profile}->{right_profile}",
                0.5,
            )

        if subject_anchor:
            bump(f"decompiler-plan:subject-anchor:{subject_anchor}", 0.55)
        if action_anchor:
            bump(f"decompiler-plan:action-anchor:{action_anchor}", 0.75)
        if object_anchor:
            bump(f"decompiler-plan:object-anchor:{object_anchor}", 0.55)
        if subject_anchor and action_anchor:
            bump(
                f"decompiler-plan:subject-action:{subject_anchor}->{action_anchor}",
                0.5,
            )
        if action_anchor and object_anchor:
            bump(
                f"decompiler-plan:action-object:{action_anchor}->{object_anchor}",
                0.5,
            )
        for role_name, anchor in sorted(source_anchors.items()):
            bump(f"decompiler-plan:source-role:{role_name}:{anchor}", 0.5)

        if any(cue in cues for cue in ("conditional",)):
            bump("decompiler-plan:condition-surface-present", 0.75)
        if any(cue in cues for cue in ("exception",)):
            bump("decompiler-plan:exception-surface-present", 0.75)
        if any(cue in cues for cue in ("temporal",)):
            bump("decompiler-plan:temporal-surface-present", 0.75)
        if sample.selected_frame:
            frame = _feature_atom(sample.selected_frame, max_tokens=6)
            if frame:
                bump(f"decompiler-plan:selected-frame:{frame}", 0.45)
                if action_anchor:
                    bump(
                        f"decompiler-plan:frame-action:{frame}:{action_anchor}",
                        0.35,
                    )
        section_prefix = _section_prefix(sample.section)
        if section_prefix and cues:
            bump(f"decompiler-plan:section-cue:{section_prefix}:{cues[0]}", 0.35)

        bump(
            f"decompiler-plan:formula-count:{_count_bucket(len(sample.modal_ir.formulas))}",
            0.35,
        )
        if not sample.modal_ir.formulas:
            bump("decompiler-plan:no-compiled-formula", 0.65)
        for formula in sample.modal_ir.formulas[:4]:
            family = _feature_atom(formula.operator.family)
            system = _feature_atom(formula.operator.system)
            symbol = _feature_atom(formula.operator.symbol)
            predicate_name = _feature_atom(getattr(formula.predicate, "name", ""))
            predicate_head = predicate_name.split("_", 1)[0] if predicate_name else ""
            role = _feature_atom(getattr(formula.predicate, "role", "") or "none")
            arguments = list(getattr(formula.predicate, "arguments", []) or [])
            conditions = list(getattr(formula, "conditions", []) or [])
            exceptions = list(getattr(formula, "exceptions", []) or [])
            arity_bucket = _count_bucket(len(arguments))
            family_pairs = _autoencoder_typed_family_pairs_for_formula(
                sample.modal_ir,
                formula,
            )
            pair_cues = _unique_preserve_order(
                [*cues, *_formula_autoencoder_cue_names(formula)]
            )
            pair_scope_tags = self._source_clause_scope_tags_for(
                sample,
                pair_cues,
                source_anchors,
            )
            if conditions and "conditioned" not in pair_scope_tags:
                pair_scope_tags = [*pair_scope_tags, "conditioned"]
            if exceptions and "excepted" not in pair_scope_tags:
                pair_scope_tags = [*pair_scope_tags, "excepted"]
            pair_scope_signature = "+".join(
                tag for tag in _unique_preserve_order(pair_scope_tags) if tag
            ) or "unconditioned"
            pair_force_tags, pair_polarity_tags = _autoencoder_formula_force_polarity_tags(
                formula,
                text=text,
            )
            if family:
                bump(f"decompiler-plan:compiled-family:{family}", 0.45)
            if family and symbol:
                bump(f"decompiler-plan:compiled-operator:{family}:{symbol}", 0.45)
            if family and role:
                bump(f"decompiler-plan:compiled-role:{family}:{role}", 0.45)
                bump(
                    f"decompiler-plan:compiled-role-shape:{family}:{role}:a{arity_bucket}",
                    0.35,
                )
            if family and system and symbol:
                bump(
                    f"decompiler-plan:compiled-system-operator:{family}:{system}:{symbol}",
                    0.35,
                )
            if family and predicate_head:
                bump(
                    f"decompiler-plan:compiled-predicate-head:{family}:{predicate_head}",
                    0.35,
                )
            if family and action_anchor:
                bump(f"decompiler-plan:source-action-family:{action_anchor}:{family}", 0.75)
                if role:
                    bump(
                        f"decompiler-plan:source-action-role:{action_anchor}:{role}",
                        0.65,
                    )
                if symbol:
                    bump(
                        f"decompiler-plan:source-action-operator:{action_anchor}:{family}:{symbol}",
                        0.45,
                    )
                if predicate_head:
                    bump(
                        f"decompiler-plan:source-action-predicate:{action_anchor}:{predicate_head}",
                        0.55,
                    )
            if family and object_anchor:
                bump(f"decompiler-plan:source-object-family:{object_anchor}:{family}", 0.55)
                if role:
                    bump(
                        f"decompiler-plan:source-object-role:{object_anchor}:{role}",
                        0.45,
                    )
                if predicate_head:
                    bump(
                        f"decompiler-plan:source-object-predicate:{object_anchor}:{predicate_head}",
                        0.5,
                    )
            if family and subject_anchor and role:
                bump(
                    f"decompiler-plan:source-subject-role:{subject_anchor}:{role}",
                    0.35,
                )
            if family and condition_anchor:
                bump(
                    f"decompiler-plan:source-condition-family:{condition_anchor}:{family}",
                    0.4,
                )
            if family and exception_anchor:
                bump(
                    f"decompiler-plan:source-exception-family:{exception_anchor}:{family}",
                    0.4,
                )
            if family and temporal_anchor:
                bump(
                    f"decompiler-plan:source-temporal-family:{temporal_anchor}:{family}",
                    0.4,
                )
            if conditions:
                bump(f"decompiler-plan:compiled-condition:{family}", 0.35)
            if exceptions:
                bump(f"decompiler-plan:compiled-exception:{family}", 0.35)
            for family_pair in family_pairs:
                bump(f"decompiler-plan:typed-family-pair:{family_pair}", 0.9)
                bump(
                    (
                        "decompiler-plan:typed-family-pair-scope:"
                        f"{pair_scope_signature}:{family_pair}"
                    ),
                    0.75,
                )
                if conditions:
                    bump(
                        f"decompiler-plan:typed-family-pair-condition:{family_pair}",
                        0.55,
                    )
                if exceptions:
                    bump(
                        f"decompiler-plan:typed-family-pair-exception:{family_pair}",
                        0.55,
                    )
                if action_anchor:
                    bump(
                        (
                            "decompiler-plan:source-action-family-pair:"
                            f"{action_anchor}:{family_pair}"
                        ),
                        0.65,
                    )
                if predicate_head:
                    bump(
                        (
                            "decompiler-plan:predicate-family-pair:"
                            f"{predicate_head}:{family_pair}"
                        ),
                        0.55,
                    )
                for force in pair_force_tags[:2]:
                    for polarity in pair_polarity_tags[:2]:
                        bump(
                            (
                                "decompiler-plan:force-polarity-family-pair:"
                                f"{force}:{polarity}:{family_pair}"
                            ),
                            0.6,
                        )

        result = _normalized_distribution(counts)
        cache["decompiler_plan_distribution"] = dict(result)
        return result

    def _predicate_argument_distribution_for(
        self,
        sample: LegalSample,
    ) -> Dict[str, float]:
        cache = self._sample_cache_for(sample)
        cached = cache.get("predicate_argument_distribution")
        if isinstance(cached, dict):
            return {str(name): float(value) for name, value in cached.items()}

        counts: Dict[str, float] = {}

        def bump(signature: str, weight: float = 1.0) -> None:
            normalized_weight = max(0.0, float(weight))
            if not signature or normalized_weight <= 0.0:
                return
            counts[str(signature)] = counts.get(str(signature), 0.0) + normalized_weight

        def argument_atom(argument: Any) -> str:
            candidates: List[Any] = []
            if isinstance(argument, Mapping):
                for key in ("role", "name", "value", "text", "entity", "label"):
                    if key in argument:
                        candidates.append(argument.get(key))
            else:
                for key in ("role", "name", "value", "text", "entity", "label"):
                    if hasattr(argument, key):
                        candidates.append(getattr(argument, key))
            for candidate in candidates:
                atom = _feature_atom(candidate, max_tokens=4)
                if atom:
                    return atom
            return _feature_atom(argument, max_tokens=4)

        source_anchors = self._source_role_anchors_for(sample)
        action_anchor = source_anchors.get("action", "")
        object_anchor = source_anchors.get("object", "")
        subject_anchor = source_anchors.get("subject", "")
        condition_anchor = source_anchors.get("condition", "")
        exception_anchor = source_anchors.get("exception", "")
        temporal_anchor = source_anchors.get("temporal", "")
        formulas = list(sample.modal_ir.formulas or [])
        bump("predicate-argument:bias", 0.75)
        bump(f"predicate-argument:formula-count:{_count_bucket(len(formulas))}", 0.4)
        if not formulas:
            bump("predicate-argument:no-formula", 0.75)
        for role_name, anchor in sorted(source_anchors.items()):
            bump(f"predicate-argument:source-role:{role_name}:{anchor}", 0.35)

        for formula in formulas[:6]:
            family = _feature_atom(formula.operator.family)
            system = _feature_atom(formula.operator.system)
            symbol = _feature_atom(formula.operator.symbol)
            predicate_name = _feature_atom(getattr(formula.predicate, "name", ""))
            predicate_role = _feature_atom(
                getattr(formula.predicate, "role", "") or "none"
            )
            arguments = list(getattr(formula.predicate, "arguments", []) or [])
            conditions = list(getattr(formula, "conditions", []) or [])
            exceptions = list(getattr(formula, "exceptions", []) or [])
            arity_bucket = _count_bucket(len(arguments))
            condition_bucket = _count_bucket(len(conditions))
            exception_bucket = _count_bucket(len(exceptions))

            if family:
                bump(f"predicate-argument:family:{family}", 0.45)
            if family and predicate_role:
                bump(f"predicate-argument:role:{family}:{predicate_role}", 1.0)
                bump(
                    f"predicate-argument:role-arity:{family}:{predicate_role}:{arity_bucket}",
                    1.0,
                )
                bump(
                    f"predicate-argument:role-shape:{family}:{predicate_role}:c{condition_bucket}:e{exception_bucket}",
                    0.8,
                )
            if family and system and symbol:
                bump(f"predicate-argument:operator:{family}:{system}:{symbol}", 0.7)
            if family and predicate_name:
                predicate_head = predicate_name.split("_", 1)[0]
                if predicate_head:
                    bump(
                        f"predicate-argument:predicate-head:{family}:{predicate_head}",
                        0.5,
                    )
                    if action_anchor:
                        bump(
                            f"predicate-argument:source-action-predicate:{action_anchor}:{predicate_head}",
                            0.65,
                        )
                    if object_anchor:
                        bump(
                            f"predicate-argument:source-object-predicate:{object_anchor}:{predicate_head}",
                            0.55,
                        )
            if family and action_anchor:
                bump(f"predicate-argument:source-action-family:{action_anchor}:{family}", 0.65)
                if predicate_role:
                    bump(
                        f"predicate-argument:source-action-role:{action_anchor}:{predicate_role}",
                        0.7,
                    )
            if family and object_anchor:
                bump(f"predicate-argument:source-object-family:{object_anchor}:{family}", 0.5)
                if predicate_role:
                    bump(
                        f"predicate-argument:source-object-role:{object_anchor}:{predicate_role}",
                        0.45,
                    )
            if family and subject_anchor and predicate_role:
                bump(
                    f"predicate-argument:source-subject-role:{subject_anchor}:{predicate_role}",
                    0.4,
                )
            if family and condition_anchor:
                bump(
                    f"predicate-argument:source-condition-family:{condition_anchor}:{family}",
                    0.35,
                )
            if family and exception_anchor:
                bump(
                    f"predicate-argument:source-exception-family:{exception_anchor}:{family}",
                    0.35,
                )
            if family and temporal_anchor:
                bump(
                    f"predicate-argument:source-temporal-family:{temporal_anchor}:{family}",
                    0.35,
                )
            if not arguments:
                bump(f"predicate-argument:no-arguments:{family or 'unknown'}", 0.5)
            for index, argument in enumerate(arguments[:4]):
                atom = argument_atom(argument)
                if not atom:
                    continue
                position = f"arg{index}"
                bump(
                    f"predicate-argument:position:{family}:{predicate_role}:{position}:{atom}",
                    0.8,
                )
                bump(f"predicate-argument:argument:{family}:{atom}", 0.45)
                if predicate_role:
                    bump(
                        f"predicate-argument:role-argument:{predicate_role}:{atom}",
                        0.55,
                    )
                if index > 0:
                    previous = argument_atom(arguments[index - 1])
                    if previous:
                        bump(
                            f"predicate-argument:argument-transition:{previous}->{atom}",
                            0.35,
                        )
            if conditions:
                bump(f"predicate-argument:conditioned-role:{family}:{predicate_role}", 0.7)
            if exceptions:
                bump(f"predicate-argument:excepted-role:{family}:{predicate_role}", 0.7)

        frame_logic = getattr(sample.modal_ir, "frame_logic", None)
        if frame_logic is not None:
            triples = list(getattr(frame_logic, "triples", []) or [])
            bump(f"predicate-argument:kg-triples:{_count_bucket(len(triples))}", 0.35)
            for triple in triples[:6]:
                predicate = _feature_atom(getattr(triple, "predicate", ""))
                subject = _feature_atom(getattr(triple, "subject", ""))
                obj = _feature_atom(getattr(triple, "object", ""))
                if predicate:
                    bump(f"predicate-argument:kg-predicate:{predicate}", 0.3)
                if predicate and subject:
                    bump(f"predicate-argument:kg-subject:{predicate}:{subject}", 0.25)
                if predicate and obj:
                    bump(f"predicate-argument:kg-object:{predicate}:{obj}", 0.25)

        result = _normalized_distribution(counts)
        cache["predicate_argument_distribution"] = dict(result)
        return result

    def _family_semantic_slot_distribution_for_embedding(
        self,
        sample: LegalSample,
        *,
        use_sample_memory: bool,
    ) -> Dict[str, float]:
        if self.family_semantic_slot_embedding_weight_scale <= 0.0:
            return {}
        return _joint_distribution(
            self._family_distribution_for_semantic_slot_embedding(
                sample,
                use_sample_memory=use_sample_memory,
            ),
            self._semantic_slot_distribution_for(sample),
            key_fn=_family_semantic_slot_key,
        )

    def _target_family_semantic_slot_distribution_for_sample(
        self,
        sample: LegalSample,
    ) -> Dict[str, float]:
        if self.family_semantic_slot_embedding_weight_scale <= 0.0:
            return {}
        return _joint_distribution(
            self._target_family_distribution_for_semantic_slot_embedding(sample),
            self._semantic_slot_distribution_for(sample),
            key_fn=_family_semantic_slot_key,
        )

    def _semantic_slot_legal_ir_view_distribution_for_embedding(
        self,
        sample: LegalSample,
        *,
        use_sample_memory: bool,
    ) -> Dict[str, float]:
        if (
            self.semantic_slot_legal_ir_view_embedding_weight_scale <= 0.0
            and self.semantic_slot_legal_ir_view_family_logit_scale <= 0.0
        ):
            return {}
        return _joint_distribution(
            self._semantic_slot_distribution_for(sample),
            self._legal_ir_view_distribution_for_embedding(
                sample,
                use_sample_memory=use_sample_memory,
            ),
            key_fn=_semantic_slot_legal_ir_view_key,
        )

    def _target_semantic_slot_legal_ir_view_distribution_for_sample(
        self,
        sample: LegalSample,
    ) -> Dict[str, float]:
        if (
            self.semantic_slot_legal_ir_view_embedding_weight_scale <= 0.0
            and self.semantic_slot_legal_ir_view_family_logit_scale <= 0.0
        ):
            return {}
        return _joint_distribution(
            self._semantic_slot_distribution_for(sample),
            self._legal_ir_view_target_distribution_for_sample(sample),
            key_fn=_semantic_slot_legal_ir_view_key,
        )

    def _family_semantic_slot_distribution_for_legal_ir_view(
        self,
        sample: LegalSample,
    ) -> Dict[str, float]:
        if self.family_semantic_slot_legal_ir_view_logit_scale <= 0.0:
            return {}
        return _joint_distribution(
            self._target_family_distribution_for_semantic_slot_embedding(sample),
            self._semantic_slot_distribution_for(sample),
            key_fn=_family_semantic_slot_key,
        )

    def _family_semantic_slot_legal_ir_view_distribution_for_embedding(
        self,
        sample: LegalSample,
        *,
        use_sample_memory: bool,
    ) -> Dict[str, float]:
        if self.family_semantic_slot_legal_ir_view_embedding_weight_scale <= 0.0:
            return {}
        return _triple_distribution(
            self._family_distribution_for_semantic_slot_embedding(
                sample,
                use_sample_memory=use_sample_memory,
            ),
            self._semantic_slot_distribution_for(sample),
            self._legal_ir_view_distribution_for_embedding(
                sample,
                use_sample_memory=use_sample_memory,
            ),
            key_fn=_family_semantic_slot_legal_ir_view_key,
        )

    def _target_family_semantic_slot_legal_ir_view_distribution_for_sample(
        self,
        sample: LegalSample,
    ) -> Dict[str, float]:
        if self.family_semantic_slot_legal_ir_view_embedding_weight_scale <= 0.0:
            return {}
        return _triple_distribution(
            self._target_family_distribution_for_semantic_slot_embedding(sample),
            self._semantic_slot_distribution_for(sample),
            self._legal_ir_view_target_distribution_for_sample(sample),
            key_fn=_family_semantic_slot_legal_ir_view_key,
        )

    def _family_legal_ir_view_distribution_for_embedding(
        self,
        sample: LegalSample,
        *,
        use_sample_memory: bool,
    ) -> Dict[str, float]:
        if self.family_legal_ir_view_embedding_weight_scale <= 0.0:
            return {}
        family_distribution = self._family_distribution_for_embedding(
            sample,
            use_sample_memory=use_sample_memory,
        )
        view_distribution = self._legal_ir_view_distribution_for_embedding(
            sample,
            use_sample_memory=use_sample_memory,
        )
        return _joint_distribution(
            family_distribution,
            view_distribution,
            key_fn=_family_legal_ir_view_key,
        )

    def _target_family_legal_ir_view_distribution_for_sample(
        self,
        sample: LegalSample,
    ) -> Dict[str, float]:
        if self.family_legal_ir_view_embedding_weight_scale <= 0.0:
            return {}
        return _joint_distribution(
            _observed_family_distribution(sample),
            self._legal_ir_view_target_distribution_for_sample(sample),
            key_fn=_family_legal_ir_view_key,
        )

    def _family_distribution_for_embedding(
        self,
        sample: LegalSample,
        *,
        use_sample_memory: bool,
    ) -> Dict[str, float]:
        """Gate decoder embedding heads with compiled IR families.

        Family logits are still evaluated by the classifier loss.  The decoder
        heads are trained from observed modal IR families, so cold-start
        reconstruction should use the same family space instead of routing
        reusable semantic-slot weights through a possibly wrong classifier.
        """
        observed = _observed_family_distribution(sample)
        if observed:
            return observed
        return self._family_distribution(sample, use_sample_memory=use_sample_memory)

    def _family_distribution_for_semantic_slot_embedding(
        self,
        sample: LegalSample,
        *,
        use_sample_memory: bool,
    ) -> Dict[str, float]:
        """Return family gates for semantic-slot reconstruction heads.

        A frame formula can carry typed decompiler slots such as
        ``frame->deontic`` or ``frame->conditional_normative``.  The classifier
        should still learn from the observed source family, but the embedding
        heads need target-family gates so reusable decompiler features transfer
        to the LegalIR view that reconstructs the slot.
        """
        return self._semantic_slot_projected_family_distribution(
            sample,
            base_distribution=self._family_distribution_for_embedding(
                sample,
                use_sample_memory=use_sample_memory,
            ),
        )

    def _target_family_distribution_for_semantic_slot_embedding(
        self,
        sample: LegalSample,
    ) -> Dict[str, float]:
        return self._semantic_slot_projected_family_distribution(
            sample,
            base_distribution=_observed_family_distribution(sample),
        )

    def _semantic_slot_projected_family_distribution(
        self,
        sample: LegalSample,
        *,
        base_distribution: Mapping[str, float],
    ) -> Dict[str, float]:
        base = {
            str(family): max(0.0, float(weight))
            for family, weight in dict(base_distribution or {}).items()
            if max(0.0, float(weight)) > 0.0
        }
        slots = self._semantic_slot_distribution_for(sample)
        if not slots:
            return _normalized_distribution(base)

        counts: Dict[str, float] = dict(base)
        for slot, slot_weight in slots.items():
            weight = max(0.0, float(slot_weight))
            if weight <= 0.0 or "typed-decompiler" not in str(slot):
                continue
            slot_text = str(slot)
            if "typed-decompiler-target-reconstruction" in slot_text:
                weight *= 6.0
            elif "typed-decompiler-family-pair" in slot_text:
                weight *= 2.5
            for source_family, target_family in re.findall(
                r"\b([a-z][a-z0-9_]*)->([a-z][a-z0-9_]*)\b",
                slot_text,
            ):
                is_cross_family = source_family != target_family
                if is_cross_family and source_family != "frame":
                    continue
                if source_family and is_cross_family:
                    counts[source_family] = counts.get(source_family, 0.0) + (
                        weight * 0.10
                    )
                if target_family:
                    target_weight = weight if is_cross_family else weight * 0.20
                    counts[target_family] = (
                        counts.get(target_family, 0.0) + target_weight
                    )
        return _normalized_distribution(counts)

    def _is_legal_ir_view_family(self, family: str) -> bool:
        return str(family) not in self.modal_families

    def _legal_ir_view_family_candidates(self) -> tuple[str, ...]:
        cached = self._legal_ir_view_family_candidates_cache
        if cached is not None:
            return cached

        families: List[str] = []
        seen: set[str] = set()

        def add(value: Any) -> None:
            family = str(value)
            if family in seen or not self._is_legal_ir_view_family(family):
                return
            seen.add(family)
            families.append(family)

        for view in self.state.legal_ir_view_embedding_weights.keys():
            add(view)
        for key in self.state.family_legal_ir_view_embedding_weights.keys():
            parts = str(key).split("||")
            if len(parts) == 2:
                add(parts[1])
        for key in self.state.semantic_slot_legal_ir_view_embedding_weights.keys():
            parts = str(key).split("||")
            if len(parts) == 2:
                add(parts[1])
        for key in self.state.family_semantic_slot_legal_ir_view_embedding_weights.keys():
            parts = str(key).split("||")
            if len(parts) == 3:
                add(parts[2])
        for view in self.state.legal_ir_view_logits.keys():
            add(view)
        for logits_by_key in (
            self.state.feature_legal_ir_view_logits,
            self.state.feature_family_logits,
            self.state.semantic_slot_legal_ir_view_logits,
            self.state.logic_signature_legal_ir_view_logits,
            self.state.round_trip_signal_legal_ir_view_logits,
            self.state.decompiler_plan_legal_ir_view_logits,
            self.state.predicate_argument_legal_ir_view_logits,
            self.state.family_semantic_slot_legal_ir_view_logits,
        ):
            for logits in logits_by_key.values():
                for family in logits.keys():
                    add(family)

        cached = tuple(families)
        self._legal_ir_view_family_candidates_cache = cached
        return cached

    def _invalidate_legal_ir_view_family_candidates(self) -> None:
        self._legal_ir_view_family_candidates_cache = None

    def _legal_ir_view_logits_for(
        self,
        sample: LegalSample,
        families: Sequence[str],
        *,
        use_sample_memory: bool,
    ) -> Dict[str, float]:
        """Return logits from the dedicated LegalIR view head."""
        logits = {
            str(family): float(self.state.legal_ir_view_logits.get(str(family), 0.0))
            * self.legal_ir_view_logit_scale
            for family in families
        }
        feature_keys = self._legal_ir_view_feature_keys_for(sample)
        feature_scale = 1.0 / self._feature_activity_scale(
            self._learned_feature_activity_count(
                sample,
                feature_keys,
                self.state.feature_legal_ir_view_logits,
                self.state.feature_family_logits,
            )
        )
        for feature in feature_keys:
            for family, value in self.state.feature_legal_ir_view_logits.get(feature, {}).items():
                family = str(family)
                if family in logits:
                    logits[family] += (
                        float(value)
                        * self.legal_ir_view_logit_scale
                        * feature_scale
                    )
            # Backwards compatibility: older warm-starts stored LegalIR view
            # logits in the modal feature bucket, where the default modal scale
            # is zero.  Read those legal-view entries through the dedicated
            # scale so prior useful work remains visible.
            for family, value in self.state.feature_family_logits.get(feature, {}).items():
                family = str(family)
                if family in logits and self._is_legal_ir_view_family(family):
                    logits[family] += (
                        float(value)
                        * self.legal_ir_view_logit_scale
                        * feature_scale
                    )
        for slot, slot_weight in self._semantic_slot_distribution_for(sample).items():
            for family, value in self.state.semantic_slot_legal_ir_view_logits.get(slot, {}).items():
                family = str(family)
                if family in logits and self._is_legal_ir_view_family(family):
                    logits[family] += (
                        float(value)
                        * float(slot_weight)
                        * self.semantic_slot_legal_ir_view_logit_scale
                    )
        if self.logic_signature_legal_ir_view_logit_scale > 0.0:
            for signature, signature_weight in (
                self._logic_signature_distribution_for(sample).items()
            ):
                normalized_weight = max(0.0, float(signature_weight))
                if normalized_weight <= 0.0:
                    continue
                for family, value in (
                    self.state.logic_signature_legal_ir_view_logits.get(
                        signature,
                        {},
                    ).items()
                ):
                    family = str(family)
                    if family in logits and self._is_legal_ir_view_family(family):
                        logits[family] += (
                            float(value)
                            * normalized_weight
                            * self.logic_signature_legal_ir_view_logit_scale
                        )
        if self.round_trip_signal_legal_ir_view_logit_scale > 0.0:
            for signal, signal_weight in (
                self._round_trip_signal_distribution_for(sample).items()
            ):
                normalized_weight = max(0.0, float(signal_weight))
                if normalized_weight <= 0.0:
                    continue
                for family, value in (
                    self.state.round_trip_signal_legal_ir_view_logits.get(
                        signal,
                        {},
                    ).items()
                ):
                    family = str(family)
                    if family in logits and self._is_legal_ir_view_family(family):
                        logits[family] += (
                            float(value)
                            * normalized_weight
                            * self.round_trip_signal_legal_ir_view_logit_scale
                        )
        if self.decompiler_plan_legal_ir_view_logit_scale > 0.0:
            for plan, plan_weight in (
                self._decompiler_plan_distribution_for(sample).items()
            ):
                normalized_weight = max(0.0, float(plan_weight))
                if normalized_weight <= 0.0:
                    continue
                for family, value in (
                    self.state.decompiler_plan_legal_ir_view_logits.get(
                        plan,
                        {},
                    ).items()
                ):
                    family = str(family)
                    if family in logits and self._is_legal_ir_view_family(family):
                        logits[family] += (
                            float(value)
                            * normalized_weight
                            * self.decompiler_plan_legal_ir_view_logit_scale
                        )
        if self.predicate_argument_legal_ir_view_logit_scale > 0.0:
            for signature, signature_weight in (
                self._predicate_argument_distribution_for(sample).items()
            ):
                normalized_weight = max(0.0, float(signature_weight))
                if normalized_weight <= 0.0:
                    continue
                for family, value in (
                    self.state.predicate_argument_legal_ir_view_logits.get(
                        signature,
                        {},
                    ).items()
                ):
                    family = str(family)
                    if family in logits and self._is_legal_ir_view_family(family):
                        logits[family] += (
                            float(value)
                            * normalized_weight
                            * self.predicate_argument_legal_ir_view_logit_scale
                        )
        if self.family_semantic_slot_legal_ir_view_logit_scale > 0.0:
            for key, pair_weight in (
                self._family_semantic_slot_distribution_for_legal_ir_view(sample).items()
            ):
                normalized_weight = max(0.0, float(pair_weight))
                if normalized_weight <= 0.0:
                    continue
                for family, value in (
                    self.state.family_semantic_slot_legal_ir_view_logits.get(
                        key,
                        {},
                    ).items()
                ):
                    family = str(family)
                    if family in logits and self._is_legal_ir_view_family(family):
                        logits[family] += (
                            float(value)
                            * normalized_weight
                            * self.family_semantic_slot_legal_ir_view_logit_scale
                        )
        if use_sample_memory:
            for family, value in self.state.family_logits.get(sample.sample_id, {}).items():
                family = str(family)
                if family in logits and self._is_legal_ir_view_family(family):
                    logits[family] += float(value)
        return self._clip_logits(logits)

    def _apply_legal_ir_view_family_logits(
        self,
        sample: LegalSample,
        logits: Dict[str, float],
        *,
        use_sample_memory: bool,
    ) -> None:
        if self.legal_ir_view_family_logit_scale <= 0.0:
            view_distribution: Dict[str, float] = {}
        else:
            view_distribution = self._legal_ir_view_distribution_for_embedding(
                sample,
                use_sample_memory=use_sample_memory,
            )
            for view, view_weight in view_distribution.items():
                normalized_weight = max(0.0, float(view_weight))
                if normalized_weight <= 0.0:
                    continue
                for family, value in self.state.legal_ir_view_family_logits.get(view, {}).items():
                    family = str(family)
                    if family in logits:
                        logits[family] += (
                            float(value)
                            * normalized_weight
                            * self.legal_ir_view_family_logit_scale
                        )
        if self.semantic_slot_legal_ir_view_family_logit_scale <= 0.0:
            return
        for key, pair_weight in self._semantic_slot_legal_ir_view_distribution_for_embedding(
            sample,
            use_sample_memory=use_sample_memory,
        ).items():
            normalized_weight = max(0.0, float(pair_weight))
            if normalized_weight <= 0.0:
                continue
            for family, value in self.state.semantic_slot_legal_ir_view_family_logits.get(key, {}).items():
                family = str(family)
                if family in logits:
                    logits[family] += (
                        float(value)
                        * normalized_weight
                        * self.semantic_slot_legal_ir_view_family_logit_scale
                    )

