def _uscode_surface_profile_modal_families(profile: str) -> tuple[str, ...]:
    """Return modal families implied by a stable U.S. Code surface profile."""
    return _USCODE_SURFACE_PROFILE_MODAL_FAMILIES.get(str(profile), ())


def _uscode_surface_profile_legal_ir_view_weights(
    profile: str,
) -> Mapping[str, float]:
    """Return LegalIR views implied by a stable U.S. Code surface profile."""
    return _USCODE_SURFACE_PROFILE_LEGAL_IR_VIEW_WEIGHTS.get(str(profile), {})


def _legal_ir_surface_profile_view_distribution(text: str) -> Dict[str, float]:
    """Return a LegalIR-view prior from sparse U.S. Code surface profiles."""
    scores: Dict[str, float] = {}

    def bump(view: str, weight: float) -> None:
        normalized_weight = max(0.0, float(weight))
        if not view or normalized_weight <= 0.0:
            return
        scores[view] = scores.get(view, 0.0) + normalized_weight

    for profile in _uscode_surface_profile_tags(text):
        for view, weight in _uscode_surface_profile_legal_ir_view_weights(
            profile
        ).items():
            bump(view, weight)
        for family in _uscode_surface_profile_modal_families(profile):
            for view in _AUTOENCODER_FAMILY_LEGAL_IR_VIEW_TARGETS.get(family, ()):
                bump(view, 0.08)
    return _normalized_distribution(scores)


def _feature_atom(value: Any, *, max_tokens: int = 4) -> str:
    tokens = _TOKEN_RE.findall(str(value or "").lower())
    if max_tokens > 0:
        tokens = tokens[:max_tokens]
    return "_".join(tokens)


def _semantic_slot_kind(slot: str) -> str:
    value = str(slot or "")
    if value.startswith("slot-pair:"):
        return "slot-pair"
    if value.startswith("slot:"):
        value = value[len("slot:") :]
    return value.split(":", 1)[0]


def _token_ngram_features(
    tokens: Sequence[str],
    *,
    n: int,
    max_ngrams: int,
    prefix: str,
) -> List[str]:
    if n <= 1 or max_ngrams <= 0 or len(tokens) < n:
        return []
    values: List[str] = []
    for index in range(0, len(tokens) - n + 1):
        values.append(f"{prefix}:{'_'.join(tokens[index:index + n])}")
        if len(values) >= max_ngrams:
            break
    return values


def _section_prefix(section: str) -> str:
    return str(section or "").split(".", 1)[0].split("-", 1)[0].split("(", 1)[0]


def _count_bucket(value: int) -> str:
    count = max(0, int(value))
    if count <= 0:
        return "0"
    if count == 1:
        return "1"
    if count <= 3:
        return "2-3"
    if count <= 7:
        return "4-7"
    if count <= 15:
        return "8-15"
    if count <= 31:
        return "16-31"
    return "32+"


def _quality_loss_bucket(value: float) -> str:
    loss = max(0.0, _float_or_zero(value))
    if loss <= 0.0:
        return "0"
    if loss <= 0.01:
        return "tiny"
    if loss <= 0.05:
        return "small"
    if loss <= 0.2:
        return "medium"
    if loss <= 1.0:
        return "large"
    return "huge"


def _ratio_bucket(value: float) -> str:
    ratio = min(1.0, max(0.0, _float_or_zero(value)))
    if ratio <= 0.0:
        return "0"
    if ratio <= 0.01:
        return "tiny"
    if ratio <= 0.05:
        return "small"
    if ratio <= 0.15:
        return "medium"
    if ratio <= 0.35:
        return "large"
    if ratio <= 0.65:
        return "high"
    return "very-high"


def _unique_preserve_order(values: Iterable[str]) -> List[str]:
    seen: set[str] = set()
    result: List[str] = []
    for value in values:
        if not value or value in seen:
            continue
        seen.add(value)
        result.append(value)
    return result


def _hash_text(text: str) -> str:
    return hashlib.sha256(text.encode("utf-8")).hexdigest()


def _hash_json(value: Any) -> str:
    payload = json.dumps(value, ensure_ascii=True, sort_keys=True, separators=(",", ":"))
    return hashlib.sha256(payload.encode("utf-8")).hexdigest()


