def _trusted_guidance_mapping(value: Any) -> Dict[str, Any]:
    if isinstance(value, Mapping):
        return {str(key): child for key, child in value.items()}
    to_dict = getattr(value, "to_dict", None)
    if callable(to_dict):
        try:
            converted = to_dict()
        except (TypeError, ValueError):
            return {}
        if isinstance(converted, Mapping):
            return {str(key): child for key, child in converted.items()}
    return {}


def _trusted_guidance_sequence(value: Any) -> List[Any]:
    if value is None:
        return []
    if isinstance(value, Mapping):
        return [value]
    if isinstance(value, Sequence) and not isinstance(
        value,
        (bytes, bytearray, str),
    ):
        return list(value)
    if isinstance(value, str):
        return [item.strip() for item in value.split(",") if item.strip()]
    return [value]


def _trusted_guidance_bool(value: Any) -> Optional[bool]:
    if isinstance(value, bool):
        return value
    if isinstance(value, (int, float)) and not isinstance(value, bool):
        if float(value) == 1.0:
            return True
        if float(value) == 0.0:
            return False
        return None
    text = str(value or "").strip().lower()
    if text in {"1", "accepted", "proved", "true", "trusted", "verified", "yes"}:
        return True
    if text in {"0", "false", "no", "rejected", "untrusted"}:
        return False
    return None


def _trusted_guidance_is_trusted(item: Mapping[str, Any]) -> bool:
    """Require affirmative trust evidence and honor every explicit rejection."""

    rejected_keys = (
        "copy_source_span_rejected",
        "copied_source_span_rejected",
        "draft_rejected",
        "rejected",
        "source_copy_rejected",
    )
    nested_rejections = _trusted_guidance_keyed_values(
        item,
        frozenset(rejected_keys),
    )
    if any(_trusted_guidance_bool(value) is True for value in nested_rejections):
        return False
    if (
        "accepted" in item
        and _trusted_guidance_bool(item.get("accepted")) is False
    ) or (
        "trusted" in item
        and _trusted_guidance_bool(item.get("trusted")) is False
    ):
        return False
    rejection_reasons = {
        _feature_atom(value, max_tokens=6)
        for value in _trusted_guidance_keyed_values(
            item,
            frozenset({"rejection_reason", "rejection_reasons"}),
        )
    }
    if rejection_reasons & {
        "copied_source_span",
        "drafted_logic_candidate_copies_source",
        "source_copy",
        "source_copy_rejected",
    }:
        return False
    return any(
        _trusted_guidance_bool(item.get(key)) is True
        for key in (
            "accepted",
            "trusted",
            "leanstral_verified",
            "verified",
            "proof_checked",
        )
    )


def _trusted_guidance_excluded_field_paths(
    value: Any,
    *,
    prefix: str = "",
    depth: int = 0,
) -> List[str]:
    if depth > 5:
        return []
    excluded: List[str] = []
    if isinstance(value, Mapping):
        for raw_key, child in sorted(value.items(), key=lambda pair: str(pair[0])):
            key = str(raw_key)
            lowered = key.lower()
            path = f"{prefix}.{key}" if prefix else key
            is_hash = lowered.endswith(("_hash", "_sha256", "_hashes"))
            if (
                lowered in _TRUSTED_GUIDANCE_FORBIDDEN_TEXT_KEYS
                or ("source_span" in lowered and not is_hash)
                or lowered.endswith(("_source_text", "_proof_text"))
            ):
                excluded.append(path)
                continue
            excluded.extend(
                _trusted_guidance_excluded_field_paths(
                    child,
                    prefix=path,
                    depth=depth + 1,
                )
            )
    elif isinstance(value, Sequence) and not isinstance(
        value,
        (bytes, bytearray, str),
    ):
        for index, child in enumerate(value[:64]):
            path = f"{prefix}[{index}]" if prefix else f"[{index}]"
            excluded.extend(
                _trusted_guidance_excluded_field_paths(
                    child,
                    prefix=path,
                    depth=depth + 1,
                )
            )
    return _unique_preserve_order(excluded)[:64]


def _trusted_guidance_keyed_values(
    value: Any,
    keys: frozenset[str],
    *,
    depth: int = 0,
) -> List[Any]:
    """Collect only named categorical fields under strict traversal bounds."""

    if depth > 5:
        return []
    values: List[Any] = []
    if isinstance(value, Mapping):
        ordered_items = sorted(value.items(), key=lambda pair: str(pair[0]))
        # Prefer the artifact's direct categorical claims.  Deep metadata is
        # useful fallback evidence but cannot crowd out a canonical top-level
        # contract or status by supplying a long nested list.
        for raw_key, child in ordered_items:
            key = str(raw_key).lower()
            if key in keys:
                values.extend(_trusted_guidance_sequence(child))
            if len(values) >= 64:
                return values[:64]
        for raw_key, child in ordered_items:
            key = str(raw_key).lower()
            if key not in _TRUSTED_GUIDANCE_FORBIDDEN_TEXT_KEYS:
                values.extend(
                    _trusted_guidance_keyed_values(child, keys, depth=depth + 1)
                )
            if len(values) >= 64:
                return values[:64]
    elif isinstance(value, Sequence) and not isinstance(
        value,
        (bytes, bytearray, str),
    ):
        for child in value[:64]:
            values.extend(
                _trusted_guidance_keyed_values(child, keys, depth=depth + 1)
            )
            if len(values) >= 64:
                return values[:64]
    return values[:64]


def _trusted_guidance_contracts() -> tuple[Any, ...]:
    """Load canonical contracts lazily to keep the baseline import lightweight."""

    try:
        from ...logic.integration.reasoning.legal_ir_view_contracts import (
            legal_ir_view_contracts,
        )

        return tuple(legal_ir_view_contracts())
    except (ImportError, RuntimeError):
        return ()


def _trusted_guidance_contract_lookup(
    contracts: Sequence[Any],
) -> Dict[str, Any]:
    lookup: Dict[str, Any] = {}
    for contract in contracts:
        names = (
            getattr(contract, "contract_id", ""),
            getattr(getattr(contract, "view", None), "value", ""),
            getattr(contract, "target_component", ""),
            *tuple(getattr(contract, "aliases", ()) or ()),
        )
        for name in names:
            atom = _feature_atom(name, max_tokens=10)
            if atom:
                lookup[atom] = contract
    return lookup


def _trusted_feature_atom(value: Any, *, max_tokens: int = 8) -> str:
    """Return an identifier atom with both token and byte-size bounds."""

    atom = _feature_atom(value, max_tokens=max_tokens)
    if len(atom) <= 96:
        return atom
    return f"{atom[:79]}_{_hash_text(atom)[:16]}"


def _trusted_guidance_identifier(value: Any, *, fallback: str) -> str:
    text = str(value or "").strip()
    if not text:
        return fallback
    if len(text) <= 128 and re.fullmatch(r"[A-Za-z0-9][A-Za-z0-9._:/-]*", text):
        return text
    return f"trusted-guidance-{_hash_text(text)[:24]}"


def build_trusted_hammer_leanstral_feature_bus(
    guidance: Any,
    *,
    require_trusted: bool = True,
) -> TrustedHammerLeanstralFeatureBus:
    """Project one guidance artifact into bounded categorical model features.

    Canonical LegalIR contracts supply the only accepted contract IDs,
    obligation families, target views, and repair lanes.  Unknown backend and
    reconstruction values collapse to ``other`` instead of creating an
    attacker-controlled feature vocabulary.
    """

    item = _trusted_guidance_mapping(guidance)
    trusted = bool(item) and _trusted_guidance_is_trusted(item)
    guidance_id = _trusted_guidance_identifier(
        item.get("guidance_id")
        or item.get("task_id")
        or item.get("leanstral_task_id")
        or item.get("modal_ir_hash"),
        fallback=f"trusted-guidance-{_hash_json(item)[:24]}",
    )
    excluded_paths = tuple(_trusted_guidance_excluded_field_paths(item))
    empty_families = {family: () for family in TRUSTED_HAMMER_FEATURE_FAMILIES}
    if not item or (require_trusted and not trusted):
        return TrustedHammerLeanstralFeatureBus(
            guidance_id=guidance_id,
            trusted=False,
            feature_families=empty_families,
            feature_keys=(),
            target_views=(),
            per_view_repair_labels={},
            excluded_field_paths=excluded_paths,
        )

    contracts = _trusted_guidance_contracts()
    contract_lookup = _trusted_guidance_contract_lookup(contracts)
    contract_candidates = _trusted_guidance_keyed_values(
        item,
        frozenset(
            {
                "contract_id",
                "contract_ids",
                "related_contract_ids",
                "source_contract_id",
            }
        ),
    )
    view_candidates = _trusted_guidance_keyed_values(
        item,
        frozenset(
            {
                "compiler_surface",
                "contract_view",
                "legal_ir_view",
                "premise_views",
                "related_views",
                "target_component",
                "target_view",
                "view",
            }
        ),
    )
    resolved_contracts: List[Any] = []
    for value in (*contract_candidates, *view_candidates):
        contract = contract_lookup.get(_feature_atom(value, max_tokens=10))
        if contract is not None and contract not in resolved_contracts:
            resolved_contracts.append(contract)
    resolved_contracts = resolved_contracts[
        :TRUSTED_HAMMER_FEATURE_BUS_MAX_VALUES_PER_FAMILY
    ]

    known_obligation_families = {
        str(family)
        for contract in contracts
        for family in tuple(getattr(contract, "all_obligation_families", ()) or ())
    }
    raw_obligation_families = _trusted_guidance_keyed_values(
        item,
        frozenset(
            {
                "obligation_family",
                "obligation_families",
                "obligation_kind",
                "proof_obligation_family",
            }
        ),
    )
    obligation_families = _unique_preserve_order(
        str(value).strip()
        for value in raw_obligation_families
        if str(value).strip() in known_obligation_families
    )[:TRUSTED_HAMMER_FEATURE_BUS_MAX_VALUES_PER_FAMILY]

    raw_premise_families = _trusted_guidance_keyed_values(
        item,
        frozenset(
            {
                "matched_obligation_families",
                "premise_families",
                "premise_family",
                "premise_hints",
                "premise_kind",
                "selected_premises",
            }
        ),
    )
    known_premise_families = known_obligation_families | set(
        _TRUSTED_GUIDANCE_PREMISE_KINDS
    )
    premise_families = _unique_preserve_order(
        str(value).strip()
        for value in raw_premise_families
        if str(value).strip() in known_premise_families
    )[:TRUSTED_HAMMER_FEATURE_BUS_MAX_VALUES_PER_FAMILY]

    backend_features: List[str] = []
    backend_status_maps = _trusted_guidance_keyed_values(
        item,
        frozenset({"backend_statuses"}),
    )
    for backend_statuses in backend_status_maps:
        if not isinstance(backend_statuses, Mapping):
            continue
        for backend, status in sorted(
            backend_statuses.items(), key=lambda pair: str(pair[0])
        ):
            backend_atom = _trusted_feature_atom(backend, max_tokens=2)
            status_atom = _trusted_feature_atom(status, max_tokens=3)
            if backend_atom not in _TRUSTED_GUIDANCE_BACKENDS:
                backend_atom = "other"
            if status_atom not in _TRUSTED_GUIDANCE_BACKEND_STATUSES:
                status_atom = "other"
            backend_features.append(f"{backend_atom}:{status_atom}")
    backend_features = _unique_preserve_order(backend_features)[
        :TRUSTED_HAMMER_FEATURE_BUS_MAX_VALUES_PER_FAMILY
    ]

    raw_reconstruction_statuses = _trusted_guidance_keyed_values(
        item,
        frozenset({"outcome", "reconstruction_outcome", "reconstruction_status"}),
    )
    reconstruction_statuses: List[str] = []
    for value in raw_reconstruction_statuses:
        status = _trusted_feature_atom(value, max_tokens=5)
        if not status:
            continue
        if status not in _TRUSTED_GUIDANCE_RECONSTRUCTION_STATUSES:
            status = "other"
        if status not in reconstruction_statuses:
            reconstruction_statuses.append(status)
    reconstruction_statuses = reconstruction_statuses[
        :TRUSTED_HAMMER_FEATURE_BUS_MAX_VALUES_PER_FAMILY
    ]

    raw_repair_labels = _trusted_guidance_keyed_values(
        item,
        frozenset(
            {
                "action",
                "repair_label",
                "repair_labels",
                "repair_lane",
                "repair_lanes",
            }
        ),
    )
    per_view_repairs: Dict[str, tuple[str, ...]] = {}
    repair_features: List[str] = []
    successful_reconstruction = bool(
        set(reconstruction_statuses)
        & {"backend_proof", "native_reconstruction", "script_generated", "verified"}
    ) or _trusted_guidance_bool(item.get("proof_checked")) is True
    failed_reconstruction = bool(
        set(reconstruction_statuses)
        & {
            "failed",
            "kernel_rejected",
            "native_reconstruction_failed",
            "reconstruction_failed",
            "translation_failure",
        }
    )
    for contract in resolved_contracts:
        view = str(getattr(contract, "target_component", "") or "").strip()
        allowed_lanes = tuple(getattr(contract, "allowed_repair_lanes", ()) or ())
        action_to_lane = {
            str(getattr(lane, "action", "")): str(getattr(lane, "lane_id", ""))
            for lane in tuple(getattr(contract, "repair_lanes", ()) or ())
        }
        labels = _unique_preserve_order(
            action_to_lane.get(str(value).strip(), str(value).strip())
            for value in raw_repair_labels
            if action_to_lane.get(str(value).strip(), str(value).strip())
            in allowed_lanes
        )
        if not labels and failed_reconstruction:
            labels = list(allowed_lanes)
        if not labels and successful_reconstruction:
            labels = ["no_repair"]
        labels = labels[:TRUSTED_HAMMER_FEATURE_BUS_MAX_VALUES_PER_FAMILY]
        if view and labels:
            per_view_repairs[view] = tuple(labels)
            repair_features.extend(f"{view}:{label}" for label in labels)

    family_values: Dict[str, tuple[str, ...]] = {
        "contract_id": tuple(
            str(getattr(contract, "contract_id", "")) for contract in resolved_contracts
        ),
        "obligation_family": tuple(obligation_families),
        "premise_family": tuple(premise_families),
        "backend_status": tuple(backend_features),
        "reconstruction_status": tuple(reconstruction_statuses),
        "repair_lane": tuple(
            repair_features[:TRUSTED_HAMMER_FEATURE_BUS_MAX_VALUES_PER_FAMILY]
        ),
    }

    feature_keys: List[str] = []
    prefixes = {
        "contract_id": "contract-id",
        "obligation_family": "obligation-family",
        "premise_family": "premise-family",
        "backend_status": "backend-status",
        "reconstruction_status": "reconstruction-status",
        "repair_lane": "repair-lane",
    }
    for family in TRUSTED_HAMMER_FEATURE_FAMILIES:
        for value in family_values[family]:
            if family in {"backend_status", "repair_lane"} and ":" in value:
                atoms = [
                    _trusted_feature_atom(part, max_tokens=8)
                    for part in value.split(":", 1)
                ]
                atom = ":".join(part for part in atoms if part)
            else:
                atom = _trusted_feature_atom(value, max_tokens=8)
            if atom:
                feature_keys.append(f"hammer:{prefixes[family]}:{atom}")
    feature_keys = _unique_preserve_order(feature_keys)[
        :TRUSTED_HAMMER_FEATURE_BUS_MAX_FEATURES
    ]

    target_views = _unique_preserve_order(
        str(getattr(contract, "target_component", "") or "").strip()
        for contract in resolved_contracts
    )[:TRUSTED_HAMMER_FEATURE_BUS_MAX_VALUES_PER_FAMILY]
    logic_families = _unique_preserve_order(
        _trusted_feature_atom(value, max_tokens=3)
        for value in _trusted_guidance_keyed_values(
            item,
            frozenset({"logic_family"}),
        )
        if _trusted_feature_atom(value, max_tokens=3)
        in _AUTOENCODER_FAMILY_LEGAL_IR_VIEW_TARGETS
    )[:TRUSTED_HAMMER_FEATURE_BUS_MAX_VALUES_PER_FAMILY]
    safe_backend_statuses = {
        value.split(":", 1)[0]: value.split(":", 1)[1]
        for value in backend_features
        if ":" in value
    }
    learning_payload: Dict[str, Any] = {
        "backend_statuses": safe_backend_statuses,
        "drafted_logic_candidates": [
            {
                "confidence": 1.0,
                "logic_family": family,
                "target_view": target_views[0] if target_views else "",
            }
            for family in logic_families
        ],
        "legal_ir_view": target_views[0] if target_views else "",
        "premise_views": list(target_views),
        "proof_checked": _trusted_guidance_bool(item.get("proof_checked")) is True,
        "proved": _trusted_guidance_bool(item.get("proved")) is True,
        "reconstruction_status": (
            reconstruction_statuses[0] if reconstruction_statuses else ""
        ),
        "target_component": target_views[0] if target_views else "",
        "target_view": target_views[0] if target_views else "",
    }
    if item.get("obligation_id") or item.get("proof_obligation_ids"):
        learning_payload["obligation_id"] = "present"

    return TrustedHammerLeanstralFeatureBus(
        guidance_id=guidance_id,
        trusted=trusted,
        feature_families=family_values,
        feature_keys=tuple(feature_keys),
        target_views=tuple(target_views),
        per_view_repair_labels=per_view_repairs,
        excluded_field_paths=excluded_paths,
        learning_payload=learning_payload,
    )


def trusted_hammer_leanstral_feature_bus(
    guidance: Any,
    *,
    require_trusted: bool = True,
) -> Dict[str, Any]:
    """Return the public dictionary representation of the trusted feature bus."""

    return build_trusted_hammer_leanstral_feature_bus(
        guidance,
        require_trusted=require_trusted,
    ).to_dict()


def _text_shape(text: str) -> str:
    tokens = _token_features(text)
    return "|".join(tokens[:12]) or "empty"


def _render_modal_formula(formula: Any) -> str:
    arguments = ", ".join(str(value) for value in getattr(formula.predicate, "arguments", []))
    predicate = str(formula.predicate.name)
    if arguments:
        predicate = f"{predicate}({arguments})"
    return f"{formula.operator.symbol}[{formula.operator.family}:{formula.operator.system}]({predicate})"


def _modal_formula_span_text(sample: LegalSample, formula: Any) -> str:
    start = max(0, int(getattr(formula.provenance, "start_char", 0)))
    end = max(start, int(getattr(formula.provenance, "end_char", 0)))
    return sample.normalized_text[start:end] or sample.normalized_text


def _codex_gate_local_loss(
    metrics: Mapping[str, float],
    gate: CodexCallGateConfig,
    *,
    prover_signal: Optional[ProverCompilationSignal],
) -> float:
    cosine_gap = max(0.0, 1.0 - float(metrics.get("embedding_cosine_similarity", 0.0)))
    cross_entropy_component = float(
        metrics.get("cross_entropy_excess_loss", metrics.get("cross_entropy_loss", 0.0))
    )
    loss = (
        gate.cosine_weight * cosine_gap
        + gate.cross_entropy_weight * max(0.0, cross_entropy_component)
        + gate.reconstruction_weight * max(0.0, float(metrics.get("reconstruction_loss", 0.0)))
        + gate.frame_weight * max(0.0, float(metrics.get("frame_ranking_loss", 0.0)))
        + gate.symbolic_weight * max(0.0, float(metrics.get("symbolic_validity_penalty", 0.0)))
    )
    legal_ir_view_component = float(
        metrics.get(
            "legal_ir_view_cross_entropy_excess_loss",
            metrics.get("legal_ir_view_cross_entropy_loss", 0.0),
        )
    )
    legal_ir_loss = (
        max(0.0, float(metrics.get("legal_ir_multiview_total_loss", 0.0)))
        + max(0.0, legal_ir_view_component)
        + max(0.0, float(metrics.get("legal_ir_multiview_proof_failure_ratio", 0.0)))
        + max(0.0, float(metrics.get("legal_ir_multiview_graph_failure_penalty", 0.0)))
    )
    loss += gate.legal_ir_weight * legal_ir_loss
    if gate.require_prover_compilation:
        if prover_signal is None:
            loss += gate.prover_weight
        else:
            loss += gate.prover_weight * prover_signal.failure_ratio
    return loss


def _bounded_proof_auxiliary_head_logits(value: Any) -> Dict[str, Dict[str, Dict[str, float]]]:
    """Load proof-head state while enforcing architecture cardinality bounds."""

    if not isinstance(value, Mapping):
        return {}
    result: Dict[str, Dict[str, Dict[str, float]]] = {}
    for head in PROOF_AUXILIARY_HEAD_NAMES:
        raw_contexts = value.get(head)
        if not isinstance(raw_contexts, Mapping):
            continue
        contexts: Dict[str, Dict[str, float]] = {}
        head_labels: set[str] = set()
        for raw_context, raw_logits in sorted(
            raw_contexts.items(),
            key=lambda item: str(item[0]),
        )[:PROOF_AUXILIARY_MAX_FAMILY_CONTEXTS]:
            if not isinstance(raw_logits, Mapping):
                continue
            context = _proof_auxiliary_family_context(str(raw_context))
            logits: Dict[str, float] = {}
            for raw_label, raw_value in sorted(
                raw_logits.items(),
                key=lambda item: str(item[0]),
            )[:PROOF_AUXILIARY_MAX_LABELS_PER_HEAD]:
                try:
                    number = float(raw_value)
                except (TypeError, ValueError):
                    continue
                if not math.isfinite(number):
                    continue
                label = _proof_auxiliary_label(str(raw_label))
                if (
                    label not in head_labels
                    and len(head_labels) >= PROOF_AUXILIARY_MAX_LABELS_PER_HEAD
                ):
                    continue
                head_labels.add(label)
                logits[label] = _clip_float(
                    number,
                    12.0,
                )
            if logits:
                contexts[context] = logits
        if contexts:
            result[head] = contexts
    return result


def _proof_auxiliary_label(value: Any) -> str:
    text = str(value or "unknown").strip()
    text = re.sub(r"[^A-Za-z0-9._:/@+|=\-]+", "_", text).strip("_")
    if not text:
        return "unknown"
    if len(text) <= 160:
        return text
    return f"sha256:{hashlib.sha256(text.encode('utf-8')).hexdigest()}"


def _proof_auxiliary_family_context(value: Any) -> str:
    text = str(value or "").strip()
    if text == PROOF_AUXILIARY_GLOBAL_CONTEXT:
        return text
    family = _legal_ir_view_family_name(text)
    return family if family in LEGAL_IR_VIEW_FAMILIES else "other"


def _proof_feedback_record_family(record: Any) -> str:
    legal_ir_view = str(getattr(record, "legal_ir_view", "") or "")
    semantic_family = str(getattr(record, "semantic_family", "") or "")
    family = _proof_auxiliary_family_context(legal_ir_view)
    if family == "other":
        family = _proof_auxiliary_family_context(semantic_family)
    return family


def _proof_auxiliary_targets(record: Any) -> Dict[str, tuple[str, ...]]:
    semantic_slots = dict(getattr(record, "semantic_slots", {}) or {})
    premises = tuple(getattr(record, "selected_premise_families", ()) or ())
    route_availability = dict(getattr(record, "route_availability", {}) or {})
    kernel = getattr(record, "kernel_reconstruction", None)
    contract = getattr(record, "minimal_failing_contract", None)

    slot_labels = tuple(
        f"{_proof_auxiliary_label(slot)}={_proof_auxiliary_label(state)}"
        for slot, state in sorted(semantic_slots.items(), key=lambda item: str(item[0]))
    ) or ("none",)
    premise_labels = tuple(
        _proof_auxiliary_label(value) for value in sorted(premises, key=str)
    ) or ("none",)
    route_labels = tuple(
        f"{_proof_auxiliary_label(route)}={'available' if bool(available) else 'unavailable'}"
        for route, available in sorted(
            route_availability.items(),
            key=lambda item: str(item[0]),
        )
    ) or ("none",)
    if bool(getattr(kernel, "verified", False)):
        reconstruction = "success"
    elif bool(getattr(kernel, "attempted", False)):
        reconstruction = "failure"
    else:
        reconstruction = "not_attempted"

    contract_labels: tuple[str, ...]
    if contract is None:
        contract_labels = ("none",)
    else:
        values = [
            f"contract:{_proof_auxiliary_label(getattr(contract, 'contract_id', 'unknown'))}",
            f"failure:{_proof_auxiliary_label(getattr(contract, 'failure_code', 'unknown'))}",
        ]
        values.extend(
            f"field:{_proof_auxiliary_label(field_name)}"
            for field_name in tuple(getattr(contract, "failing_fields", ()) or ())
        )
        contract_labels = tuple(_unique_preserve_order(values))

    training_label = getattr(record, "training_label", "unknown")
    trusted_outcome = str(getattr(training_label, "value", training_label) or "unknown")
    return {
        "obligation_family": (
            _proof_auxiliary_label(getattr(record, "obligation_type", "unknown")),
        ),
        "semantic_slots": slot_labels,
        "premise_family": premise_labels,
        "proof_route_availability": route_labels,
        "trusted_outcome": (_proof_auxiliary_label(trusted_outcome),),
        "reconstruction_success": (reconstruction,),
        "minimal_failing_contract": contract_labels,
    }


def _proof_feedback_expected_fingerprint(value: Any) -> str:
    if value is None:
        return ""
    if isinstance(value, str):
        return value.strip()
    for name in ("fingerprint", "version_fingerprint"):
        attribute = getattr(value, name, None)
        if attribute:
            return str(attribute)
    if isinstance(value, Mapping):
        explicit = value.get("version_fingerprint") or value.get("fingerprint")
        if explicit:
            return str(explicit)
        try:
            from ipfs_datasets_py.logic.integration.reasoning.legal_ir_proof_feedback import (
                ProofFeedbackVersions,
            )

            return ProofFeedbackVersions.from_dict(value).fingerprint
        except (KeyError, TypeError, ValueError):
            return ""
    return ""


def _validated_proof_feedback_records(
    feedback_records: Iterable[Any],
    *,
    expected_fingerprint: str,
    require_train_partition: bool,
) -> tuple[List[Any], Dict[str, int]]:
    from ipfs_datasets_py.logic.integration.reasoning.legal_ir_proof_feedback import (
        LegalIRProofFeedbackRecord,
        ProofFeedbackPartition,
    )

    raw_records = _proof_feedback_record_items(feedback_records)
    counters = {
        "candidate_count": len(raw_records),
        "eligible_before_version_count": 0,
        "skipped_holdout_count": 0,
        "skipped_invalid_count": 0,
        "skipped_untrusted_count": 0,
        "skipped_version_mismatch_count": 0,
    }
    accepted: List[Any] = []
    for raw_record in raw_records:
        try:
            if isinstance(raw_record, LegalIRProofFeedbackRecord):
                record = LegalIRProofFeedbackRecord.from_dict(raw_record.to_dict())
            elif isinstance(raw_record, Mapping):
                record = LegalIRProofFeedbackRecord.from_dict(raw_record)
            else:
                to_dict = getattr(raw_record, "to_dict", None)
                if not callable(to_dict):
                    raise TypeError("proof feedback must be a record or mapping")
                record = LegalIRProofFeedbackRecord.from_dict(to_dict())
        except (AttributeError, KeyError, TypeError, ValueError):
            counters["skipped_invalid_count"] += 1
            continue
        if not record.eligible_for_training:
            counters["skipped_untrusted_count"] += 1
            continue
        if require_train_partition and record.partition != ProofFeedbackPartition.TRAIN:
            counters["skipped_holdout_count"] += 1
            continue
        counters["eligible_before_version_count"] += 1
        if expected_fingerprint and record.version_fingerprint != expected_fingerprint:
            counters["skipped_version_mismatch_count"] += 1
            continue
        accepted.append(record)
    accepted.sort(key=lambda record: record.record_id)
    return accepted, counters


def _proof_feedback_record_items(value: Any) -> List[Any]:
    if value is None:
        return []
    if isinstance(value, Mapping) or hasattr(value, "record_id"):
        return [value]
    if isinstance(value, (str, bytes, bytearray)):
        return [value]
    try:
        return list(value)
    except TypeError:
        return [value]


def _proof_head_probabilities(
    autoencoder: AdaptiveModalAutoencoder,
    head: str,
    family: str,
    target_labels: Sequence[str],
) -> Dict[str, float]:
    logits = autoencoder._proof_auxiliary_logits(head, family)
    for label in target_labels:
        logits.setdefault(label, 0.0)
    labels = sorted(logits)[: autoencoder.proof_head_max_labels]
    logits = {label: logits[label] for label in labels}
    if head in PROOF_AUXILIARY_MULTILABEL_HEADS:
        return {label: _sigmoid(value) for label, value in logits.items()}
    return _softmax(logits)


def _proof_auxiliary_metrics(
    autoencoder: AdaptiveModalAutoencoder,
    records: Sequence[Any],
    *,
    abstention_threshold: Optional[float],
) -> Dict[str, Any]:
    threshold = (
        autoencoder.proof_head_abstention_threshold
        if abstention_threshold is None
        else max(0.0, min(1.0, float(abstention_threshold)))
    )
    observations: Dict[str, Dict[str, List[Dict[str, float]]]] = {}
    family_record_counts: Dict[str, int] = {}
    for record in records:
        family = _proof_feedback_record_family(record)
        family_record_counts[family] = family_record_counts.get(family, 0) + 1
        targets = _proof_auxiliary_targets(record)
        family_heads = observations.setdefault(family, {})
        for head, target_labels in targets.items():
            probabilities = _proof_head_probabilities(
                autoencoder,
                head,
                family,
                target_labels,
            )
            target_set = set(target_labels)
            if head in PROOF_AUXILIARY_MULTILABEL_HEADS:
                labels = sorted(set(probabilities) | target_set)
                per_label_losses: List[float] = []
                per_label_calibration: List[float] = []
                correct = True
                for label in labels:
                    target = 1.0 if label in target_set else 0.0
                    probability = min(
                        1.0 - 1e-12,
                        max(1e-12, float(probabilities.get(label, 0.5))),
                    )
                    per_label_losses.append(
                        -(target * math.log(probability)
                          + (1.0 - target) * math.log(1.0 - probability))
                    )
                    per_label_calibration.append((probability - target) ** 2)
                    correct = correct and ((probability >= 0.5) == bool(target))
                loss = _mean(per_label_losses)
                calibration = _mean(per_label_calibration)
                confidence = max(probabilities.values(), default=0.0)
            else:
                target = target_labels[0]
                probability = min(
                    1.0,
                    max(1e-12, float(probabilities.get(target, 0.0))),
                )
                loss = -math.log(probability)
                calibration = sum(
                    (
                        float(predicted_probability)
                        - (1.0 if label == target else 0.0)
                    )
                    ** 2
                    for label, predicted_probability in probabilities.items()
                ) / max(1, len(probabilities))
                predicted = (
                    max(probabilities, key=probabilities.get)
                    if probabilities
                    else None
                )
                correct = predicted == target
                confidence = max(probabilities.values(), default=0.0)
            abstained = confidence < threshold
            family_heads.setdefault(head, []).append(
                {
                    "abstained": 1.0 if abstained else 0.0,
                    "calibration": calibration,
                    "confidence": confidence,
                    "correct": 1.0 if correct else 0.0,
                    "loss": loss,
                }
            )

    by_family: Dict[str, Any] = {}
    all_rows: List[Dict[str, float]] = []
    aggregate_head_rows: Dict[str, List[Dict[str, float]]] = {
        head: [] for head in PROOF_AUXILIARY_HEAD_NAMES
    }
    for family, family_heads in sorted(observations.items()):
        head_metrics: Dict[str, Any] = {}
        family_rows: List[Dict[str, float]] = []
        for head in PROOF_AUXILIARY_HEAD_NAMES:
            rows = family_heads.get(head, [])
            family_rows.extend(rows)
            aggregate_head_rows[head].extend(rows)
            head_metrics[head] = _proof_metric_rows(rows)
        family_metrics = _proof_metric_rows(family_rows)
        family_metrics["heads"] = head_metrics
        family_metrics["record_count"] = family_record_counts.get(family, 0)
        by_family[family] = family_metrics
        all_rows.extend(family_rows)

    aggregate = _proof_metric_rows(all_rows)
    head_metrics = {
        head: _proof_metric_rows(rows)
        for head, rows in aggregate_head_rows.items()
    }
    return {
        **aggregate,
        "by_legal_ir_family": by_family,
        "calibration_by_family": {
            family: payload["calibration_error"]
            for family, payload in by_family.items()
        },
        "head_metrics": head_metrics,
        "per_family_loss": {
            family: payload["loss"]
            for family, payload in by_family.items()
        },
        "record_count": len(records),
    }


def _proof_metric_rows(rows: Sequence[Mapping[str, float]]) -> Dict[str, Any]:
    count = len(rows)
    abstention_rate = _mean([float(row["abstained"]) for row in rows])
    return {
        "abstention_rate": round(abstention_rate, 12),
        "accuracy": round(_mean([float(row["correct"]) for row in rows]), 12),
        "calibration_error": round(
            _mean([float(row["calibration"]) for row in rows]),
            12,
        ),
        "coverage": round(1.0 - abstention_rate if count else 0.0, 12),
        "loss": round(_mean([float(row["loss"]) for row in rows]), 12),
        "observation_count": count,
    }


def _proof_protected_objective_fingerprint(
    state: ModalAutoencoderTrainingState,
) -> str:
    payload = state.to_dict()
    for key in (
        "applied_proof_feedback_ids",
        "architecture_version",
        "proof_auxiliary_head_logits",
        "proof_auxiliary_head_schema_version",
        "proof_feedback_version_fingerprint",
        "schema_version",
    ):
        payload.pop(key, None)
    return _hash_json(payload)


def _sigmoid(value: float) -> float:
    number = float(value)
    if number >= 0.0:
        exponent = math.exp(-number)
        return 1.0 / (1.0 + exponent)
    exponent = math.exp(number)
    return exponent / (1.0 + exponent)


def _clip_float(value: float, absolute_limit: float) -> float:
    limit = max(0.0, float(absolute_limit))
    return max(-limit, min(limit, float(value)))


def _softmax(logits: Mapping[str, float]) -> Dict[str, float]:
    if not logits:
        return {}
    max_logit = max(float(value) for value in logits.values())
    exponentials = {
        name: math.exp(float(value) - max_logit)
        for name, value in logits.items()
    }
    total = sum(exponentials.values())
    if total == 0.0:
        uniform = 1.0 / len(exponentials)
        return {name: uniform for name in sorted(exponentials)}
    return {name: exponentials[name] / total for name in sorted(exponentials)}


def _clamp_learning_rate(value: float) -> float:
    return max(0.0, min(1.0, float(value)))


def _resolve_vector_compute_backend(
    compute_device: str,
) -> tuple[str, str, Any | None, Any | None]:
    request = str(compute_device or "auto").strip().lower()
    if request in {"", "auto"}:
        request = "auto"
    if request in {"python", "list", "lists", "none", "off"}:
        return request, "python", None, None

    try:
        import torch  # type: ignore[import-not-found]
    except Exception:
        return request, "python", None, None

    if request == "auto":
        enable_auto_cuda = str(
            os.environ.get("IPFS_DATASETS_MODAL_AUTOENCODER_AUTO_CUDA", "")
        ).strip().lower()
        if enable_auto_cuda in {"1", "true", "yes", "on"} and bool(
            torch.cuda.is_available()
        ):
            return request, "torch_cuda", torch.device("cuda"), torch
        return request, "python", None, None
    if request.startswith("cuda"):
        if bool(torch.cuda.is_available()):
            return request, "torch_cuda", torch.device(request), torch
        return request, "python_cuda_unavailable", None, None
    if request == "cpu":
        return request, "torch_cpu", torch.device("cpu"), torch
    return request, "python_unknown_device", None, None


def _mean(values: Sequence[float]) -> float:
    return sum(values) / len(values) if values else 0.0


def _sample_embedding_metric_rows(
    samples: Sequence[LegalSample],
    *,
    cosine_scores: Sequence[float],
    reconstruction_losses: Sequence[float],
    limit: int = 8,
) -> List[Dict[str, object]]:
    """Return the worst embedding residuals for diagnostics and TODO routing."""
    rows: List[Dict[str, object]] = []
    for sample, cosine, reconstruction in zip(
        samples,
        cosine_scores,
        reconstruction_losses,
    ):
        cosine_value = _float_or_zero(cosine)
        reconstruction_value = _float_or_zero(reconstruction)
        rows.append(
            {
                "citation": str(getattr(sample, "citation", "")),
                "cosine_loss": round(1.0 - cosine_value, 9),
                "cosine_similarity": round(cosine_value, 9),
                "reconstruction_loss": round(reconstruction_value, 9),
                "sample_id": str(sample.sample_id),
                "text_shape": _text_shape(str(getattr(sample, "normalized_text", ""))),
            }
        )
    rows.sort(
        key=lambda row: (
            float(row["cosine_similarity"]),
            -float(row["reconstruction_loss"]),
            str(row["sample_id"]),
        )
    )
    return rows[: max(0, int(limit))]


def _mean_distributions(
    distributions: Sequence[Mapping[str, float]],
) -> Dict[str, float]:
    values_by_name: Dict[str, List[float]] = {}
    for distribution in distributions:
        for name, value in dict(distribution or {}).items():
            values_by_name.setdefault(str(name), []).append(_float_or_zero(value))
    return {
        name: _mean(values)
        for name, values in sorted(values_by_name.items())
        if values
    }


def _float_or_zero(value: Any) -> float:
    try:
        return float(value)
    except (TypeError, ValueError):
        return 0.0


def _normalize_hammer_guidance_metric_item(item: Any) -> Dict[str, Any]:
    if item is None:
        return {}
    if hasattr(item, "to_dict") and callable(getattr(item, "to_dict")):
        try:
            item = item.to_dict()
        except (TypeError, ValueError):
            return {}
    if isinstance(item, Mapping):
        return {str(key): value for key, value in dict(item).items()}
    return {}


def _hammer_guidance_metric_items(value: Any) -> List[Mapping[str, Any]]:
    if value is None:
        return []
    normalized = _normalize_hammer_guidance_metric_item(value)
    if isinstance(value, Mapping) or normalized:
        source = normalized if normalized else dict(value)
        nested: List[Mapping[str, Any]] = []
        for key in (
            "artifacts",
            "hammer_guidance_artifacts",
            "verified_guidance",
            "leanstral_guidance",
            "guidance",
            "guidance_items",
            "items",
        ):
            if key in source:
                nested.extend(_hammer_guidance_metric_items(source.get(key)))
        candidate_results = source.get("candidate_results")
        if isinstance(candidate_results, Sequence) and not isinstance(
            candidate_results,
            (bytes, bytearray, str),
        ):
            for candidate_result in candidate_results:
                if not isinstance(candidate_result, Mapping):
                    continue
                nested.extend(
                    _hammer_guidance_metric_items(
                        candidate_result.get("verified_guidance")
                    )
                )
                nested.extend(
                    _hammer_guidance_metric_items(
                        candidate_result.get("hammer_guidance_artifacts")
                    )
                )
                hammer_report = candidate_result.get("hammer_report")
                if isinstance(hammer_report, Mapping):
                    nested.extend(
                        _hammer_guidance_metric_items(hammer_report.get("artifacts"))
                    )
        if nested:
            return nested
        if _is_hammer_guidance_metric_item(source):
            return [source]
        return []
    if isinstance(value, Sequence) and not isinstance(
        value,
        (bytes, bytearray, str),
    ):
        items: List[Mapping[str, Any]] = []
        for item in value:
            items.extend(_hammer_guidance_metric_items(item))
        return items
    return []


def _is_hammer_guidance_metric_item(item: Mapping[str, Any]) -> bool:
    source = str(item.get("source") or "").strip().lower()
    schema_version = str(item.get("schema_version") or "").strip().lower()
    return (
        source == "hammer_verified_guidance"
        or schema_version.startswith("legal-ir-hammer-")
        or bool(item.get("backend_statuses"))
        or bool(item.get("selected_premises"))
        or bool(item.get("reconstruction_status"))
        or "proof_checked" in item
        or "proved" in item
    )


def _hammer_guidance_truthy(value: Any) -> bool:
    if isinstance(value, bool):
        return value
    text = str(value or "").strip().lower()
    return text in {"1", "true", "yes", "y", "verified", "proved", "success"}


def _hammer_guidance_reconstruction_verified(item: Mapping[str, Any]) -> bool:
    if _hammer_guidance_truthy(item.get("proof_checked")):
        return True
    status = str(item.get("reconstruction_status") or "").strip().lower()
    return status in {"checked", "proof_checked", "reconstructed", "success", "verified"}


def _hammer_guidance_source_copy_rejected(item: Mapping[str, Any]) -> bool:
    for key in (
        "copy_source_span_rejected",
        "copied_source_span_rejected",
        "source_copy_rejected",
        "source_copy_penalty",
    ):
        value = item.get(key)
        if isinstance(value, (int, float)) and float(value) > 0.0:
            return True
        if _hammer_guidance_truthy(value):
            return True
    reasons = item.get("rejection_reasons")
    if isinstance(reasons, Sequence) and not isinstance(
        reasons,
        (bytes, bytearray, str),
    ):
        return any("copy" in str(reason).lower() for reason in reasons)
    return "copy" in str(item.get("failure_reason") or "").lower()


def _hammer_metric_view_key(value: Any) -> str:
    text = str(value or "").strip()
    return text or "unknown"


def _hammer_metric_suffix(value: Any) -> str:
    try:
        return _feature_atom(value, max_tokens=8) or "unknown"
    except NameError:
        return re.sub(r"[^a-z0-9]+", "_", str(value or "").lower()).strip("_") or "unknown"


def _hammer_metric_family_key(item: Mapping[str, Any]) -> str:
    """Resolve a guidance artifact through canonical view and contract aliases."""

    candidates: List[Any] = [
        item.get("legal_ir_view"),
        item.get("target_view"),
        item.get("contract_id"),
        item.get("target_component"),
        item.get("logic_family"),
    ]
    for key in ("contract_ids", "legal_ir_views", "premise_views", "target_views"):
        candidates.extend(_trusted_guidance_sequence(item.get(key)))
    for candidate in candidates:
        family = _legal_ir_view_family_name(str(candidate or ""))
        if family in LEGAL_IR_VIEW_FAMILIES:
            return family
    return "decompiler" if any(
        "decompil" in str(candidate or "").lower() for candidate in candidates
    ) else "other"


def hammer_guidance_metric_block(guidance: Any) -> Dict[str, Any]:
    """Return aggregate proof and guardrail metrics for hammer guidance artifacts."""

    items = _hammer_guidance_metric_items(guidance)
    artifact_count = len(items)
    proved_count = 0
    trusted_count = 0
    reconstruction_success_count = 0
    premise_hit_count = 0
    source_copy_rejected_count = 0
    backend_unavailable_count = 0
    view_counts: Dict[str, int] = {}
    view_proved: Dict[str, int] = {}
    view_trusted: Dict[str, int] = {}
    view_reconstructed: Dict[str, int] = {}
    view_source_copy_rejected: Dict[str, int] = {}
    family_counts: Dict[str, int] = {family: 0 for family in LEGAL_IR_VIEW_FAMILIES}
    family_proved: Dict[str, int] = {family: 0 for family in LEGAL_IR_VIEW_FAMILIES}
    family_trusted: Dict[str, int] = {family: 0 for family in LEGAL_IR_VIEW_FAMILIES}
    family_reconstructed: Dict[str, int] = {
        family: 0 for family in LEGAL_IR_VIEW_FAMILIES
    }
    family_source_copy_rejected: Dict[str, int] = {
        family: 0 for family in LEGAL_IR_VIEW_FAMILIES
    }
    for item in items:
        view = _hammer_metric_view_key(
            item.get("legal_ir_view")
            or item.get("target_view")
            or item.get("target_component")
        )
        family = _hammer_metric_family_key(item)
        view_counts[view] = view_counts.get(view, 0) + 1
        if family in family_counts:
            family_counts[family] += 1
        proved = _hammer_guidance_truthy(item.get("proved"))
        trusted = _hammer_guidance_truthy(item.get("trusted"))
        reconstructed = _hammer_guidance_reconstruction_verified(item)
        if proved:
            proved_count += 1
            view_proved[view] = view_proved.get(view, 0) + 1
            if family in family_proved:
                family_proved[family] += 1
        if trusted:
            trusted_count += 1
            view_trusted[view] = view_trusted.get(view, 0) + 1
            if family in family_trusted:
                family_trusted[family] += 1
        if reconstructed:
            reconstruction_success_count += 1
            view_reconstructed[view] = view_reconstructed.get(view, 0) + 1
            if family in family_reconstructed:
                family_reconstructed[family] += 1
        selected_premises = item.get("selected_premises")
        if isinstance(selected_premises, Sequence) and not isinstance(
            selected_premises,
            (bytes, bytearray, str),
        ) and any(str(premise).strip() for premise in selected_premises):
            premise_hit_count += 1
        if _hammer_guidance_source_copy_rejected(item):
            source_copy_rejected_count += 1
            view_source_copy_rejected[view] = (
                view_source_copy_rejected.get(view, 0) + 1
            )
            if family in family_source_copy_rejected:
                family_source_copy_rejected[family] += 1
        backend_statuses = item.get("backend_statuses")
        if isinstance(backend_statuses, Mapping):
            statuses = [
                str(status).strip().lower()
                for status in backend_statuses.values()
                if str(status).strip()
            ]
            if statuses and all(status == "unavailable" for status in statuses):
                backend_unavailable_count += 1

    denominator = max(1, artifact_count)
    proof_success_rate = proved_count / denominator
    trusted_success_rate = trusted_count / denominator
    reconstruction_success_rate = reconstruction_success_count / denominator
    premise_hit_rate = premise_hit_count / denominator
    source_copy_penalty = source_copy_rejected_count / denominator
    backend_unavailable_ratio = backend_unavailable_count / denominator
    symbolic_validity_success_rate = trusted_success_rate
    symbolic_validity_penalty_value = 1.0 - symbolic_validity_success_rate
    per_view: Dict[str, Dict[str, Any]] = {}
    numeric_view_metrics: Dict[str, float] = {}
    for view, count in sorted(view_counts.items()):
        view_denominator = max(1, count)
        proof_rate = view_proved.get(view, 0) / view_denominator
        trusted_rate = view_trusted.get(view, 0) / view_denominator
        reconstruction_rate = view_reconstructed.get(view, 0) / view_denominator
        suffix = _hammer_metric_suffix(view)
        per_view[view] = {
            "artifact_count": count,
            "hammer_proof_failure_ratio": round(1.0 - proof_rate, 12),
            "hammer_proof_success_rate": round(proof_rate, 12),
            "hammer_reconstruction_success_rate": round(reconstruction_rate, 12),
            "source_copy_penalty": round(
                view_source_copy_rejected.get(view, 0) / view_denominator,
                12,
            ),
            "symbolic_validity_penalty": round(1.0 - trusted_rate, 12),
            "symbolic_validity_success_rate": round(trusted_rate, 12),
        }
        numeric_view_metrics[f"hammer_{suffix}_proof_success_rate"] = proof_rate
        numeric_view_metrics[f"hammer_{suffix}_proof_failure_ratio"] = 1.0 - proof_rate
        numeric_view_metrics[f"symbolic_validity_{suffix}_success_rate"] = trusted_rate
        numeric_view_metrics[f"symbolic_validity_{suffix}_penalty"] = 1.0 - trusted_rate

    per_family: Dict[str, Dict[str, Any]] = {}
    numeric_family_metrics: Dict[str, float] = {}
    for family in LEGAL_IR_VIEW_FAMILIES:
        count = family_counts[family]
        family_denominator = max(1, count)
        proof_rate = family_proved[family] / family_denominator
        trusted_rate = family_trusted[family] / family_denominator
        reconstruction_rate = family_reconstructed[family] / family_denominator
        copy_penalty = family_source_copy_rejected[family] / family_denominator
        per_family[family] = {
            "artifact_count": count,
            "hammer_proof_success_rate": round(proof_rate, 12),
            "reconstruction_success_rate": round(reconstruction_rate, 12),
            "source_copy_penalty": round(copy_penalty, 12),
            "symbolic_validity_success_rate": round(trusted_rate, 12),
        }
        prefix = f"legal_ir_view_family_{family}"
        numeric_family_metrics[f"{prefix}_hammer_proof_success_rate"] = proof_rate
        numeric_family_metrics[f"{prefix}_reconstruction_success_rate"] = (
            reconstruction_rate
        )
        numeric_family_metrics[f"{prefix}_source_copy_penalty"] = copy_penalty
        numeric_family_metrics[f"{prefix}_symbolic_validity_success_rate"] = (
            trusted_rate
        )

    metrics: Dict[str, Any] = {
        "hammer_artifact_count": artifact_count,
        "hammer_backend_unavailable_count": backend_unavailable_count,
        "hammer_backend_unavailable_ratio": round(backend_unavailable_ratio, 12),
        "hammer_metric_group_count": 6,
        "hammer_premise_selection_hit_count": premise_hit_count,
        "hammer_premise_selection_hit_rate": round(premise_hit_rate, 12),
        "hammer_proof_failure_count": artifact_count - proved_count,
        "hammer_proof_failure_ratio": round(1.0 - proof_success_rate, 12),
        "hammer_proof_success_rate": round(proof_success_rate, 12),
        "hammer_proved_count": proved_count,
        "hammer_reconstruction_success_count": reconstruction_success_count,
        "hammer_reconstruction_success_rate": round(reconstruction_success_rate, 12),
        "hammer_source_copy_rejected_count": source_copy_rejected_count,
        "hammer_source_copy_penalty": round(source_copy_penalty, 12),
        "hammer_trusted_success_rate": round(trusted_success_rate, 12),
        "round_trip_reconstruction_success_rate": round(
            reconstruction_success_rate,
            12,
        ),
        "schema_version": HAMMER_GUIDANCE_METRIC_SCHEMA_VERSION,
        "source_copy_penalty": round(source_copy_penalty, 12),
        "symbolic_validity_by_view": per_view,
        "view_family_metrics": per_family,
        "symbolic_validity_penalty": round(symbolic_validity_penalty_value, 12),
        "symbolic_validity_success_rate": round(symbolic_validity_success_rate, 12),
        "trusted_hammer_guidance_count": trusted_count,
    }
    metrics.update(
        {key: round(value, 12) for key, value in sorted(numeric_view_metrics.items())}
    )
    metrics.update(
        {key: round(value, 12) for key, value in sorted(numeric_family_metrics.items())}
    )
    return metrics


def legal_ir_view_family_metric_block(
    ir_metrics: Optional[Mapping[str, Any]] = None,
    autoencoder_metrics: Optional[Any] = None,
    hammer_guidance: Any = None,
) -> Dict[str, Any]:
    """Join validation signals under the seven canonical LegalIR families.

    The returned shape is intentionally complete: every family and every
    required metric is present.  ``observed_metrics`` and the per-source counts
    distinguish an actual zero from a metric that was unavailable in a run.
    Flattened numeric aliases keep the block consumable by the existing metric
    gates and JSONL summaries.
    """

    by_family: Dict[str, Dict[str, Any]] = {
        family: {
            **{name: 0.0 for name in LEGAL_IR_VIEW_FAMILY_METRIC_NAMES},
            "artifact_count": 0,
            "sample_count": 0,
            "observed_metrics": [],
        }
        for family in LEGAL_IR_VIEW_FAMILIES
    }

    def observe(family: str, name: str, value: Any) -> None:
        canonical = _legal_ir_view_family_name(family)
        if canonical not in by_family or name not in LEGAL_IR_VIEW_FAMILY_METRIC_NAMES:
            return
        try:
            numeric = float(value)
        except (TypeError, ValueError):
            return
        if not math.isfinite(numeric):
            return
        if name == "source_copy_penalty" and name in by_family[canonical]["observed_metrics"]:
            numeric = max(numeric, float(by_family[canonical][name]))
        by_family[canonical][name] = round(max(0.0, numeric), 12)
        if name not in by_family[canonical]["observed_metrics"]:
            by_family[canonical]["observed_metrics"].append(name)

    def merge_nested(
        source: Mapping[str, Any],
        aliases: Mapping[str, str],
        *,
        count_key: str,
        require_positive_count: bool = False,
    ) -> None:
        nested = source.get("view_family_metrics")
        if not isinstance(nested, Mapping):
            nested = source.get("legal_ir_view_family_metrics")
        if not isinstance(nested, Mapping):
            return
        for raw_family, raw_metrics in nested.items():
            family = _legal_ir_view_family_name(str(raw_family))
            if family not in by_family or not isinstance(raw_metrics, Mapping):
                continue
            count = raw_metrics.get(count_key, raw_metrics.get("sample_count", 0))
            if require_positive_count:
                try:
                    if int(count or 0) <= 0:
                        continue
                except (TypeError, ValueError):
                    continue
            try:
                by_family[family][count_key] = max(
                    int(by_family[family].get(count_key, 0)), int(count or 0)
                )
            except (TypeError, ValueError):
                pass
            declared_observed = raw_metrics.get("observed_metrics")
            observed_names = (
                {str(name) for name in declared_observed}
                if isinstance(declared_observed, Sequence)
                and not isinstance(declared_observed, (bytes, bytearray, str))
                else None
            )
            for source_name, target_name in aliases.items():
                if observed_names is not None and not (
                    source_name in observed_names or target_name in observed_names
                ):
                    continue
                if source_name in raw_metrics:
                    observe(family, target_name, raw_metrics[source_name])

    ir_payload = dict(ir_metrics or {})
    merge_nested(
        ir_payload,
        {
            "ir_cross_entropy_loss": "ir_cross_entropy_loss",
            "cross_entropy_loss": "ir_cross_entropy_loss",
            "ir_cosine_similarity": "ir_cosine_similarity",
            "cosine_similarity": "ir_cosine_similarity",
            "symbolic_validity_success_rate": "symbolic_validity_success_rate",
            "reconstruction_success_rate": "reconstruction_success_rate",
            "source_copy_penalty": "source_copy_penalty",
            "source_copy_reward_hack_penalty": "source_copy_penalty",
        },
        count_key="sample_count",
    )
    # The deterministic codec is itself the canonical decompiler lane.  Older
    # metric blocks only have global fields, so preserve them under that family.
    if ir_payload and not isinstance(ir_payload.get("view_family_metrics"), Mapping):
        for source_name, target_name in (
            ("cross_entropy_loss", "ir_cross_entropy_loss"),
            ("cosine_similarity", "ir_cosine_similarity"),
            ("symbolic_validity_success_rate", "symbolic_validity_success_rate"),
            ("source_copy_reward_hack_penalty", "source_copy_penalty"),
            ("source_copy_penalty", "source_copy_penalty"),
        ):
            if source_name in ir_payload:
                observe("decompiler", target_name, ir_payload[source_name])
        by_family["decompiler"]["sample_count"] = int(
            ir_payload.get("evaluated_count", ir_payload.get("sample_count", 0)) or 0
        )

    if isinstance(autoencoder_metrics, AutoencoderEvaluation):
        auto_payload: Dict[str, Any] = {
            "legal_ir_view_family_metrics": {
                str(family): dict(metrics)
                for family, metrics in dict(
                    autoencoder_metrics.legal_ir_view_family_metrics or {}
                ).items()
            }
        }
        auto_losses = dict(autoencoder_metrics.legal_ir_losses or {})
        for family in LEGAL_IR_VIEW_FAMILIES:
            prefix = f"legal_ir_view_family_{family}"
            legacy_prefix = (
                "legal_ir_view_family_prover"
                if family == "external_provers"
                else prefix
            )
            ce = auto_losses.get(
                f"{prefix}_cross_entropy_loss",
                auto_losses.get(f"{legacy_prefix}_cross_entropy_loss"),
            )
            cosine_gap = auto_losses.get(
                f"{prefix}_cosine_gap_loss",
                auto_losses.get(f"{legacy_prefix}_cosine_gap_loss"),
            )
            family_values = auto_payload["legal_ir_view_family_metrics"].setdefault(
                family, {}
            )
            if ce is not None:
                family_values.setdefault("ir_cross_entropy_loss", ce)
            if cosine_gap is not None:
                family_values.setdefault(
                    "ir_cosine_similarity", max(0.0, 1.0 - float(cosine_gap))
                )
    elif isinstance(autoencoder_metrics, Mapping):
        auto_payload = dict(autoencoder_metrics)
    else:
        auto_payload = {}
    merge_nested(
        auto_payload,
        {
            "ir_cross_entropy_loss": "ir_cross_entropy_loss",
            "ir_cosine_similarity": "ir_cosine_similarity",
            "autoencoder_cross_entropy_loss": "autoencoder_cross_entropy_loss",
            "cross_entropy_loss": "autoencoder_cross_entropy_loss",
            "autoencoder_cosine_similarity": "autoencoder_cosine_similarity",
            "cosine_similarity": "autoencoder_cosine_similarity",
            "symbolic_validity_success_rate": "symbolic_validity_success_rate",
            "source_copy_penalty": "source_copy_penalty",
        },
        count_key="sample_count",
    )

    if isinstance(hammer_guidance, Mapping) and isinstance(
        hammer_guidance.get("view_family_metrics"), Mapping
    ):
        hammer_payload = dict(hammer_guidance)
    else:
        hammer_payload = hammer_guidance_metric_block(hammer_guidance)
    hammer_nested = hammer_payload.get("view_family_metrics")
    hammer_has_observations = int(
        hammer_payload.get("hammer_artifact_count", 0) or 0
    ) > 0 or (
        isinstance(hammer_nested, Mapping)
        and any(
            int(metrics.get("artifact_count", 0) or 0) > 0
            for metrics in hammer_nested.values()
            if isinstance(metrics, Mapping)
        )
    )
    if hammer_has_observations:
        merge_nested(
            hammer_payload,
            {
                "hammer_proof_success_rate": "hammer_proof_success_rate",
                "hammer_reconstruction_success_rate": "reconstruction_success_rate",
                "reconstruction_success_rate": "reconstruction_success_rate",
                "source_copy_penalty": "source_copy_penalty",
                "symbolic_validity_success_rate": "symbolic_validity_success_rate",
            },
            count_key="artifact_count",
            require_positive_count=True,
        )

    flat_metrics: Dict[str, float] = {}
    observed_family_scores: List[float] = []
    for family in LEGAL_IR_VIEW_FAMILIES:
        entry = by_family[family]
        entry["observed_metrics"] = sorted(entry["observed_metrics"])
        quality_components: List[float] = []
        for name in entry["observed_metrics"]:
            value = float(entry[name])
            if name.endswith("cross_entropy_loss"):
                quality_components.append(1.0 / (1.0 + value))
            elif name == "source_copy_penalty":
                quality_components.append(1.0 - min(1.0, value))
            else:
                quality_components.append(min(1.0, max(0.0, value)))
            flat_metrics[f"legal_ir_view_family_{family}_{name}"] = value
        score = sum(quality_components) / len(quality_components) if quality_components else 0.0
        entry["metric_coverage"] = round(
            len(entry["observed_metrics"]) / len(LEGAL_IR_VIEW_FAMILY_METRIC_NAMES),
            12,
        )
        entry["score"] = round(score, 12)
        entry["objective_loss"] = round(1.0 - score, 12) if quality_components else 0.0
        flat_metrics[f"legal_ir_view_family_{family}_score"] = score
        if quality_components:
            observed_family_scores.append(score)

    macro_score = (
        sum(observed_family_scores) / len(observed_family_scores)
        if observed_family_scores
        else 0.0
    )
    return {
        "families": list(LEGAL_IR_VIEW_FAMILIES),
        "family_count": len(LEGAL_IR_VIEW_FAMILIES),
        "flat_metrics": {
            name: round(value, 12) for name, value in sorted(flat_metrics.items())
        },
        "macro_objective_loss": round(1.0 - macro_score, 12)
        if observed_family_scores
        else 0.0,
        "macro_score": round(macro_score, 12),
        "metric_names": list(LEGAL_IR_VIEW_FAMILY_METRIC_NAMES),
        "schema_version": LEGAL_IR_VIEW_FAMILY_METRIC_SCHEMA_VERSION,
        "view_family_metrics": by_family,
    }


def _metric_higher_is_better(name: str) -> bool:
    normalized = str(name or "")
    return (
        normalized in {
            "hammer_premise_selection_hit_rate",
            "hammer_proof_success_rate",
            "hammer_reconstruction_success_rate",
            "hammer_trusted_success_rate",
            "round_trip_reconstruction_success_rate",
            "symbolic_validity_success_rate",
        }
        or normalized.endswith("_success_rate")
        or normalized.endswith("_similarity")
        or normalized.endswith("_score")
    ) and not normalized.endswith("_loss")


def _evaluation_improved_for_training(
    before: AutoencoderEvaluation,
    after: AutoencoderEvaluation,
    *,
    max_cosine_regression: float = 0.01,
    max_reconstruction_regression: float = 0.02,
    max_cross_entropy_regression: float = 0.0,
    max_legal_ir_loss_regression: float = 0.02,
    cross_entropy: float = 1.0,
    reconstruction: float = 1.0,
    cosine_gap: float = 1.0,
    legal_ir: float = 1.0,
) -> bool:
    """Return true when a feature update improves total loss without regressions."""
    if _evaluation_regressions_for_training(
        before,
        after,
        max_cosine_regression=max_cosine_regression,
        max_reconstruction_regression=max_reconstruction_regression,
        max_cross_entropy_regression=max_cross_entropy_regression,
        max_legal_ir_loss_regression=max_legal_ir_loss_regression,
    ):
        return False
    return (
        _evaluation_objective_for_training(
            after,
            cross_entropy=cross_entropy,
            reconstruction=reconstruction,
            cosine_gap=cosine_gap,
            legal_ir=legal_ir,
        )
        < _evaluation_objective_for_training(
            before,
            cross_entropy=cross_entropy,
            reconstruction=reconstruction,
            cosine_gap=cosine_gap,
            legal_ir=legal_ir,
        )
    )


def _evaluation_objective_for_training(
    evaluation: AutoencoderEvaluation,
    *,
    cross_entropy: float = 1.0,
    reconstruction: float = 1.0,
    cosine_gap: float = 1.0,
    legal_ir: float = 1.0,
) -> float:
    """Return a scalar objective where lower is better for guarded training."""
    cross_entropy_component = getattr(
        evaluation,
        "cross_entropy_excess_loss",
        evaluation.cross_entropy_loss,
    )
    if (
        cross_entropy_component <= 0.0
        and evaluation.cross_entropy_loss > 0.0
        and getattr(evaluation, "cross_entropy_entropy_loss", 0.0) <= 0.0
    ):
        cross_entropy_component = evaluation.cross_entropy_loss
    return (
        (max(0.0, float(cross_entropy)) * cross_entropy_component)
        + (max(0.0, float(reconstruction)) * evaluation.reconstruction_loss)
        + (
            max(0.0, float(cosine_gap))
            * max(0.0, 1.0 - evaluation.embedding_cosine_similarity)
        )
        + (
            max(0.0, float(legal_ir))
            * _legal_ir_objective_component(evaluation.legal_ir_losses)
        )
    )


def legal_ir_trainable_head_delta_norm_report(
    before: ModalAutoencoderTrainingState,
    after: ModalAutoencoderTrainingState,
    *,
    learning_rate: float,
) -> Dict[str, Any]:
    """Return finite gradient/update norms for trainable LegalIR heads.

    The optimizer stores trainable LegalIR parameters in sparse Python maps.
    This report intentionally compares state snapshots instead of relying on a
    backend-specific autograd object, so native, CUDA-resident, and guarded
    trusted-feedback paths expose the same accounting.
    """

    values_by_field: Dict[
        str,
        tuple[Mapping[tuple[str, ...], float], Mapping[tuple[str, ...], float]],
    ] = {}
    for field_name in LEGAL_IR_TRAINABLE_HEAD_FIELDS:
        values_by_field[field_name] = (
            _flatten_numeric_head_values(getattr(before, field_name, {})),
            _flatten_numeric_head_values(getattr(after, field_name, {})),
        )
    return _legal_ir_trainable_flat_delta_norm_report(
        values_by_field,
        learning_rate=learning_rate,
    )


def legal_ir_trainable_head_transaction_delta_norm_report(
    transaction: ModalAutoencoderStateTransaction,
    state: ModalAutoencoderTrainingState,
    *,
    learning_rate: float,
) -> Dict[str, Any]:
    """Return update norms from a transaction's sparse row journal."""

    if transaction.state is not state:
        raise StateTransactionConflictError(
            "update-norm transaction targets a different state object"
        )

    before_by_field: Dict[str, Dict[tuple[str, ...], float]] = {}
    after_by_field: Dict[str, Dict[tuple[str, ...], float]] = {}
    for row in transaction.iter_row_deltas():
        if row.component not in LEGAL_IR_TRAINABLE_HEAD_FIELDS:
            continue
        if row.before_exists:
            for path, value in _flatten_numeric_head_values(
                row.before_value
            ).items():
                before_by_field.setdefault(row.component, {})[
                    (str(row.key), *path)
                ] = value
        if row.after_exists:
            for path, value in _flatten_numeric_head_values(
                row.after_value
            ).items():
                after_by_field.setdefault(row.component, {})[
                    (str(row.key), *path)
                ] = value
    values_by_field = {
        field_name: (
            before_by_field.get(field_name, {}),
            after_by_field.get(field_name, {}),
        )
        for field_name in LEGAL_IR_TRAINABLE_HEAD_FIELDS
    }
    return _legal_ir_trainable_flat_delta_norm_report(
        values_by_field,
        learning_rate=learning_rate,
    )


def _legal_ir_trainable_flat_delta_norm_report(
    values_by_field: Mapping[
        str,
        tuple[Mapping[tuple[str, ...], float], Mapping[tuple[str, ...], float]],
    ],
    *,
    learning_rate: float,
) -> Dict[str, Any]:
    step = abs(float(learning_rate)) if math.isfinite(float(learning_rate)) else 0.0
    update_squares_by_head: Dict[str, float] = {}
    update_squares_by_head_family: Dict[str, float] = {}
    update_squares_by_family: Dict[str, float] = {}
    scalar_count_by_head: Dict[str, int] = {}
    finite = True

    for field_name, head_family in LEGAL_IR_TRAINABLE_HEAD_FIELDS.items():
        before_values, after_values = values_by_field.get(field_name, ({}, {}))
        for path in sorted(set(before_values) | set(after_values)):
            delta = float(after_values.get(path, 0.0)) - float(
                before_values.get(path, 0.0)
            )
            if not math.isfinite(delta):
                finite = False
                continue
            if abs(delta) <= 0.0:
                continue
            square = delta * delta
            family = _trainable_legal_ir_delta_family(field_name, path, head_family)
            update_squares_by_head[field_name] = (
                update_squares_by_head.get(field_name, 0.0) + square
            )
            update_squares_by_head_family[head_family] = (
                update_squares_by_head_family.get(head_family, 0.0) + square
            )
            update_squares_by_family[family] = (
                update_squares_by_family.get(family, 0.0) + square
            )
            scalar_count_by_head[field_name] = scalar_count_by_head.get(field_name, 0) + 1

    update_norms_by_head = _sqrt_norms(update_squares_by_head)
    update_norms_by_head_family = _sqrt_norms(update_squares_by_head_family)
    update_norms_by_family = _sqrt_norms(update_squares_by_family)
    gradient_norms_by_head = _gradient_norms(update_norms_by_head, step)
    gradient_norms_by_head_family = _gradient_norms(update_norms_by_head_family, step)
    gradient_norms_by_family = _gradient_norms(update_norms_by_family, step)
    total_update_norm = math.sqrt(sum(update_squares_by_head.values()))
    total_gradient_norm = total_update_norm / step if step > 0.0 else 0.0
    return {
        "finite": bool(finite),
        "gradient_norm": round(total_gradient_norm, 12),
        "gradient_norms_by_family": gradient_norms_by_family,
        "gradient_norms_by_head": gradient_norms_by_head,
        "head_family_gradient_norms": gradient_norms_by_head_family,
        "head_family_update_norms": update_norms_by_head_family,
        "learning_rate": float(learning_rate),
        "nonzero_gradient": bool(total_gradient_norm > 0.0),
        "nonzero_update": bool(total_update_norm > 0.0),
        "schema_version": LEGAL_IR_TRAINABLE_OBJECTIVE_NORM_SCHEMA_VERSION,
        "scalar_update_counts_by_head": dict(sorted(scalar_count_by_head.items())),
        "trainable_head_families": dict(sorted(LEGAL_IR_TRAINABLE_HEAD_FIELDS.items())),
        "update_norm": round(total_update_norm, 12),
        "update_norms_by_family": update_norms_by_family,
        "update_norms_by_head": update_norms_by_head,
    }


def _flatten_numeric_head_values(value: Any) -> Dict[tuple[str, ...], float]:
    flattened: Dict[tuple[str, ...], float] = {}

    def visit(child: Any, path: tuple[str, ...]) -> None:
        if isinstance(child, Mapping):
            for key, nested in child.items():
                visit(nested, (*path, str(key)))
            return
        if isinstance(child, Sequence) and not isinstance(child, (str, bytes, bytearray)):
            for index, nested in enumerate(child):
                visit(nested, (*path, str(index)))
            return
        if isinstance(child, (int, float)) and not isinstance(child, bool):
            number = float(child)
            flattened[path] = number if math.isfinite(number) else float("nan")

    visit(value, ())
    return flattened


def _sqrt_norms(squares: Mapping[str, float]) -> Dict[str, float]:
    return {
        name: round(math.sqrt(max(0.0, float(value))), 12)
        for name, value in sorted(squares.items())
    }


def _gradient_norms(update_norms: Mapping[str, float], step: float) -> Dict[str, float]:
    if step <= 0.0:
        return {name: 0.0 for name in sorted(update_norms)}
    return {
        name: round(float(value) / step, 12)
        for name, value in sorted(update_norms.items())
    }


def _trainable_legal_ir_delta_family(
    field_name: str,
    path: tuple[str, ...],
    head_family: str,
) -> str:
    if field_name == "proof_auxiliary_head_logits":
        if len(path) >= 2 and path[1] != PROOF_AUXILIARY_GLOBAL_CONTEXT:
            return _proof_auxiliary_family_context(path[1])
        return "proof"
    if "decompiler" in field_name:
        terminal = path[-1] if path else ""
        family = _legal_ir_view_family_name(terminal)
        return "decompiler" if family == "other" else family
    if field_name == "legal_ir_view_logits" and path:
        return _legal_ir_view_family_name(path[0])
    if "legal_ir_view" in field_name and path:
        family = _legal_ir_view_family_name(path[-1])
        if family != "other":
            return family
    if field_name.endswith("_family_logits") and path:
        family = str(path[-1])
        if family:
            return family
    return head_family


def _selected_objective_metric_values(
    evaluation: AutoencoderEvaluation,
    objective_weights: Mapping[str, float],
) -> Dict[str, float]:
    values: Dict[str, float] = {}
    if max(0.0, float(objective_weights.get("cross_entropy", 0.0))) > 0.0:
        values["cross_entropy_excess_loss"] = float(
            getattr(evaluation, "cross_entropy_excess_loss", evaluation.cross_entropy_loss)
        )
    if max(0.0, float(objective_weights.get("reconstruction", 0.0))) > 0.0:
        values["reconstruction_loss"] = float(evaluation.reconstruction_loss)
    if max(0.0, float(objective_weights.get("cosine_gap", 0.0))) > 0.0:
        values["embedding_cosine_gap"] = max(
            0.0,
            1.0 - float(evaluation.embedding_cosine_similarity),
        )
    if max(0.0, float(objective_weights.get("legal_ir", 0.0))) > 0.0:
        for name in _legal_ir_selected_metric_names(evaluation.legal_ir_losses):
            values[f"legal_ir:{name}"] = float(evaluation.legal_ir_losses.get(name, 0.0))
    return dict(sorted(values.items()))


def _selected_objective_metric_names(
    evaluation: AutoencoderEvaluation,
    objective_weights: Mapping[str, float],
) -> List[str]:
    return list(_selected_objective_metric_values(evaluation, objective_weights))


def _legal_ir_selected_metric_names(losses: Mapping[str, float]) -> List[str]:
    values = {str(name): float(value) for name, value in dict(losses or {}).items()}
    selected: List[str] = []
    for name in (
        "legal_ir_multiview_total_loss",
        "legal_ir_view_cross_entropy_excess_loss",
        "legal_ir_view_cross_entropy_loss",
        "legal_ir_view_family_cross_entropy_excess_loss",
        "legal_ir_view_family_cross_entropy_loss",
        "legal_ir_view_family_cosine_gap_loss",
        "legal_ir_multiview_proof_failure_ratio",
        "legal_ir_multiview_graph_failure_penalty",
        "legal_ir_grammar_invalid_production_penalty",
        "legal_ir_grammar_rejection_count",
        "legal_ir_grammar_rejection_ratio",
        "legal_ir_grammar_source_copy_placeholder_penalty",
        "hammer_proof_failure_ratio",
        "hammer_backend_unavailable_ratio",
        "hammer_source_copy_penalty",
        "round_trip_source_copy_guardrail_loss",
        "round_trip_structural_reconstruction_loss",
        "source_copy_penalty",
        "source_copy_reward_hack_penalty",
        "symbolic_validity_penalty",
    ):
        if name in values:
            selected.append(name)
    for family in LEGAL_IR_VIEW_FAMILIES:
        prefix = f"legal_ir_view_family_{family}_"
        for metric_name in LEGAL_IR_VIEW_FAMILY_METRIC_NAMES:
            key = f"{prefix}{metric_name}"
            if key in values:
                selected.append(key)
    for success_name in (
        "hammer_premise_selection_hit_rate",
        "hammer_proof_success_rate",
        "hammer_reconstruction_success_rate",
        "hammer_trusted_success_rate",
        "legal_ir_grammar_accepted",
        "legal_ir_grammar_syntactic_validity_success_rate",
        "round_trip_reconstruction_success_rate",
        "symbolic_validity_success_rate",
    ):
        if success_name in values:
            selected.append(success_name)
    for name in sorted(values):
        if name.startswith("legal_ir_grammar_rejection_reason_"):
            selected.append(name)
    return _unique_preserve_order(selected)


def _legal_ir_objective_component(losses: Mapping[str, float]) -> float:
    """Return a normalized LegalIR objective component.

    LegalIR exposes overlapping diagnostics: total loss, view cross entropy,
    proof ratios, graph penalties, and adapter-specific losses.  Summing every
    raw value lets one dense diagnostic swamp cosine/reconstruction.  This
    component keeps the important residuals visible while capping duplicate
    bridge detail.
    """
    values = {str(name): max(0.0, float(value)) for name, value in dict(losses).items()}
    if not values:
        return 0.0
    component = 0.0
    component += min(1.0, values.get("legal_ir_multiview_total_loss", 0.0))
    view_ce_component = values.get(
        "legal_ir_view_cross_entropy_excess_loss",
        values.get("legal_ir_view_cross_entropy_loss", 0.0),
    )
    component += min(1.0, view_ce_component / 3.0)
    view_family_component = values.get(
        "legal_ir_view_family_cross_entropy_excess_loss",
        values.get("legal_ir_view_family_cross_entropy_loss", 0.0),
    )
    component += min(1.0, view_family_component / 3.0)
    component += min(1.0, values.get("legal_ir_view_family_cosine_gap_loss", 0.0))
    component += min(1.0, values.get("legal_ir_multiview_proof_failure_ratio", 0.0))
    component += min(1.0, values.get("legal_ir_multiview_graph_failure_penalty", 0.0))
    component += min(1.0, values.get("legal_ir_grammar_invalid_production_penalty", 0.0))
    component += min(1.0, values.get("legal_ir_grammar_rejection_ratio", 0.0))
    component += min(1.0, values.get("legal_ir_grammar_source_copy_placeholder_penalty", 0.0))
    component += min(1.0, values.get("hammer_proof_failure_ratio", 0.0))
    component += min(1.0, values.get("hammer_backend_unavailable_ratio", 0.0))
    component += min(1.0, values.get("hammer_source_copy_penalty", 0.0))
    component += min(1.0, values.get("round_trip_source_copy_guardrail_loss", 0.0))
    component += min(1.0, values.get("round_trip_structural_reconstruction_loss", 0.0))
    component += min(1.0, values.get("source_copy_penalty", 0.0))
    component += min(1.0, values.get("source_copy_reward_hack_penalty", 0.0))
    component += min(1.0, values.get("symbolic_validity_penalty", 0.0))
    family_objective_values: Dict[str, List[float]] = {}
    for family in LEGAL_IR_VIEW_FAMILIES:
        prefix = f"legal_ir_view_family_{family}_"
        for metric_name in LEGAL_IR_VIEW_FAMILY_METRIC_NAMES:
            key = f"{prefix}{metric_name}"
            if key not in values:
                continue
            value = values[key]
            if metric_name.endswith("cross_entropy_loss"):
                objective_value = min(1.0, value / 3.0)
            elif metric_name == "source_copy_penalty":
                objective_value = min(1.0, value)
            else:
                objective_value = min(1.0, max(0.0, 1.0 - value))
            family_objective_values.setdefault(family, []).append(objective_value)
    if family_objective_values:
        component += sum(
            _mean(metric_values)
            for metric_values in family_objective_values.values()
            if metric_values
        ) / len(family_objective_values)
    for success_name in (
        "hammer_premise_selection_hit_rate",
        "hammer_proof_success_rate",
        "hammer_reconstruction_success_rate",
        "hammer_trusted_success_rate",
        "round_trip_reconstruction_success_rate",
        "symbolic_validity_success_rate",
    ):
        if success_name in values:
            component += min(1.0, max(0.0, 1.0 - values[success_name]))
    detail = 0.0
    for name, value in values.items():
        if any(
            name.startswith(f"legal_ir_view_family_{family}_")
            and (
                name.removeprefix(f"legal_ir_view_family_{family}_")
                in LEGAL_IR_VIEW_FAMILY_METRIC_NAMES
                or name.endswith(("_score", "_objective_loss"))
            )
            for family in LEGAL_IR_VIEW_FAMILIES
        ):
            continue
        if name in {
            "legal_ir_multiview_total_loss",
            "legal_ir_view_cross_entropy_loss",
            "legal_ir_view_entropy_loss",
            "legal_ir_view_cross_entropy_excess_loss",
            "legal_ir_view_family_cross_entropy_loss",
            "legal_ir_view_family_entropy_loss",
            "legal_ir_view_family_cross_entropy_excess_loss",
            "legal_ir_view_family_cosine_gap_loss",
            "legal_ir_multiview_proof_failure_ratio",
            "legal_ir_multiview_graph_failure_penalty",
            "legal_ir_grammar_invalid_production_penalty",
            "legal_ir_grammar_rejection_count",
            "legal_ir_grammar_rejection_ratio",
            "legal_ir_grammar_source_copy_placeholder_penalty",
            "hammer_backend_unavailable_ratio",
            "hammer_premise_selection_hit_rate",
            "hammer_proof_failure_ratio",
            "hammer_proof_success_rate",
            "hammer_reconstruction_success_rate",
            "hammer_source_copy_penalty",
            "hammer_trusted_success_rate",
            "round_trip_reconstruction_success_rate",
            "round_trip_source_copy_guardrail_loss",
            "round_trip_structural_reconstruction_loss",
            "source_copy_penalty",
            "source_copy_reward_hack_penalty",
            "symbolic_validity_penalty",
            "legal_ir_grammar_accepted",
            "legal_ir_grammar_syntactic_validity_success_rate",
            "symbolic_validity_success_rate",
        }:
            continue
        if name.endswith("_entropy_loss"):
            continue
        if name.startswith("legal_ir_view_family_") and name.endswith(
            "_cross_entropy_loss"
        ):
            continue
        if name.startswith("legal_ir_") or name.startswith(
            ("deontic_", "tdfol_", "cec_", "zkp_", "external_prover_")
        ):
            detail += min(0.25, value)
    return component + min(1.0, detail)


def _evaluation_regressions_for_training(
    before: AutoencoderEvaluation,
    after: AutoencoderEvaluation,
    *,
    max_cosine_regression: float = 0.01,
    max_reconstruction_regression: float = 0.02,
    max_cross_entropy_regression: float = 0.0,
    max_legal_ir_loss_regression: float = 0.02,
) -> Dict[str, float]:
    """Return metric regressions that exceed the guarded training tolerances."""
    regressions: Dict[str, float] = {}
    cosine_regression = (
        before.embedding_cosine_similarity - after.embedding_cosine_similarity
    )
    if cosine_regression > max(0.0, float(max_cosine_regression)):
        regressions["embedding_cosine_similarity"] = cosine_regression
    reconstruction_regression = after.reconstruction_loss - before.reconstruction_loss
    if reconstruction_regression > max(0.0, float(max_reconstruction_regression)):
        regressions["reconstruction_loss"] = reconstruction_regression
    before_ce = getattr(before, "cross_entropy_excess_loss", before.cross_entropy_loss)
    after_ce = getattr(after, "cross_entropy_excess_loss", after.cross_entropy_loss)
    if (
        before_ce <= 0.0
        and before.cross_entropy_loss > 0.0
        and getattr(before, "cross_entropy_entropy_loss", 0.0) <= 0.0
    ):
        before_ce = before.cross_entropy_loss
    if (
        after_ce <= 0.0
        and after.cross_entropy_loss > 0.0
        and getattr(after, "cross_entropy_entropy_loss", 0.0) <= 0.0
    ):
        after_ce = after.cross_entropy_loss
    cross_entropy_regression = after_ce - before_ce
    if cross_entropy_regression > max(0.0, float(max_cross_entropy_regression)):
        regressions["cross_entropy_excess_loss"] = cross_entropy_regression
    for name in sorted(set(before.legal_ir_losses) | set(after.legal_ir_losses)):
        regression = (
            (
                float(before.legal_ir_losses.get(name, 0.0))
                - float(after.legal_ir_losses.get(name, 0.0))
            )
            if _metric_higher_is_better(name)
            else (
                float(after.legal_ir_losses.get(name, 0.0))
                - float(before.legal_ir_losses.get(name, 0.0))
            )
        )
        if regression > max(0.0, float(max_legal_ir_loss_regression)):
            regressions[f"legal_ir:{name}"] = regression
    return regressions


def _projection_deadband_mode(value: str) -> str:
    mode = str(value or "off").strip().lower()
    return mode if mode in PROJECTION_DEADBAND_MODES else "off"


def _projection_prescreen_mode(value: str) -> str:
    mode = str(value or "off").strip().lower()
    return mode if mode in PROJECTION_PRESCREEN_MODES else "off"


def _annotate_projection_prescreen_rankings(
    attempt_reports: Sequence[MutableMapping[str, Any]],
    *,
    top_k: int,
) -> None:
    ranked: List[tuple[float, int, MutableMapping[str, Any], MutableMapping[str, Any]]] = []
    for index, report in enumerate(attempt_reports):
        prescreen = report.get("projection_prescreen")
        if not isinstance(prescreen, MutableMapping):
            continue
        if not bool(prescreen.get("enabled", False)):
            prescreen["selected_for_holdout"] = True
            continue
        objective_delta = _float_or_zero(prescreen.get("objective_delta"))
        ranked.append((objective_delta, index, report, prescreen))
    if not ranked:
        return
    ranked.sort(key=lambda item: (-item[0], item[1]))
    selected_limit = max(0, int(top_k or 0))
    for rank, (_score, _index, _report, prescreen) in enumerate(ranked, start=1):
        selected = selected_limit <= 0 or rank <= selected_limit
        prescreen["rank"] = rank
        prescreen["selected_for_holdout"] = bool(selected)
        prescreen["would_select_for_holdout"] = bool(selected)


def _projection_prescreen_summary(
    epoch_reports: Sequence[Mapping[str, Any]],
) -> Dict[str, Any]:
    attempted_count = 0
    enabled_attempt_count = 0
    selected_count = 0
    unselected_count = 0
    evaluated_holdout_count = 0
    positive_delta_count = 0
    best_prescreen: Optional[Dict[str, Any]] = None
    for epoch in epoch_reports:
        candidate_reports = epoch.get("candidate_reports")
        if not isinstance(candidate_reports, Sequence) or isinstance(
            candidate_reports,
            (str, bytes),
        ):
            continue
        for candidate in candidate_reports:
            if not isinstance(candidate, Mapping):
                continue
            attempt_reports = candidate.get("attempt_reports")
            if not isinstance(attempt_reports, Sequence) or isinstance(
                attempt_reports,
                (str, bytes),
            ):
                attempt_reports = [candidate]
            for attempt in attempt_reports:
                if not isinstance(attempt, Mapping):
                    continue
                attempted_count += 1
                prescreen = attempt.get("projection_prescreen")
                if not isinstance(prescreen, Mapping):
                    continue
                if not bool(prescreen.get("enabled", False)):
                    continue
                enabled_attempt_count += 1
                objective_delta = _float_or_zero(prescreen.get("objective_delta"))
                if objective_delta > 0.0:
                    positive_delta_count += 1
                if bool(prescreen.get("selected_for_holdout", True)):
                    selected_count += 1
                else:
                    unselected_count += 1
                if bool(attempt.get("holdout_evaluated", True)):
                    evaluated_holdout_count += 1
                if (
                    best_prescreen is None
                    or objective_delta > _float_or_zero(
                        best_prescreen.get("objective_delta")
                    )
                ):
                    best_prescreen = {
                        "line_search_multiplier": round(
                            _float_or_zero(attempt.get("line_search_multiplier")),
                            12,
                        ),
                        "objective_delta": round(objective_delta, 12),
                        "rank": int(prescreen.get("rank", 0) or 0),
                        "selected_for_holdout": bool(
                            prescreen.get("selected_for_holdout", True)
                        ),
                        "update": str(attempt.get("update") or ""),
                    }
    return {
        "attempted_count": attempted_count,
        "best_prescreen_attempt": best_prescreen or {},
        "enabled_attempt_count": enabled_attempt_count,
        "evaluated_holdout_count": evaluated_holdout_count,
        "positive_delta_count": positive_delta_count,
        "selected_for_holdout_count": selected_count,
        "unselected_for_holdout_count": unselected_count,
    }


def _projection_guardrail_names(values: Sequence[str] | str | None) -> tuple[str, ...]:
    if values is None:
        return PROJECTION_DEADBAND_DEFAULT_HARD_GUARDRAILS
    if isinstance(values, str):
        raw_values: Sequence[Any] = values.split(",")
    else:
        raw_values = values
    normalized = tuple(
        str(value).strip()
        for value in raw_values
        if str(value).strip()
    )
    return normalized or PROJECTION_DEADBAND_DEFAULT_HARD_GUARDRAILS


def _projection_metric_matches_guardrail(name: str, guardrail: str) -> bool:
    metric_name = str(name)
    guardrail_name = str(guardrail)
    if guardrail_name.endswith("*"):
        return metric_name.startswith(guardrail_name[:-1])
    return metric_name == guardrail_name


def _projection_deadband_decision(
    regressions: Mapping[str, float],
    *,
    objective_delta: float,
    mode: str = "off",
    max_ce_deadband: float = 0.0,
    hard_guardrail_metrics: Sequence[str] | str | None = None,
) -> Dict[str, Any]:
    """Return shadow/enforced acceptance metadata for tiny CE regressions."""

    normalized_mode = _projection_deadband_mode(mode)
    guardrails = _projection_guardrail_names(hard_guardrail_metrics)
    ce_deadband = max(0.0, float(max_ce_deadband or 0.0))
    adjusted_regressions: Dict[str, float] = {}
    tolerated_regressions: Dict[str, float] = {}
    hard_guardrail_blocked: Dict[str, float] = {}
    for name, raw_value in sorted(dict(regressions).items()):
        value = max(0.0, float(raw_value))
        is_hard_guardrail = any(
            _projection_metric_matches_guardrail(name, guardrail)
            for guardrail in guardrails
        )
        if (
            normalized_mode != "off"
            and not is_hard_guardrail
            and name in PROJECTION_DEADBAND_CE_REGRESSION_KEYS
            and value <= ce_deadband
        ):
            tolerated_regressions[str(name)] = value
            continue
        adjusted_regressions[str(name)] = value
        if is_hard_guardrail:
            hard_guardrail_blocked[str(name)] = value

    would_accept = bool(
        normalized_mode != "off"
        and float(objective_delta) > 0.0
        and tolerated_regressions
        and not adjusted_regressions
    )
    enforced_accepted = bool(normalized_mode == "enforce" and would_accept)
    return {
        "adjusted_pareto_regressions": adjusted_regressions,
        "enabled": normalized_mode != "off",
        "enforced_accepted": enforced_accepted,
        "hard_guardrail_blocked_regressions": hard_guardrail_blocked,
        "hard_guardrail_metrics": list(guardrails),
        "max_ce_deadband": ce_deadband,
        "mode": normalized_mode,
        "tolerated_regressions": tolerated_regressions,
        "would_accept": would_accept,
    }


def _projection_rejection_summary(
    epoch_reports: Sequence[Mapping[str, Any]],
) -> Dict[str, Any]:
    """Summarize why guarded projection attempts were not accepted."""
    attempted_count = 0
    accepted_attempt_count = 0
    deadband_enforced_accept_count = 0
    refinement_attempt_count = 0
    rejected_attempt_count = 0
    strict_accepted_attempt_count = 0
    deadband_would_accept_count = 0
    deadband_shadow_would_accept_count = 0
    regression_counts: Dict[str, int] = {}
    deadband_tolerated_counts: Dict[str, int] = {}
    deadband_hard_guardrail_counts: Dict[str, int] = {}
    best_rejected: Optional[Dict[str, Any]] = None
    best_deadband_would_accept: Optional[Dict[str, Any]] = None
    for epoch in epoch_reports:
        candidate_reports = epoch.get("candidate_reports")
        if not isinstance(candidate_reports, Sequence) or isinstance(
            candidate_reports,
            (str, bytes),
        ):
            continue
        for candidate in candidate_reports:
            if not isinstance(candidate, Mapping):
                continue
            attempt_reports = candidate.get("attempt_reports")
            if not isinstance(attempt_reports, Sequence) or isinstance(
                attempt_reports,
                (str, bytes),
            ):
                attempt_reports = [candidate]
            for attempt in attempt_reports:
                if not isinstance(attempt, Mapping):
                    continue
                attempted_count += 1
                if bool(attempt.get("line_search_refinement")):
                    refinement_attempt_count += 1
                accepted = bool(attempt.get("accepted"))
                if bool(attempt.get("strict_accepted")):
                    strict_accepted_attempt_count += 1
                deadband = attempt.get("projection_deadband")
                if isinstance(deadband, Mapping):
                    if bool(deadband.get("would_accept")):
                        deadband_would_accept_count += 1
                        if str(deadband.get("mode") or "") == "shadow":
                            deadband_shadow_would_accept_count += 1
                    if bool(deadband.get("enforced_accepted")):
                        deadband_enforced_accept_count += 1
                    tolerated = deadband.get("tolerated_regressions")
                    if isinstance(tolerated, Mapping):
                        for name in tolerated:
                            key = str(name)
                            deadband_tolerated_counts[key] = (
                                deadband_tolerated_counts.get(key, 0) + 1
                            )
                    blocked = deadband.get("hard_guardrail_blocked_regressions")
                    if isinstance(blocked, Mapping):
                        for name in blocked:
                            key = str(name)
                            deadband_hard_guardrail_counts[key] = (
                                deadband_hard_guardrail_counts.get(key, 0) + 1
                            )
                if accepted:
                    accepted_attempt_count += 1
                pareto_regressions = attempt.get("pareto_regressions")
                if isinstance(pareto_regressions, Mapping):
                    for name in pareto_regressions:
                        key = str(name)
                        if not accepted:
                            regression_counts[key] = regression_counts.get(key, 0) + 1
                objective_delta = _float_or_zero(attempt.get("objective_delta"))
                if (
                    isinstance(deadband, Mapping)
                    and bool(deadband.get("would_accept"))
                    and (
                        best_deadband_would_accept is None
                        or objective_delta
                        > _float_or_zero(
                            best_deadband_would_accept.get("objective_delta")
                        )
                    )
                ):
                    best_deadband_would_accept = {
                        "acceptance_source": str(
                            attempt.get("acceptance_source") or ""
                        ),
                        "cross_entropy_delta": round(
                            _float_or_zero(attempt.get("cross_entropy_delta")),
                            12,
                        ),
                        "effective_learning_rate": round(
                            _float_or_zero(attempt.get("effective_learning_rate")),
                            12,
                        ),
                        "line_search_multiplier": round(
                            _float_or_zero(attempt.get("line_search_multiplier")),
                            12,
                        ),
                        "objective_delta": round(objective_delta, 12),
                        "pareto_regressions": dict(pareto_regressions)
                        if isinstance(pareto_regressions, Mapping)
                        else {},
                        "projection_deadband": dict(deadband),
                        "update": str(attempt.get("update") or ""),
                    }
                if accepted:
                    continue
                rejected_attempt_count += 1
                if best_rejected is None or objective_delta > _float_or_zero(
                    best_rejected.get("objective_delta")
                ):
                    best_rejected = {
                        "cross_entropy_delta": round(
                            _float_or_zero(attempt.get("cross_entropy_delta")),
                            12,
                        ),
                        "effective_learning_rate": round(
                            _float_or_zero(attempt.get("effective_learning_rate")),
                            12,
                        ),
                        "legal_ir_view_cross_entropy_delta": round(
                            _float_or_zero(
                                attempt.get("legal_ir_view_cross_entropy_delta")
                            ),
                            12,
                        ),
                        "line_search_multiplier": round(
                            _float_or_zero(attempt.get("line_search_multiplier")),
                            12,
                        ),
                        "line_search_refinement": bool(
                            attempt.get("line_search_refinement")
                        ),
                        "objective_delta": round(objective_delta, 12),
                        "pareto_regressions": dict(pareto_regressions)
                        if isinstance(pareto_regressions, Mapping)
                        else {},
                        "reconstruction_delta": round(
                            _float_or_zero(attempt.get("reconstruction_delta")),
                            12,
                        ),
                        "update": str(attempt.get("update") or ""),
                    }
    return {
        "accepted_attempt_count": accepted_attempt_count,
        "attempted_count": attempted_count,
        "best_rejected_attempt": best_rejected or {},
        "projection_deadband": {
            "best_would_accept_attempt": best_deadband_would_accept or {},
            "enforced_accept_count": deadband_enforced_accept_count,
            "hard_guardrail_blocked_counts": dict(
                sorted(deadband_hard_guardrail_counts.items())
            ),
            "shadow_would_accept_count": deadband_shadow_would_accept_count,
            "strict_accepted_attempt_count": strict_accepted_attempt_count,
            "tolerated_regression_counts": dict(
                sorted(deadband_tolerated_counts.items())
            ),
            "would_accept_count": deadband_would_accept_count,
        },
        "pareto_regression_counts": dict(sorted(regression_counts.items())),
        "refinement_attempt_count": refinement_attempt_count,
        "rejected_attempt_count": rejected_attempt_count,
    }


def _vector_norm(values: Sequence[float]) -> float:
    return math.sqrt(sum(float(value) * float(value) for value in values))


def _max_abs_mapping(values: Mapping[str, float]) -> float:
    if not values:
        return 0.0
    return max(abs(float(value)) for value in values.values())


def _distribution_cosine_similarity(
    left: Mapping[str, float],
    right: Mapping[str, float],
) -> float:
    names = sorted(set(map(str, left.keys())) | set(map(str, right.keys())))
    if not names:
        return 0.0
    left_vector = [_float_or_zero(left.get(name, 0.0)) for name in names]
    right_vector = [_float_or_zero(right.get(name, 0.0)) for name in names]
    return cosine_similarity(left_vector, right_vector)


def _metric_delta(
    changed: Mapping[str, float],
    baseline: Mapping[str, float],
) -> Dict[str, float]:
    return {
        key: round(
            _float_or_zero(changed.get(key, 0.0))
            - _float_or_zero(baseline.get(key, 0.0)),
            12,
        )
        for key in sorted(set(changed) | set(baseline))
    }


def _directional_effect_from_delta(delta: Mapping[str, float]) -> Dict[str, Any]:
    objective_delta = (
        _float_or_zero(delta.get("compiler_ir_cross_entropy_excess_loss"))
        - _float_or_zero(delta.get("compiler_ir_cosine_similarity"))
        + _float_or_zero(delta.get("learned_view_cross_entropy_excess_loss"))
        - _float_or_zero(delta.get("learned_view_cosine_similarity"))
        + _float_or_zero(delta.get("decompiler_embedding_cosine_loss"))
        + _float_or_zero(delta.get("decompiler_token_loss"))
        + _float_or_zero(delta.get("formal_validity_penalty"))
    )
    return {
        "direction": "worsens_when_removed"
        if objective_delta > 0.0
        else "improves_or_neutral_when_removed",
        "objective_delta": round(objective_delta, 12),
        "supports_compiler_action": objective_delta > 0.0,
    }


def _feature_group_prefixes(group: str) -> tuple[str, ...]:
    if group == "compiler-contract":
        return ("compiler-contract:", "legal-ir:compiler-contract:", "quality:")
    if group == "decompiler-template":
        return ("decompiler-surface:", "decompiler-plan:", "legal-ir:decompiler-surface:")
    if group == "cycle-consistency":
        return ("cycle-consistency:", "round-trip:", "legal-ir:cycle-consistency:")
    if group == "semantic-slot":
        return (
            "semantic-slot:",
            "slot:",
            "legal-ir:semantic-slot:",
            "predicate-argument:",
        )
    if group == "logic-view":
        return ("logic-view-contract:", "legal-ir:", "legal-ir-view:", "signature:")
    return ()


def _remove_group_keys(
    mapping: MutableMapping[str, Any],
    *,
    prefixes: Sequence[str],
    keys: set[str],
) -> None:
    for key in list(mapping.keys()):
        key_text = str(key)
        if key_text in keys or any(key_text.startswith(prefix) for prefix in prefixes):
            mapping.pop(key, None)


def _minimal_pair_text_for_group(text: str, group: str) -> tuple[str, str]:
    source = str(text or "").strip()
    if not source:
        return source, "empty-text"
    replacements: Mapping[str, Sequence[tuple[str, str]]] = {
        "compiler-contract": (
            (r"\bshall not\b", "may"),
            (r"\bshall\b", "may"),
            (r"\bmust\b", "may"),
            (r"\bmay\b", "shall"),
        ),
        "decompiler-template": (
            (r"\bnotice\b", "written notice"),
            (r"\blicense\b", "authorization instrument"),
            (r"\brecords?\b", "official record"),
        ),
        "cycle-consistency": (
            (r"\bbefore\b", "after"),
            (r"\bafter\b", "before"),
            (r"\bwithin\b", "not later than"),
        ),
        "semantic-slot": (
            (r"\bagency\b", "Secretary"),
            (r"\bapplicant\b", "recipient"),
            (r"\bperson\b", "officer"),
        ),
        "logic-view": (
            (r"\bexcept as provided\b", "subject to"),
            (r"\bif\b", "unless"),
            (r"\bsubject to\b", "notwithstanding"),
        ),
    }
    for pattern, replacement in replacements.get(group, ()):
        changed = re.sub(pattern, replacement, source, count=1, flags=re.IGNORECASE)
        if changed != source:
            return changed, f"replace:{pattern}->{replacement}"
    suffixes = {
        "compiler-contract": " The agency may grant an exception.",
        "decompiler-template": " The decision must be stated in writing.",
        "cycle-consistency": " The action occurs before final notice.",
        "semantic-slot": " The Secretary records the applicant role.",
        "logic-view": " If the condition applies, the rule is subject to this section.",
    }
    return source + suffixes.get(group, ""), "append:legal-contrastive-cue"


_STABLE_LEGAL_IR_FEATURE_PREFIX_GROUPS: tuple[tuple[str, str], ...] = (
    ("hammer:contract-id:", "contract_id"),
    ("hammer:repair-lane:", "repair_lane"),
    ("compiler-contract:", "compiler_contract"),
    ("compiler-profile:", "compiler_contract"),
    ("decompiler-surface:", "decompiler_surface_template"),
    ("repair-plan:", "decompiler_surface_template"),
    ("cycle-consistency:", "cycle_consistency"),
    ("round-trip-bridge:", "cycle_consistency"),
    ("semantic-slot:", "semantic_slot"),
    ("logic-view-contract:", "logic_view_contract"),
    ("legal-ir-view:", "logic_view_contract"),
)
_STABLE_LEGAL_IR_FORBIDDEN_FEATURE_MARKERS = (
    "raw-source",
    "raw_source",
    "sample-memory",
    "sample_memory",
    "source-copy",
    "source-text",
    "source-span",
    "source_copy",
    "source_text",
    "source_span",
    "token:",
    "token2:",
    "token3:",
)


def _stable_legal_ir_feature_group(feature: Any) -> str:
    value = str(feature or "").strip()
    lowered = value.lower()
    if not value or len(value.encode("utf-8")) > 512:
        return ""
    if any(marker in lowered for marker in _STABLE_LEGAL_IR_FORBIDDEN_FEATURE_MARKERS):
        return ""
    for prefix, group in _STABLE_LEGAL_IR_FEATURE_PREFIX_GROUPS:
        if value.startswith(prefix):
            return group
    return ""


def _stable_legal_ir_numeric_magnitude(value: Any) -> float:
    if isinstance(value, Mapping):
        return max(
            (_stable_legal_ir_numeric_magnitude(child) for child in value.values()),
            default=0.0,
        )
    if isinstance(value, Sequence) and not isinstance(
        value, (str, bytes, bytearray)
    ):
        numeric = [_float_or_zero(child) for child in value]
        return _vector_norm(numeric)
    try:
        numeric_value = float(value)
    except (TypeError, ValueError):
        return 0.0
    return abs(numeric_value) if math.isfinite(numeric_value) else 0.0


def _stable_legal_ir_learned_feature_rows(
    state: ModalAutoencoderTrainingState,
) -> List[Dict[str, Any]]:
    """Return deterministic structural feature weights from shared heads only."""

    weights: Dict[str, float] = {}
    head_counts: Dict[str, int] = {}
    excluded_heads = {
        "applied_leanstral_guidance_ids",
        "applied_todo_ids",
        "decoded_embeddings",
        "family_logits",
        "legal_ir_view_logits",
    }
    for head_name, head in sorted(vars(state).items()):
        if head_name in excluded_heads or not isinstance(head, Mapping):
            continue
        for feature, value in sorted(head.items(), key=lambda item: str(item[0])):
            feature_name = str(feature)
            if not _stable_legal_ir_feature_group(feature_name):
                continue
            magnitude = _stable_legal_ir_numeric_magnitude(value)
            if magnitude <= 0.0:
                continue
            weights[feature_name] = weights.get(feature_name, 0.0) + magnitude
            head_counts[feature_name] = head_counts.get(feature_name, 0) + 1
    rows = [
        {
            "feature": feature,
            "feature_group": _stable_legal_ir_feature_group(feature),
            "source_head_count": head_counts[feature],
            "weight": round(weight, 12),
        }
        for feature, weight in weights.items()
    ]
    rows.sort(key=lambda row: (-float(row["weight"]), str(row["feature"])))
    return rows


def _stable_legal_ir_feature_keys_for_autoencoder_sample(
    autoencoder: AdaptiveModalAutoencoder,
    sample: LegalSample,
) -> List[str]:
    return sorted(
        {
            feature
            for feature in autoencoder._feature_keys_for(sample)
            if _stable_legal_ir_feature_group(feature)
        }
    )


def _stable_legal_ir_model_state(
    state: ModalAutoencoderTrainingState,
) -> Dict[str, Any]:
    """Build the source-free state payload used by the export fingerprint."""

    return {
        "architecture_version": MODAL_AUTOENCODER_ARCHITECTURE_VERSION,
        "features": _stable_legal_ir_learned_feature_rows(state),
        "legal_ir_view_logits": {
            str(view): round(float(weight), 12)
            for view, weight in sorted(state.legal_ir_view_logits.items())
            if math.isfinite(float(weight))
        },
        "schema_version": MODAL_AUTOENCODER_STATE_SCHEMA_VERSION,
    }


def export_stable_legal_ir_features(
    autoencoder: AdaptiveModalAutoencoder,
    samples: Iterable[LegalSample] = (),
    **kwargs: Any,
) -> Dict[str, Any]:
    """Public dictionary export for deterministic learned-guidance promotion."""

    return autoencoder.export_stable_legal_ir_features(samples, **kwargs).to_dict()


def export_stable_learned_ir_features(
    autoencoder: AdaptiveModalAutoencoder,
    samples: Iterable[LegalSample] = (),
    **kwargs: Any,
) -> Dict[str, Any]:
    """Compatibility alias for :func:`export_stable_legal_ir_features`."""

    return export_stable_legal_ir_features(autoencoder, samples, **kwargs)


def _json_round_floats(value: Any) -> Any:
    if isinstance(value, Mapping):
        return {
            str(key): _json_round_floats(item)
            for key, item in sorted(value.items(), key=lambda pair: str(pair[0]))
        }
    if isinstance(value, list):
        return [_json_round_floats(item) for item in value]
    if isinstance(value, tuple):
        return [_json_round_floats(item) for item in value]
    if isinstance(value, float):
        return round(value, 12) if math.isfinite(value) else 0.0
    return value


def frame_ranking_loss(sample: LegalSample) -> float:
    """Return zero when the selected frame is ranked first, otherwise rank penalty."""
    if not sample.frame_candidates or sample.selected_frame is None:
        return 1.0
    for index, candidate in enumerate(sample.frame_candidates):
        if candidate.get("frame_id") == sample.selected_frame:
            return float(index)
    return float(len(sample.frame_candidates))


def symbolic_validity_penalty(sample: LegalSample) -> float:
    """Return a simple penalty for samples without parseable modal formulas."""
    return 0.0 if sample.modal_ir.formulas else 1.0


def _check_same_length(left: Sequence[float], right: Sequence[float]) -> None:
    if len(left) != len(right):
        raise ValueError("Vectors must have the same length")


